-- Schema for Domain: reference | Business: Real Estate | Version: v1_ecm
-- Generated on: 2026-05-02 01:46:58

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `real_estate_ecm`.`reference` COMMENT 'Centralized repository for all enterprise reference and lookup data — property types, lease types, transaction types, geographic hierarchies, market segments, zoning codes, currency codes, unit-of-measure standards (PSF, SQF/SQM), industry classification codes, and business taxonomies. Provides controlled vocabularies and standardized code sets that ensure data consistency across all operational and analytical domains.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`property_type` (
    `property_type_id` BIGINT COMMENT 'Unique surrogate identifier for each node in the property classification taxonomy. Primary key. [REFERENCE_LOOKUP role — exempt from per-role minimums; _canonical_skip_reason: This is a controlled vocabulary / hierarchical code-list serving as the enterprise-wide property classification taxonomy, not a first-class operational entity with its own lifecycle.]',
    `building_class_id` BIGINT COMMENT 'Foreign key linking to reference.building_class. Business justification: Property types are associated with a default building class designation (e.g., trophy office properties are Class A, older industrial properties are Class C). Linking to the building_class registry no',
    `construction_type_id` BIGINT COMMENT 'Foreign key linking to reference.construction_type. Business justification: Property types are characterized by their primary construction method (e.g., multifamily residential typically uses wood frame or concrete, industrial uses steel frame). Linking to the construction_ty',
    `parent_property_type_id` BIGINT COMMENT 'Self-referencing foreign key to the parent node in the property classification hierarchy. NULL for Level 1 (asset class) root nodes. Enables traversal of the multi-level taxonomy (L1 asset class → L2 sub-category → L3 quality tier → L4 space use → L5 construction method → L6 amenity classification).',
    `space_use_type_id` BIGINT COMMENT 'Foreign key linking to reference.space_use_type. Business justification: Property types define the primary space use classification for the asset (e.g., office property type → office space use, retail property type → retail space use). Linking to the space_use_type registr',
    `amenity_classification` STRING COMMENT 'Level 6 amenity classification indicating whether amenities associated with this property type are provided at the building level (lobbies, fitness centers, conference rooms), unit level (in-unit washer/dryer, private terrace), or community level (shared outdoor spaces, pools, clubhouses). Used in property marketing, tenant scoring, and lease negotiation.. Valid values are `Building-Level|Unit-Level|Community|N/A`',
    `asset_class` STRING COMMENT 'Top-level (Level 1) asset class classification for this property type node. Denormalized from the root ancestor for fast filtering in analytics and reporting. Aligned with CoStar and NAIOP asset class definitions.. Valid values are `Commercial|Residential|Mixed-Use|Land|Special-Purpose`',
    `bim_applicable` BOOLEAN COMMENT 'Indicates whether BIM (Building Information Modeling) digital asset documentation is applicable and required for development and construction projects of this property type. True for complex commercial, mixed-use, and large-scale residential development types managed in Procore. Drives BIM data collection and document control workflows.',
    `cam_inclusion_rule` STRING COMMENT 'Standard CAM (Common Area Maintenance) expense inclusion rule applicable to this property type, defining which operating expenses are passed through to tenants. NNN (Triple Net) passes taxes, insurance, and maintenance; NN (Double Net) passes taxes and insurance; Full-Service Gross includes all expenses in base rent. Drives lease structuring defaults in Yardi Voyager and MRI Software. [ENUM-REF-CANDIDATE: Full-Service Gross|Modified Gross|NNN|NN|N|Absolute Net|N/A — 7 candidates stripped; promote to reference product]',
    `cap_rate_benchmark_pct` DECIMAL(18,2) COMMENT 'Market benchmark CAP Rate (Capitalization Rate) percentage for this property type, representing the expected ratio of Net Operating Income (NOI) to property value. Used as a default underwriting assumption in Argus Enterprise DCF (Discounted Cash Flow) models and investment advisory valuations. Expressed as a percentage (e.g., 5.50 = 5.50%).',
    `costar_property_type_code` STRING COMMENT 'CoStar Suites standardized property type code for this classification node. Enables direct mapping and data reconciliation between the enterprise taxonomy and CoStar market research data, comparable sales, and lease analytics. Critical for market benchmarking and CMA (Comparative Market Analysis) workflows.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this property type taxonomy node was first created in the enterprise reference data repository. Supports audit trail, data lineage, and SOX (Sarbanes-Oxley Act) compliance for reference data governance.',
    `effective_from` DATE COMMENT 'Date from which this property type classification node became effective and available for use in the enterprise taxonomy. Supports temporal validity tracking and ensures historical data integrity when taxonomy nodes are introduced or revised.',
    `effective_until` DATE COMMENT 'Date after which this property type classification node is no longer valid for new assignments. NULL indicates the node is currently active with no planned expiry. Supports taxonomy versioning and ensures deprecated nodes are not applied to new properties or leases after their retirement date.',
    `far_applicable` BOOLEAN COMMENT 'Indicates whether Floor Area Ratio (FAR) regulations are applicable to development projects of this property type. True for commercial and mixed-use development types subject to FAR zoning restrictions. Used in development feasibility analysis and Procore project planning.',
    `hierarchy_level` STRING COMMENT 'Integer indicating the depth of this node within the six-level property classification hierarchy. Level 1 = Asset Class (commercial, residential, mixed-use, land, special-purpose); Level 2 = Sub-Category (office, retail, industrial, hospitality, single-family, multifamily, condo); Level 3 = Quality Tier / Building Class (Class A/B/C, trophy, institutional-grade, luxury, affordable); Level 4 = Space Use Type (office, retail, restaurant, medical, fitness, storage, parking); Level 5 = Construction Method (wood frame, steel, concrete, masonry, modular); Level 6 = Amenity Classification (building-level, unit-level, community).',
    `hierarchy_path` STRING COMMENT 'Materialized full ancestry path from root to this node expressed as a delimited string (e.g., Commercial / Office / Class A / Office Space Use / Steel Frame / Building-Level Amenity). Enables efficient subtree queries and breadcrumb navigation in reporting tools without recursive CTE traversal.',
    `hoa_applicable` BOOLEAN COMMENT 'Indicates whether properties of this type are subject to HOA (Homeowners Association) governance, fees, and covenants. Applicable to condominium, single-family community, and certain mixed-use residential property types. Drives HOA fee tracking in property management and tenant disclosure requirements.',
    `ibc_fire_resistance_type` STRING COMMENT 'International Building Code (IBC) construction type classification indicating the fire resistance rating of the structural system. Types I and II are non-combustible; Types III, IV, and V include combustible elements. Drives insurance underwriting, OSHA compliance, and maintenance safety protocols. Aligned with IBC Chapter 6 construction type definitions. [ENUM-REF-CANDIDATE: Type I-A|Type I-B|Type II-A|Type II-B|Type III-A|Type III-B|Type IV|Type V-A|Type V-B|N/A — 10 candidates stripped; promote to reference product]',
    `is_cam_applicable` BOOLEAN COMMENT 'Indicates whether Common Area Maintenance (CAM) charges are applicable to leases for properties of this type. True for commercial property types (office, retail, industrial) where CAM reconciliation is standard. False for residential or gross lease property types where operating expenses are not passed through to tenants.',
    `is_commercial` BOOLEAN COMMENT 'Indicates whether this property type is classified as CRE (Commercial Real Estate) for regulatory, tax, and accounting purposes. Drives applicability of CMBS (Commercial Mortgage-Backed Securities) financing, DSCR (Debt Service Coverage Ratio) underwriting, and commercial lease accounting under FASB ASC 842.',
    `is_esg_relevant` BOOLEAN COMMENT 'Indicates whether ESG (Environmental, Social, and Governance) reporting metrics and sustainability certifications are applicable and tracked for properties of this type. True for property types subject to LEED, BREEAM, or ENERGY STAR certification programs. Drives ESG data collection requirements and SEC sustainability disclosure obligations for publicly traded REITs.',
    `is_gla_applicable` BOOLEAN COMMENT 'Indicates whether Gross Leasable Area (GLA) measurement methodology is applicable to properties of this type. True for retail and commercial property types where GLA is the standard measurement basis per BOMA and ICSC standards. False for property types measured by other methodologies (e.g., residential measured by GFA or NLA).',
    `is_investment_grade` BOOLEAN COMMENT 'Indicates whether properties of this type qualify as institutional investment-grade assets suitable for REIT (Real Estate Investment Trust) portfolios, pension fund investment, and institutional capital allocation. Drives portfolio screening in Argus Enterprise and investment advisory workflows. Typically True for Class A and Trophy commercial assets.',
    `is_leaf_node` BOOLEAN COMMENT 'Indicates whether this taxonomy node is a terminal leaf node (True) with no child nodes, or an intermediate branch node (False). Leaf nodes represent the most granular assignable property type classifications. Used to enforce that only leaf-level types are assigned to individual properties and leases.',
    `is_reit_eligible` BOOLEAN COMMENT 'Indicates whether properties of this type qualify as REIT-eligible assets under IRS REIT qualification rules (IRC Section 856). Drives asset classification in financial consolidation (SAP S/4HANA) and SEC regulatory reporting for publicly traded REITs. Distinct from investment_grade as it reflects specific tax and regulatory eligibility.',
    `is_residential` BOOLEAN COMMENT 'Indicates whether this property type is classified as residential for regulatory, tax, and accounting purposes. Drives applicability of HUD regulations, residential mortgage underwriting standards (PMI, ARM, FRM, DTI), and RMBS (Residential Mortgage-Backed Securities) eligibility. Distinct from asset_class for use in compliance filtering.',
    `leed_certification_applicable` BOOLEAN COMMENT 'Indicates whether LEED (Leadership in Energy and Environmental Design) certification is applicable and pursued for properties of this type. Drives green building data collection, energy benchmarking, and ESG reporting workflows. Relevant for institutional-grade commercial and multifamily property types.',
    `measurement_methodology` STRING COMMENT 'Standard area measurement methodology applicable to this property type. GLA (Gross Leasable Area) for retail; NLA (Net Leasable Area) for commercial office; GFA (Gross Floor Area) for development and planning; IPMS (International Property Measurement Standards) for cross-border portfolios. Drives how PSF (Per Square Foot) rent and valuation metrics are calculated.. Valid values are `GLA|NLA|GFA|IPMS|BOMA|N/A`',
    `naiop_type_code` STRING COMMENT 'NAIOP (National Association for Industrial and Office Properties) standardized property type code for commercial real estate classification. Used for industry benchmarking, market research alignment, and CRE (Commercial Real Estate) portfolio reporting.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `property_type_status` STRING COMMENT 'Current lifecycle status of this property type taxonomy node. active nodes are available for assignment to properties, leases, and valuations. deprecated nodes are retained for historical data integrity but no longer assignable. draft nodes are under review prior to enterprise publication.. Valid values are `active|inactive|deprecated|draft`',
    `reso_property_type_code` STRING COMMENT 'RESO (Real Estate Standards Organization) standardized property type code for MLS (Multiple Listing Service) data exchange and industry interoperability. Enables syndication of property listings via MLS platforms and ensures compliance with RESO Data Dictionary standards.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `sort_order` STRING COMMENT 'Integer defining the preferred display sequence of this property type node within its sibling group at the same hierarchy level. Used to control the ordering of property type options in dropdown menus, reports, and dashboards across Yardi Voyager, MRI Software, and Salesforce CRM integrations.',
    `sub_category` STRING COMMENT 'Level 2 sub-category classification denormalized from the taxonomy hierarchy for analytical convenience. Examples: Office, Retail, Industrial, Hospitality, Single-Family, Multifamily, Condo, Mixed-Use Retail/Office. [ENUM-REF-CANDIDATE: Office|Retail|Industrial|Hospitality|Single-Family|Multifamily|Condo|Mixed-Use|Self-Storage|Data Center|Life Science|Senior Housing — promote to reference product]',
    `ti_allowance_benchmark_psf` DECIMAL(18,2) COMMENT 'Market benchmark for Tenant Improvement (TI) allowance expressed in dollars Per Square Foot (PSF) for this property type. Used as a default starting point in lease negotiations and deal underwriting. Sourced from CoStar market data and internal brokerage transaction history. Supports deal pipeline analysis in Salesforce CRM.',
    `type_code` STRING COMMENT 'Standardized alphanumeric code uniquely identifying this property type node within the enterprise taxonomy. Used as the stable business key for cross-system integration with Yardi Voyager, MRI Software, CoStar, and Argus Enterprise. Examples: COMM_OFF_A, RES_MF_LUX, IND_WRHSE.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `type_description` STRING COMMENT 'Detailed narrative description of the property classification node, including defining characteristics, typical use cases, and distinguishing criteria from adjacent nodes. Supports business user understanding and onboarding.',
    `type_name` STRING COMMENT 'Human-readable display name for this property classification node as used in reports, dashboards, and user interfaces across all operational systems. Examples: Class A Office, Luxury Multifamily, Triple Net Retail.',
    `typical_lease_term_months` STRING COMMENT 'Market-standard typical lease term in months for this property type. Used as a default assumption in lease underwriting, WALT (Weighted Average Lease Term) calculations, and cash flow modeling in Argus Enterprise. Examples: 12 months for residential, 60-120 months for commercial office, 36-60 months for retail.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this property type taxonomy node was last modified in the enterprise reference data repository. Supports change tracking, data lineage, and reference data governance workflows.',
    `zoning_compatibility_codes` STRING COMMENT 'Pipe-delimited list of standard zoning designation codes compatible with this property type (e.g., C-1|C-2|M-1 for light commercial/industrial). Supports regulatory compliance checks, development feasibility analysis, and GIS (Geographic Information System) integration. Aligned with local municipal zoning ordinances and FAR (Floor Area Ratio) regulations.',
    CONSTRAINT pk_property_type PRIMARY KEY(`property_type_id`)
) COMMENT 'Enterprise-wide property classification taxonomy organized as a self-referencing multi-level hierarchy. Level 1: asset class (commercial, residential, mixed-use, land, special-purpose). Level 2: sub-category (office, retail, industrial, hospitality, single-family, multifamily, condo). Level 3: quality tier / building class (Class A/B/C, trophy, institutional-grade, luxury, affordable). Level 4: space use type (office, retail, restaurant, medical, fitness, storage, parking). Level 5: construction method (wood frame, steel, concrete, masonry, modular). Level 6: amenity classification (building-level, unit-level, community). Each node carries applicable attributes: GLA applicability flags, zoning compatibility codes, fire resistance ratings (IBC Type I–V), ESG/LEED relevance indicators, CAM inclusion rules, TI allowance benchmarks, and measurement methodology (GLA/NLA/GFA). Aligned with RESO, CoStar, BOMA, and NAIOP standards. Referenced by property, lease, valuation, brokerage, development, and maintenance domains as the single source of truth for all property classification.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`lease_type` (
    `lease_type_id` BIGINT COMMENT 'Primary key for lease_type',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to reference.market_segment. Business justification: Lease types are associated with specific market segments (e.g., NNN leases are typical in Core commercial segments, gross leases in Value-Add residential segments). Linking to the market_segment regis',
    `abbreviation` STRING COMMENT 'Industry-standard abbreviation for the lease type used in market communications, CoStar listings, and brokerage reports (e.g., NNN, MG, FS, PCT, GL). Aligns with CoStar Suite and MLS syndication field conventions.. Valid values are `^[A-Z0-9/&-]{1,10}$`',
    `area_measure_standard` STRING COMMENT 'Specifies the standard unit of area measurement used for rent calculation under this lease type: SQF (Square Feet), SQM (Square Meters), GLA (Gross Leasable Area), NLA (Net Leasable Area), or GFA (Gross Floor Area). Ensures consistency in PSF/SQM rent calculations across Yardi Voyager, MRI Software, and CoStar Suite.. Valid values are `SQF|SQM|GLA|NLA|GFA`',
    `argus_lease_type_code` STRING COMMENT 'The corresponding lease type identifier as used in Argus Enterprise cash flow and valuation models. Enables mapping between this reference record and Argus Enterprise lease structure assumptions for DCF modeling, CAP rate analysis, and portfolio reporting.. Valid values are `^[A-Za-z0-9_-]{1,30}$`',
    `asc842_lease_classification` STRING COMMENT 'Specifies the default lease classification under FASB ASC 842 for this lease type: operating (lessee recognizes right-of-use asset and operating lease liability), finance (lessee recognizes finance lease asset and liability with front-loaded expense), short_term_exemption (leases ≤12 months exempt from balance sheet recognition), or not_applicable (lessor-side or non-applicable structures). Drives accounting treatment in SAP S/4HANA and Yardi Voyager GL.. Valid values are `operating|finance|short_term_exemption|not_applicable`',
    `cam_reconciliation_required` BOOLEAN COMMENT 'Indicates whether annual CAM reconciliation is required for this lease type (True). CAM reconciliation compares estimated CAM charges billed to tenants against actual CAM expenses incurred. Required for NNN and modified gross leases; not applicable for full gross leases. Activates CAM reconciliation workflows in Yardi Voyager.',
    `cam_responsibility` STRING COMMENT 'Indicates which party bears responsibility for Common Area Maintenance (CAM) charges under this lease type. landlord means the landlord absorbs all CAM costs; tenant means the tenant pays CAM directly (as in NNN); shared means costs are pro-rated; not_applicable for lease types where CAM is not a relevant concept (e.g., ground lease). Governs CAM reconciliation workflows in Yardi Voyager.. Valid values are `landlord|tenant|shared|not_applicable`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this lease type reference record was first created in the enterprise data platform. Supports data lineage, audit trail requirements under SOX financial controls, and reference data governance.',
    `effective_date` DATE COMMENT 'The date from which this lease type classification became or becomes effective for use in new lease agreements. Supports temporal validity tracking for reference data governance and ensures that historical lease records retain the correct classification at the time of execution.',
    `escalation_method` STRING COMMENT 'Indicates the standard rent escalation methodology associated with this lease type: fixed_step (predetermined dollar or percentage increases), cpi_indexed (Consumer Price Index-linked adjustments), market_reset (rent reset to prevailing market rate at intervals), none (flat rent for term), or hybrid (combination of methods). Governs rent schedule escalation logic in Yardi Voyager and Argus Enterprise DCF models.. Valid values are `fixed_step|cpi_indexed|market_reset|none|hybrid`',
    `esg_reporting_applicable` BOOLEAN COMMENT 'Indicates whether ESG (Environmental, Social, and Governance) reporting obligations — such as green lease clauses, LEED/BREEAM compliance requirements, or energy consumption data sharing — are applicable to this lease type (True). Relevant for institutional and REIT portfolios subject to SEC ESG disclosure requirements and USGBC LEED certification programs.',
    `expiry_date` DATE COMMENT 'The date on which this lease type classification ceases to be valid for use in new lease agreements (nullable for open-ended classifications). Supports reference data lifecycle management and ensures deprecated lease types are not applied to new leases after their retirement date.',
    `external_reference_code` STRING COMMENT 'Industry-standard or regulatory body reference code for this lease type, such as RESO standard codes, NCREIF property type codes, or CoStar lease type identifiers. Enables cross-system interoperability and alignment with industry data exchange standards.. Valid values are `^[A-Za-z0-9_.-]{1,50}$`',
    `ifrs16_lease_classification` STRING COMMENT 'Specifies the default lease classification under IASB IFRS 16 for this lease type: single_model (all leases recognized on balance sheet as right-of-use asset and lease liability), short_term_exemption (leases ≤12 months), low_value_exemption (underlying asset of low value), or not_applicable. Supports international financial reporting in SAP S/4HANA for entities reporting under IFRS.. Valid values are `single_model|short_term_exemption|low_value_exemption|not_applicable`',
    `insurance_responsibility` STRING COMMENT 'Defines which party is responsible for property insurance premiums under this lease type. Relevant for NNN and modified gross lease structures where insurance cost allocation varies. Used in lease administration billing and CAM reconciliation processes.. Valid values are `landlord|tenant|shared|not_applicable`',
    `is_ground_lease` BOOLEAN COMMENT 'Indicates whether this lease type is a ground lease (True), where the tenant leases land only and typically constructs improvements. Ground leases have distinct legal, accounting, and investment characteristics including long terms (50–99 years), land-only rent, and reversion of improvements to the landlord. Relevant for REIT portfolio classification and Argus Enterprise valuation modeling.',
    `is_short_term` BOOLEAN COMMENT 'Indicates whether this lease type is classified as short-term (True), typically defined as a lease term of 12 months or less at commencement. Short-term leases qualify for the practical expedient exemption from balance sheet recognition under both FASB ASC 842 and IASB IFRS 16. Drives accounting treatment selection in SAP S/4HANA and Yardi Voyager.',
    `is_sublease` BOOLEAN COMMENT 'Indicates whether this lease type represents a sublease arrangement (True), where the original lessee (sublandlord) leases all or part of the demised space to a subtenant. Subleases require distinct accounting treatment under FASB ASC 842 (intermediate lessor classification) and separate tracking in Yardi Voyager and MRI Software.',
    `lease_category` STRING COMMENT 'Broad property-use category to which this lease type applies — commercial, residential, industrial, mixed_use, or land. Determines which operational workflows in Yardi Voyager and MRI Software are applicable and which regulatory frameworks (ASC 842, IFRS 16) govern accounting treatment.. Valid values are `commercial|residential|industrial|mixed_use|land`',
    `lease_type_code` STRING COMMENT 'Short, system-facing alphanumeric code uniquely identifying the lease type (e.g., NNN, GROSS, MOD_GROSS, PCT, GROUND, SUBLEASE, MTM). Used as the canonical lookup key in Yardi Voyager, MRI Software, and downstream analytical systems to join lease records to their classification.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `lease_type_description` STRING COMMENT 'Detailed narrative description of the lease type, including its defining characteristics, typical use cases, cost responsibility allocation, and distinguishing features from similar lease structures. Used in training materials, lease administration documentation, and business glossary entries.',
    `lease_type_name` STRING COMMENT 'Full human-readable name of the lease structure classification (e.g., Triple Net Lease, Gross Lease, Modified Gross Lease, Percentage Lease, Ground Lease, Sublease, Month-to-Month). Displayed in reporting, lease administration screens, and tenant-facing documents.',
    `lease_type_status` STRING COMMENT 'Current lifecycle status of this lease type reference record: active (available for use in new lease agreements), inactive (temporarily disabled but retained for historical reference), or deprecated (superseded by a newer classification; retained for legacy lease records only). Controls availability in Yardi Voyager and MRI Software lease type selection lists.. Valid values are `active|inactive|deprecated`',
    `loi_required` BOOLEAN COMMENT 'Indicates whether a Letter of Intent (LOI) is a standard prerequisite in the deal process for this lease type (True). LOIs are standard for commercial leases but typically not required for residential or month-to-month arrangements. Governs deal pipeline workflow in Salesforce CRM and DocuSign CLM.',
    `mri_lease_type_code` STRING COMMENT 'The corresponding lease type code as configured in MRI Software Lease Management module. Enables direct mapping between this enterprise reference record and the MRI source system code for data integration and reconciliation, particularly for residential and investment management portfolios.. Valid values are `^[A-Za-z0-9_-]{1,30}$`',
    `noi_impact_classification` STRING COMMENT 'Classifies how this lease type impacts Net Operating Income (NOI) calculation: gross_revenue (all income flows through gross revenue line before expense deductions), net_revenue (tenant pays expenses directly, reducing gross revenue line), or not_applicable. Used in Argus Enterprise NOI modeling and MRI Software investment reporting.. Valid values are `gross_revenue|net_revenue|not_applicable`',
    `opex_responsibility` STRING COMMENT 'Defines which party is responsible for property operating expenditures (OpEx) beyond CAM — including insurance, management fees, and administrative costs — under this lease type. Critical for NOI calculation accuracy in Argus Enterprise and financial reporting under FASB ASC 842.. Valid values are `landlord|tenant|shared|not_applicable`',
    `percentage_rent_applicable` BOOLEAN COMMENT 'Indicates whether percentage rent (a portion of tenant gross sales revenue above a breakpoint) is a feature of this lease type (True). Applicable primarily to retail percentage leases. Activates percentage rent calculation and reporting workflows in Yardi Voyager and MRI Software.',
    `renewal_option_applicable` BOOLEAN COMMENT 'Indicates whether renewal options are a standard feature of this lease type (True) or not applicable (False). For example, ground leases and long-term commercial leases typically include renewal options, while month-to-month leases do not. Informs lease renewal option tracking in Yardi Voyager and WALT/WALE calculations in Argus Enterprise.',
    `rent_basis` STRING COMMENT 'Defines the standard unit of measure for rent quotation under this lease type: PSF (Per Square Foot) annual, PSF monthly, flat monthly amount, flat annual amount, or percentage of sales. Aligns with industry PSF/SQF conventions and drives rent schedule generation in Yardi Voyager and Argus Enterprise underwriting models.. Valid values are `psf_annual|psf_monthly|flat_monthly|flat_annual|percentage_sales`',
    `rent_structure` STRING COMMENT 'Defines the fundamental rent calculation methodology for this lease type: fixed (flat base rent), variable (indexed or market-reset), percentage (percentage of tenant sales revenue), hybrid (base + percentage), or ground_rent (land-only lease payment). Drives rent schedule generation logic in Yardi Voyager and Argus Enterprise cash flow models.. Valid values are `fixed|variable|percentage|hybrid|ground_rent`',
    `security_deposit_required` BOOLEAN COMMENT 'Indicates whether a security deposit is a standard requirement for this lease type (True). Security deposits are common in residential and commercial leases but may not apply to ground leases or certain institutional arrangements. Drives security deposit tracking and accounting in Yardi Voyager AR and MRI Software.',
    `snda_required` BOOLEAN COMMENT 'Indicates whether a Subordination Non-Disturbance and Attornment (SNDA) agreement is a standard requirement for this lease type (True). SNDAs are typically required for commercial leases where the property is encumbered by a mortgage. Tracked in DocuSign CLM and Yardi Voyager lease document management.',
    `sort_order` STRING COMMENT 'Numeric value controlling the display sequence of lease type options in user interface dropdowns, reports, and lease administration screens. Lower values appear first. Enables business-defined ordering independent of alphabetical or ID-based sorting.',
    `sublease_permitted` BOOLEAN COMMENT 'Indicates whether subleasing is a standard permitted feature under this lease type (True). Relevant for distinguishing primary lease structures from sublease structures and for compliance with FASB ASC 842 sublease accounting requirements.',
    `tax_responsibility` STRING COMMENT 'Specifies which party is responsible for real estate property taxes under this lease type. In a Triple Net (NNN) lease, the tenant bears tax responsibility; in a gross lease, the landlord absorbs taxes. Drives tax pass-through billing logic in Yardi Voyager and MRI Software.. Valid values are `landlord|tenant|shared|not_applicable`',
    `ti_allowance_applicable` BOOLEAN COMMENT 'Indicates whether Tenant Improvement (TI) allowances are a standard feature of this lease type (True). TI allowances are common in commercial gross and modified gross leases but less common in NNN or ground leases. Drives TI allowance tracking and amortization in Yardi Voyager Fixed Assets and FASB ASC 842 right-of-use asset calculations.',
    `typical_term_max_months` STRING COMMENT 'The typical maximum lease duration in months associated with this lease type (e.g., 12 months for short-term, 120 months for standard commercial, 1200 months for ground leases). Used in Argus Enterprise for WALT/WALE modeling, portfolio duration analytics, and investment underwriting.',
    `typical_term_min_months` STRING COMMENT 'The typical minimum lease duration in months associated with this lease type (e.g., 1 month for month-to-month, 12 months for short-term, 60 months for standard commercial NNN). Used in Argus Enterprise for WALT/WALE modeling and portfolio duration analytics.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this lease type reference record was most recently modified. Supports change tracking, data lineage, and audit trail requirements under SOX financial controls for reference data governance.',
    `utility_responsibility` STRING COMMENT 'Specifies which party is responsible for utility costs (electricity, water, gas, HVAC) under this lease type. Gross leases typically assign utilities to the landlord; NNN leases assign them to the tenant. Drives utility billing configuration in Building Engines and Yardi Voyager.. Valid values are `landlord|tenant|shared|not_applicable`',
    `yardi_lease_type_code` STRING COMMENT 'The corresponding lease type code as configured in Yardi Voyager Lease Administration module. Enables direct mapping between this enterprise reference record and the source system code for data integration, reconciliation, and ETL processes from Yardi Voyager.. Valid values are `^[A-Za-z0-9_-]{1,30}$`',
    CONSTRAINT pk_lease_type PRIMARY KEY(`lease_type_id`)
) COMMENT 'Standardized classification of lease structures used across commercial and residential leasing — NNN (Triple Net), gross lease, modified gross, percentage lease, ground lease, sublease, and short-term/month-to-month. Defines rent calculation methodology, CAM/OpEx responsibility allocation, and applicable accounting treatment under ASC 842 / IFRS 16. Includes escalation method indicators (CPI, fixed-step, market reset) and renewal option classification. Serves as the authoritative lookup for lease administration across Yardi Voyager, MRI Software, and all operational domains requiring lease structure classification.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`transaction_type` (
    `transaction_type_id` BIGINT COMMENT 'Unique surrogate identifier for each transaction type record in the controlled vocabulary. Primary key for the transaction_type reference product. [Role: REFERENCE_LOOKUP — _canonical_skip_reason: This is a controlled vocabulary / code-list entity; per-role minimum categories do not apply.]',
    `regulatory_framework_id` BIGINT COMMENT 'Foreign key linking to reference.regulatory_framework. Business justification: Transaction types are subject to specific primary regulatory frameworks (e.g., 1031 exchanges governed by IRS Section 1031, REIT transactions governed by SEC regulations, lease transactions governed b',
    `appraisal_required` BOOLEAN COMMENT 'Indicates whether a formal property appraisal or valuation is required for transactions of this type. Triggers valuation workflow initiation in Argus Enterprise and appraisal order management processes.',
    `asset_class_applicability` STRING COMMENT 'Comma-delimited list of real estate asset classes to which this transaction type applies (e.g., office,retail,industrial,multifamily,land,hotel,mixed-use). Governs which asset classes can be tagged with this transaction type in Yardi Voyager and MRI Software.',
    `broker_commission_applicable` BOOLEAN COMMENT 'Indicates whether brokerage commissions are applicable to transactions of this type. Drives commission calculation and split workflows in Salesforce CRM and the brokerage domain commission products.',
    `capex_or_opex` STRING COMMENT 'Indicates whether transactions of this type are classified as Capital Expenditure (CAPEX), Operating Expenditure (OPEX), both, or neither for financial reporting and budgeting purposes. Drives budget line categorization in Yardi Voyager and SAP S/4HANA.. Valid values are `capex|opex|both|not_applicable`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this transaction type record was first created in the enterprise data lakehouse Silver layer. Supports data lineage, audit trail, and compliance reporting requirements under SOX.',
    `due_diligence_period_days` STRING COMMENT 'Standard number of calendar days allocated for due diligence for transactions of this type, as defined by industry convention or internal policy. Used as a default in deal timeline planning within Salesforce CRM and Argus Enterprise.',
    `effective_date` DATE COMMENT 'Date from which this transaction type record becomes active and available for use across all operational and analytical systems. Supports temporal validity management of the controlled vocabulary.',
    `environmental_review_required` BOOLEAN COMMENT 'Flags whether an environmental site assessment (Phase I/II ESA) is required for transactions of this type. Drives due diligence checklist items in Procore and compliance tracking in SAP S/4HANA.',
    `esg_disclosure_required` BOOLEAN COMMENT 'Indicates whether transactions of this type require ESG-related disclosures (e.g., energy performance, LEED/BREEAM certification status, carbon footprint). Supports ESG reporting obligations for publicly traded REITs and institutional investors.',
    `expiry_date` DATE COMMENT 'Date on which this transaction type record is retired and no longer available for selection in new transactions. Null indicates no planned expiry. Supports controlled vocabulary lifecycle management.',
    `external_reference_code` STRING COMMENT 'Corresponding transaction type code used in external systems or industry standards (e.g., RESO transaction type codes, CoStar transaction type identifiers, MLS transaction type codes). Enables cross-system data reconciliation and integration mapping.',
    `gl_transaction_class` STRING COMMENT 'General Ledger (GL) transaction class code used to map this transaction type to the appropriate accounting treatment in Yardi Voyager and SAP S/4HANA (e.g., capital event, operating event, financing event). Ensures consistent financial statement classification.',
    `is_1031_eligible` BOOLEAN COMMENT 'Flags whether this transaction type is eligible for a like-kind exchange under IRS Section 1031, allowing deferral of capital gains taxes. Critical for investment advisory and portfolio management workflows in Argus Enterprise and MRI Software.',
    `is_distressed_asset` BOOLEAN COMMENT 'Indicates whether this transaction type involves a distressed asset scenario (e.g., foreclosure, REO sale, short sale, deed-in-lieu). Drives specialized due diligence checklists and risk flags in Salesforce CRM and Argus Enterprise.',
    `is_fasb_asc842_applicable` BOOLEAN COMMENT 'Flags whether this transaction type triggers lease accounting recognition requirements under FASB ASC 842 (e.g., ground lease assignments, sale-leaseback transactions). Used by the finance domain for lease liability and right-of-use asset recognition in Yardi Voyager and SAP S/4HANA.',
    `is_hud_reportable` BOOLEAN COMMENT 'Indicates whether transactions of this type require reporting to HUD (e.g., residential foreclosures, REO sales, FHA-related transactions). Drives compliance workflow routing in DocuSign CLM and SAP S/4HANA.',
    `is_ifrs16_applicable` BOOLEAN COMMENT 'Flags whether this transaction type triggers lease accounting recognition requirements under IFRS 16 for entities reporting under international accounting standards. Supports multi-standard financial reporting in SAP S/4HANA.',
    `is_joint_venture` BOOLEAN COMMENT 'Indicates whether this transaction type involves the formation or dissolution of a joint venture (JV) entity. Triggers JV-specific legal entity setup workflows in SAP S/4HANA and investment structuring processes in MRI Software.',
    `is_portfolio_trade` BOOLEAN COMMENT 'Flags whether this transaction type represents a bulk portfolio trade involving multiple properties transacted as a single deal. Enables portfolio-level aggregation and reporting in Argus Enterprise and MRI Software investment management modules.',
    `is_sec_reportable` BOOLEAN COMMENT 'Indicates whether transactions of this type must be reported to the SEC under applicable regulations (e.g., material acquisitions or dispositions by publicly traded REITs under Form 8-K or 10-K). Drives automated regulatory reporting flags in SAP S/4HANA.',
    `is_taxable_event` BOOLEAN COMMENT 'Indicates whether this transaction type constitutes a taxable event under applicable U.S. federal tax law (e.g., a standard acquisition/disposition is taxable; a 1031 exchange defers capital gains tax). Used by the finance domain for tax provision calculations in SAP S/4HANA.',
    `loi_required` BOOLEAN COMMENT 'Flags whether a Letter of Intent (LOI) is a required precursor document for transactions of this type before proceeding to a purchase and sale agreement. Drives deal pipeline stage gating in Salesforce CRM.',
    `mls_reportable` BOOLEAN COMMENT 'Flags whether transactions of this type are required or eligible to be reported to the Multiple Listing Service (MLS) and syndicated via CoStar Suite. Drives MLS syndication workflow in the brokerage domain.',
    `mri_transaction_code` STRING COMMENT 'Corresponding transaction type code as defined in MRI Software, used for system integration and data lineage tracing between the enterprise data lakehouse and the MRI source system.',
    `property_sector` STRING COMMENT 'Indicates whether this transaction type applies to Commercial Real Estate (CRE), residential properties, both sectors, or is sector-agnostic. Drives sector-specific workflow routing in Salesforce CRM and Yardi Voyager.. Valid values are `commercial|residential|both|not_applicable`',
    `reit_qualifying_income` BOOLEAN COMMENT 'Flags whether income or proceeds from transactions of this type qualify as REIT qualifying income under IRS Section 856. Critical for REIT compliance monitoring and FFO/AFFO calculations in MRI Software and Argus Enterprise.',
    `required_doc_checklist` STRING COMMENT 'Structured list or reference identifier for the documentation checklist required for transactions of this type (e.g., purchase agreement, title commitment, survey, environmental report, estoppel certificates, SNDA, LOI). Drives document management workflows in DocuSign CLM.',
    `snda_required` BOOLEAN COMMENT 'Indicates whether a Subordination, Non-Disturbance and Attornment (SNDA) agreement is required for transactions of this type (e.g., acquisitions of leased properties). Drives document checklist generation in DocuSign CLM.',
    `sort_order` STRING COMMENT 'Numeric value controlling the display sequence of transaction types in dropdown lists, reports, and user interfaces across Salesforce CRM, Yardi Voyager, and MRI Software. Lower values appear first.',
    `sub_category` STRING COMMENT 'Secondary classification within the parent category providing finer-grained segmentation (e.g., within disposition: voluntary sale, forced sale, REO, short sale; within exchange: 1031 like-kind, 721 UPREIT). Supports detailed analytics in Argus Enterprise and CoStar Suite.',
    `title_insurance_required` BOOLEAN COMMENT 'Flags whether title insurance (ALTA policy) is required for transactions of this type. Drives documentation checklist requirements in DocuSign CLM and closing process workflows.',
    `transaction_type_category` STRING COMMENT 'High-level grouping of the transaction type into a major business category. Supports portfolio-level reporting and analytics segmentation across the transaction and brokerage domains. [ENUM-REF-CANDIDATE: acquisition|disposition|financing|leasing|development|investment|distressed|exchange — promote to reference product]',
    `transaction_type_status` STRING COMMENT 'Lifecycle status of the transaction type record within the controlled vocabulary. active records are available for use across all domains; deprecated records are retained for historical data integrity but no longer selectable for new transactions.. Valid values are `active|inactive|deprecated|draft`',
    `transfer_tax_applicable` BOOLEAN COMMENT 'Indicates whether real estate transfer taxes (deed taxes, documentary stamp taxes) are applicable to transactions of this type. Used by the finance domain to trigger transfer tax calculations and GL entries in Yardi Voyager and SAP S/4HANA.',
    `type_code` STRING COMMENT 'Short, system-facing alphanumeric code uniquely identifying the transaction type (e.g., ACQ, DISP, 1031_EXCH, REO_SALE, FORECLOSURE, SHORT_SALE, GND_LSE_ASSIGN, JV_FORM, PORT_TRADE). Used as the stable business key across all operational systems including Yardi Voyager, MRI Software, and Argus Enterprise.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `type_description` STRING COMMENT 'Full narrative description of the transaction type, including its business purpose, typical use cases, and distinguishing characteristics. Used for business glossary documentation, onboarding materials, and data catalog entries.',
    `type_name` STRING COMMENT 'Human-readable, business-facing name of the transaction type (e.g., Acquisition, Disposition, 1031 Exchange, REO Sale, Foreclosure Sale, Short Sale, Ground Lease Assignment, Joint Venture Formation, Portfolio Trade). Displayed in Salesforce CRM deal pipelines, Argus Enterprise reports, and brokerage dashboards.',
    `typical_closing_days` STRING COMMENT 'Standard number of calendar days from executed purchase and sale agreement to closing for transactions of this type. Used for deal timeline forecasting and pipeline velocity reporting in Salesforce CRM and Argus Enterprise.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this transaction type record was most recently modified in the enterprise data lakehouse Silver layer. Supports change data capture, audit trail, and controlled vocabulary governance.',
    `version_number` STRING COMMENT 'Monotonically increasing version counter for this transaction type record, incremented each time the record is updated. Supports audit trail and change management for the controlled vocabulary.',
    `yardi_transaction_code` STRING COMMENT 'Corresponding transaction type code as defined in Yardi Voyager, used for system integration and data lineage tracing between the enterprise data lakehouse and the Yardi source system.',
    CONSTRAINT pk_transaction_type PRIMARY KEY(`transaction_type_id`)
) COMMENT 'Controlled vocabulary for all real estate transaction categories — acquisition, disposition, 1031 exchange, REO sale, foreclosure, short sale, ground lease assignment, joint venture formation, and portfolio trade. Includes transaction sub-types, applicable regulatory reporting flags (SEC, HUD), and required documentation checklists per transaction category. Used by the transaction domain and brokerage domain as the authoritative classification source.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`geographic_hierarchy` (
    `geographic_hierarchy_id` BIGINT COMMENT 'Unique surrogate identifier for each node in the enterprise geographic hierarchy. Serves as the primary key for all geographic reference lookups across the real estate portfolio. [_canonical_skip_reason: REFERENCE_LOOKUP/MASTER_RESOURCE — this is a controlled vocabulary / spatial reference node; per-role minimums for REFERENCE_LOOKUP are exempt, but MASTER_RESOURCE minimums are applied given the node carries rich business metadata.]',
    `country_id` BIGINT COMMENT 'Foreign key linking to reference.country. Business justification: Every geographic hierarchy node belongs to a country. Linking to the ISO 3166-1 country registry normalizes the country reference and enables joining to country-level attributes (sovereignty type, pro',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: Geographic hierarchy nodes (countries, regions, markets) operate in a primary currency used for financial reporting and benchmarking within that geography. Linking to the ISO 4217 currency registry en',
    `parent_node_geographic_hierarchy_id` BIGINT COMMENT 'Self-referencing identifier pointing to the immediate parent node in the geographic hierarchy (e.g., a submarket nodes parent is its MSA node). Enables recursive hierarchy traversal for portfolio roll-up and drill-down analytics.',
    `area_sqm` DECIMAL(18,2) COMMENT 'Total land area of this geographic node measured in square meters (SQM). Used for density analysis, FAR calculations, and market size benchmarking in portfolio analytics.',
    `city_name` STRING COMMENT 'Name of the city or municipality for this geographic node. Used in property address standardization, lease administration in Yardi Voyager, and MLS syndication via Salesforce CRM.',
    `costar_submarket_code` STRING COMMENT 'CoStar-assigned submarket identifier code used for market research, comparable lease and sales data alignment, and submarket-level vacancy and absorption analytics. Primary integration key with CoStar Suite.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `costar_submarket_name` STRING COMMENT 'CoStar-defined submarket name (e.g., Midtown Manhattan, Beverly Hills/West Hollywood). Used for market benchmarking, CMA preparation, and BPO analysis aligned with CoStar Suite data.',
    `effective_date` DATE COMMENT 'Date from which this geographic node definition became effective and valid for use in portfolio assignments, lease administration, and regulatory reporting. Supports temporal validity tracking for boundary changes (e.g., MSA redefinitions by OMB).',
    `enterprise_zone_flag` BOOLEAN COMMENT 'Indicates whether this geographic node is designated as a state or local enterprise zone, qualifying properties for tax incentives, development grants, or expedited permitting. Used in development feasibility analysis and CAPEX planning.',
    `esg_climate_risk_zone` STRING COMMENT 'ESG climate risk classification for this geographic node based on exposure to physical climate risks (flood, wildfire, hurricane, sea-level rise). Used for ESG portfolio reporting, LEED/BREEAM site selection, and insurance underwriting support.. Valid values are `low|moderate|high|very_high`',
    `expiry_date` DATE COMMENT 'Date on which this geographic node definition expires or is superseded (nullable for open-ended nodes). Used to manage OMB MSA boundary revisions, CoStar submarket redefinitions, and historical portfolio reporting continuity.',
    `external_reference_code` STRING COMMENT 'The identifier used for this geographic node in the primary source system (e.g., CoStar market ID, Yardi region code, MRI geographic code). Enables bi-directional reconciliation between the enterprise data lakehouse and operational systems.',
    `fips_code` STRING COMMENT 'FIPS geographic code assigned by the U.S. Census Bureau for this node (state, county, or place level). Used for regulatory reporting, HUD compliance, and integration with government datasets.. Valid values are `^[0-9]{2,10}$`',
    `flood_zone_designation` STRING COMMENT 'FEMA National Flood Insurance Program (NFIP) flood zone designation for this geographic node (e.g., AE, X, VE). Required for property insurance compliance, lender due diligence, and LTV risk assessment.. Valid values are `^[A-Z0-9]{1,5}$`',
    `hierarchy_depth` STRING COMMENT 'Integer depth level of this node within the hierarchy tree, where 1 = country (root). Used to optimize hierarchy traversal queries and enforce level-specific business rules in portfolio analytics.',
    `hierarchy_level` STRING COMMENT 'The level of this node within the enterprise geographic hierarchy. Defines the spatial granularity: country → region → state/province → Metropolitan Statistical Area (MSA) → submarket → city → zip/postal code → micro-location. Drives portfolio roll-up logic and GIS-based analysis. [ENUM-REF-CANDIDATE: country|region|state_province|msa|submarket|city|zip_postal_code|micro_location — 8 candidates stripped; promote to reference product]',
    `hierarchy_path` STRING COMMENT 'Full materialized path string representing the nodes ancestry from root to current node (e.g., USA/Northeast/New York/NYC-MSA/Manhattan/Midtown). Enables efficient hierarchy traversal and subtree queries without recursive joins.',
    `hud_area_code` STRING COMMENT 'U.S. Department of Housing and Urban Development (HUD) area code designating this geographic node for federal housing program eligibility, fair market rent (FMR) determination, and affordable housing compliance reporting.. Valid values are `^[A-Z0-9]{2,15}$`',
    `latitude` DECIMAL(18,2) COMMENT 'WGS 84 decimal-degree latitude coordinate of the geographic nodes centroid. Enables GIS-based portfolio mapping, spatial proximity analysis, and integration with GIS platforms for market visualization.',
    `longitude` DECIMAL(18,2) COMMENT 'WGS 84 decimal-degree longitude coordinate of the geographic nodes centroid. Enables GIS-based portfolio mapping, drive-time analysis, and spatial clustering for investment advisory services.',
    `market_tier` STRING COMMENT 'Classification of the markets investment grade and liquidity profile: primary (top-tier gateway markets, e.g., NYC, LA, Chicago), secondary (mid-size markets with strong fundamentals), or tertiary (smaller markets with higher risk/return profiles). Drives investment strategy, CAP rate benchmarking, and portfolio allocation decisions in Argus Enterprise.. Valid values are `primary|secondary|tertiary`',
    `median_household_income` DECIMAL(18,2) COMMENT 'Median annual household income for this geographic node in the nodes applicable currency. Used for residential affordability analysis, HUD area median income (AMI) benchmarking, and tenant demand modeling.',
    `msa_code` STRING COMMENT 'U.S. Office of Management and Budget (OMB) five-digit FIPS code identifying the Metropolitan Statistical Area (MSA). Critical for market segmentation, CoStar submarket alignment, HUD program eligibility, and CRE investment analysis.. Valid values are `^[0-9]{5}$`',
    `msa_name` STRING COMMENT 'Official OMB name of the Metropolitan Statistical Area (e.g., New York-Newark-Jersey City, NY-NJ-PA MSA). Used in Argus Enterprise cash flow models, investment advisory reports, and portfolio benchmarking.',
    `node_code` STRING COMMENT 'Externally-known, human-readable unique code identifying this geographic node (e.g., MSA-NYC, STATE-CA, ZIP-90210, SUBMARKET-MIDTOWN). Used as the business key for cross-system integration with CoStar, Yardi, and MRI. Aligns with CoStar submarket codes and HUD geographic designations.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `node_name` STRING COMMENT 'Full human-readable name of the geographic node (e.g., New York-Newark-Jersey City MSA, California, Midtown Manhattan Submarket). Used in portfolio reports, dashboards, and regulatory filings.',
    `node_short_name` STRING COMMENT 'Abbreviated or commonly used short name for the geographic node (e.g., NYC MSA, CA, Midtown). Used in space-constrained UI labels, map overlays, and condensed reporting.',
    `node_status` STRING COMMENT 'Current lifecycle status of this geographic hierarchy node. Active nodes are used in portfolio assignments and reporting. Deprecated nodes are retained for historical data integrity. Pending review nodes are under validation before activation.. Valid values are `active|inactive|deprecated|pending_review`',
    `notes` STRING COMMENT 'Free-text field for data stewards to record boundary change history, OMB reclassification notes, CoStar submarket split/merge events, or other contextual information relevant to this geographic nodes definition and usage.',
    `opportunity_zone_flag` BOOLEAN COMMENT 'Indicates whether this geographic node falls within a federally designated Opportunity Zone under the Tax Cuts and Jobs Act of 2017. Drives tax-advantaged investment structuring, REIT portfolio strategy, and investor reporting.',
    `population` BIGINT COMMENT 'Most recent census or estimated population count for this geographic node. Used as a demand driver in residential market analysis, HUD program sizing, and investment advisory demographic modeling.',
    `population_year` STRING COMMENT 'The reference year for the population count recorded in this node (e.g., 2020 for the decennial census). Ensures temporal accuracy in demographic-driven investment analysis.',
    `regulatory_jurisdiction_code` STRING COMMENT 'Code identifying the primary regulatory jurisdiction governing real estate activities in this geographic node (e.g., state real estate commission code, municipal zoning authority code). Used for license compliance tracking, NAR/state board reporting, and OSHA/EPA regulatory mapping.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this geographic node was sourced or last updated (e.g., costar for CoStar Suite, hud for HUD geographic designations, census for U.S. Census Bureau). Supports data lineage and master data governance. [ENUM-REF-CANDIDATE: costar|yardi|mri|hud|census|manual|argus — 7 candidates stripped; promote to reference product]',
    `state_province_code` STRING COMMENT 'ISO 3166-2 subdivision code for the state or province (e.g., CA, NY, TX). Used for state-level regulatory compliance, tax jurisdiction mapping, and HUD reporting.. Valid values are `^[A-Z]{2,3}$`',
    `state_province_name` STRING COMMENT 'Full name of the state or province (e.g., California, New York). Used in lease administration, regulatory filings, and portfolio reporting within Yardi Voyager and MRI Software.',
    `tax_jurisdiction_code` STRING COMMENT 'Code identifying the tax jurisdiction applicable to properties in this geographic node. Used for property tax assessment, transfer tax calculation, and SAP S/4HANA tax configuration for financial consolidation.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `time_zone` STRING COMMENT 'IANA time zone identifier for this geographic node (e.g., America/New_York, America/Los_Angeles). Used for scheduling property inspections, lease event notifications, and coordinating maintenance work orders across multi-market portfolios.',
    `unemployment_rate` DECIMAL(18,2) COMMENT 'Most recent unemployment rate (as a percentage) for this geographic node. Used as a macroeconomic indicator in CRE investment analysis, NOI forecasting, and portfolio risk assessment in Argus Enterprise.',
    `zip_postal_code` STRING COMMENT 'ZIP code (USA) or postal code (international) for this geographic node. Used for property address validation, HUD program area mapping, tax jurisdiction assignment, and GIS-based portfolio analysis.. Valid values are `^[A-Z0-9 -]{3,10}$`',
    CONSTRAINT pk_geographic_hierarchy PRIMARY KEY(`geographic_hierarchy_id`)
) COMMENT 'Enterprise geographic hierarchy defining the spatial organization of the real estate portfolio — country, region, state/province, metropolitan statistical area (MSA), submarket, city, zip/postal code, and micro-location. Supports GIS-based portfolio analysis, market segmentation, and regulatory jurisdiction mapping. Aligns with CoStar submarket definitions and HUD geographic designations. Each node carries market tier classification (primary, secondary, tertiary) and applicable regulatory jurisdiction codes.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`market_segment` (
    `market_segment_id` BIGINT COMMENT 'Unique surrogate identifier for the market segment record. Primary key for the market_segment reference product. Role: REFERENCE_LOOKUP — exempt from per-role minimums; this entity is a controlled vocabulary / code-set table providing standardized investment strategy and market segment classifications across the enterprise. _canonical_skip_reason: REFERENCE_LOOKUP — small enumeration of standardized market segment codes; no per-role minimum categories apply.',
    `data_steward` STRING COMMENT 'Name or identifier of the business data steward responsible for maintaining the accuracy and completeness of this market segment record. Supports data governance accountability and reference data change management processes.',
    `development_allowed` BOOLEAN COMMENT 'Indicates whether ground-up development or major redevelopment projects are permitted within this market segments investment mandate (True = allowed, False = not allowed). Opportunistic segments typically allow development; core segments do not.',
    `distressed_asset_eligible` BOOLEAN COMMENT 'Indicates whether distressed, REO (Real Estate Owned), or impaired assets are eligible for acquisition under this market segment (True = eligible). Used in deal sourcing filters and investment committee approval workflows.',
    `effective_date` DATE COMMENT 'Date from which this market segment definition became effective and available for use in deal classification and portfolio reporting. Supports point-in-time reporting and historical segment definition tracking.',
    `equity_multiple_max` DECIMAL(18,2) COMMENT 'Maximum target equity multiple for investments in this market segment (e.g., 2.50x for opportunistic). Defines the upper bound of expected return multiples used in fund performance benchmarking and investor reporting.',
    `equity_multiple_min` DECIMAL(18,2) COMMENT 'Minimum target equity multiple (total distributions / total equity invested) for investments in this market segment (e.g., 1.50x for core-plus). Used alongside IRR in investor return reporting and deal underwriting benchmarks.',
    `esg_classification` STRING COMMENT 'ESG (Environmental, Social, and Governance) classification for the market segment, indicating the level of ESG integration expected in investments. ESG Core = baseline compliance; ESG Enhanced = active ESG improvement targets; ESG Impact = measurable social/environmental outcomes required. Supports LEED, BREEAM, and GRESB reporting.. Valid values are `esg_core|esg_enhanced|esg_impact|not_classified`',
    `exit_strategy` STRING COMMENT 'Primary exit strategy indicator for investments in this market segment. Defines the expected disposition mechanism: outright sale, recapitalization, refinance and hold, IPO/REIT listing, long-term hold, or portfolio/bulk sale. Used in investment advisory, asset management planning, and investor reporting.. Valid values are `sale|recapitalization|refinance|ipo|hold|portfolio_sale`',
    `expiry_date` DATE COMMENT 'Date on which this market segment definition was retired or superseded. Null if the segment is currently active. Enables historical point-in-time queries and audit trail for segment reclassification events.',
    `external_benchmark_name` STRING COMMENT 'Name of the primary external performance benchmark associated with this market segment for investor reporting (e.g., NCREIF Property Index, NCREIF ODCE, MSCI Real Estate, INREV All Vehicles Index). Used in Argus Enterprise portfolio reporting and investor presentations.',
    `geographic_focus` STRING COMMENT 'Describes the geographic investment focus associated with this market segment (e.g., Gateway markets only, Secondary and tertiary markets, National diversified, Sun Belt metros). Used in deal sourcing strategy, CoStar market research filters, and portfolio geographic allocation reporting.',
    `hold_period_max_years` DECIMAL(18,2) COMMENT 'Maximum typical investment hold period in years for assets classified under this market segment (e.g., 10.0 years for core). Used in fund lifecycle planning, Discounted Cash Flow (DCF) horizon setting, and exit strategy modeling in Argus Enterprise.',
    `hold_period_min_years` DECIMAL(18,2) COMMENT 'Minimum typical investment hold period in years for assets classified under this market segment (e.g., 3.0 years for value-add). Used in Argus Enterprise DCF modeling, Weighted Average Lease Term (WALT) analysis, and investor fund lifecycle planning.',
    `income_return_focus` BOOLEAN COMMENT 'Indicates whether this market segment is primarily income-return focused (True) versus capital appreciation focused (False). Core and core-plus segments are typically income-focused; opportunistic and value-add are appreciation-focused. Used in portfolio allocation and investor mandate classification.',
    `inrev_strategy_code` STRING COMMENT 'INREV (European Association for Investors in Non-Listed Real Estate Vehicles) strategy classification code for cross-border fund reporting alignment. Used for European investor mandates and INREV benchmark submissions.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `investment_strategy_type` STRING COMMENT 'Classification of the investment strategy associated with this market segment per industry-standard NCREIF/INREV taxonomy. Core = stabilized, low-risk; Core-Plus = modest value creation; Value-Add = significant repositioning; Opportunistic = high-risk/high-return development or turnaround; Distressed = below-market acquisition of impaired assets. Null for residential segments where strategy type is not applicable.. Valid values are `core|core_plus|value_add|opportunistic|distressed`',
    `investor_type_target` STRING COMMENT 'Describes the target investor profile for this market segment (e.g., Institutional pension funds, High-net-worth individuals, Family offices, Sovereign wealth funds). Used in investor relations, fund marketing, and Salesforce CRM deal pipeline classification.',
    `is_active` BOOLEAN COMMENT 'Indicates whether this market segment is currently active and available for use in deal classification, portfolio reporting, and investment mandate assignment (True = active, False = retired/inactive). Inactive segments are retained for historical reporting continuity.',
    `last_reviewed_date` DATE COMMENT 'Date on which this market segment definition was last reviewed and validated by the data steward or investment committee. Supports reference data governance, periodic review cycles, and audit trail requirements.',
    `leverage_strategy` STRING COMMENT 'Qualitative leverage strategy descriptor for the market segment. Unlevered = all-equity; Low = LTV < 40%; Moderate = LTV 40–60%; High = LTV > 60%. Complements the target_ltv_max_pct field for narrative reporting and investor mandate screening.. Valid values are `unlevered|low_leverage|moderate_leverage|high_leverage`',
    `ncreif_benchmark_code` STRING COMMENT 'NCREIF Property Index benchmark code associated with this market segment for performance comparison (e.g., NPI, ODCE). Used in portfolio performance reporting, investor presentations, and Argus Enterprise benchmark analysis.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `occupancy_threshold_min_pct` DECIMAL(18,2) COMMENT 'Minimum acceptable physical occupancy percentage for assets classified under this market segment at acquisition or during the hold period (e.g., 85.00 for 85%). Used in deal screening, underwriting assumptions, and Yardi Voyager lease administration reporting.',
    `property_type_focus` STRING COMMENT 'Describes the primary property type(s) targeted by this market segment (e.g., Office, Retail, Industrial, Multifamily, Mixed-Use). Used in deal sourcing filters, CoStar comparable analysis, and portfolio sector allocation reporting. Free-text to accommodate multi-type segments.',
    `regulatory_compliance_notes` STRING COMMENT 'Free-text field capturing specific regulatory or compliance considerations applicable to this market segment (e.g., HUD affordability restrictions for affordable housing, REIT distribution requirements, SEC reporting obligations for publicly traded vehicles, LIHTC compliance for tax credit properties).',
    `residential_tier` STRING COMMENT 'Residential market tier classification for residential segments. Affordable = income-restricted housing (HUD AMI thresholds); Workforce = moderate-income households; Market-Rate = unsubsidized standard rental/for-sale; Luxury = premium amenity-rich product. Null for commercial segments.. Valid values are `affordable|workforce|market_rate|luxury`',
    `risk_profile` STRING COMMENT 'Qualitative risk descriptor for the market segment, reflecting expected volatility, leverage sensitivity, and execution complexity. Used in investor mandate screening, portfolio risk reporting, and deal approval workflows. Aligns with INREV risk classification framework.. Valid values are `low|moderate|moderate_high|high|very_high`',
    `segment_category` STRING COMMENT 'Broad asset class category to which this market segment belongs. Distinguishes commercial investment strategies (core, core-plus, value-add, opportunistic, distressed) from residential strategies (affordable, workforce, market-rate, luxury) and other asset classes. Drives portfolio allocation reporting and investor mandate compliance.. Valid values are `commercial|residential|mixed_use|industrial|hospitality|specialty`',
    `segment_code` STRING COMMENT 'Short, system-unique alphanumeric code identifying the market segment (e.g., CORE, CORE_PLUS, VALUE_ADD, OPPORTUNISTIC, DISTRESSED, AFFORDABLE, WORKFORCE, MKT_RATE, LUXURY). Used as the stable business key referenced by investment, valuation, brokerage, and transaction domains.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `segment_description` STRING COMMENT 'Detailed narrative description of the market segment, including its investment thesis, risk characteristics, typical asset profile, and use cases. Used in investor reporting, investment committee materials, and data governance documentation.',
    `segment_name` STRING COMMENT 'Full human-readable name of the market segment (e.g., Core, Core-Plus, Value-Add, Opportunistic, Distressed, Affordable Housing, Workforce Housing, Market-Rate, Luxury). Displayed in investor reports, portfolio dashboards, and deal classification screens.',
    `sort_order` STRING COMMENT 'Integer value controlling the display order of market segments in dropdown lists, reports, and dashboards. Lower values appear first. Enables business-defined ordering independent of alphabetical or ID-based sorting.',
    `target_cap_rate_max_pct` DECIMAL(18,2) COMMENT 'Maximum target Capitalization Rate (CAP Rate) percentage for acquisitions in this market segment, expressed as a percentage (e.g., 7.00 for 7%). Defines the upper bound of the CAP rate range used in deal screening and portfolio benchmarking.',
    `target_cap_rate_min_pct` DECIMAL(18,2) COMMENT 'Minimum target Capitalization Rate (CAP Rate) percentage for acquisitions in this market segment, expressed as a percentage (e.g., 4.50 for 4.5%). CAP Rate = Net Operating Income (NOI) / Property Value. Used in Argus Enterprise underwriting models and CoStar comparable analysis.',
    `target_dscr_min` DECIMAL(18,2) COMMENT 'Minimum acceptable Debt Service Coverage Ratio (DSCR) for assets in this market segment (e.g., 1.25). DSCR = Net Operating Income (NOI) / Total Debt Service. Used in lender covenant compliance, debt instrument structuring, and portfolio risk monitoring.',
    `target_irr_max_pct` DECIMAL(18,2) COMMENT 'Maximum target Internal Rate of Return (IRR) percentage for investments classified under this market segment, expressed as a percentage (e.g., 15.00 for 15%). Defines the upper bound of the IRR range used in deal underwriting and investor mandate compliance checks.',
    `target_irr_min_pct` DECIMAL(18,2) COMMENT 'Minimum target unlevered or levered Internal Rate of Return (IRR) percentage for investments classified under this market segment, expressed as a percentage (e.g., 8.00 for 8%). Defines the lower bound of the IRR range used in deal underwriting, Argus Enterprise cash flow models, and investor reporting against NCREIF benchmarks.',
    `target_ltv_max_pct` DECIMAL(18,2) COMMENT 'Maximum target Loan-to-Value (LTV) ratio percentage for debt financing on assets in this market segment, expressed as a percentage (e.g., 65.00 for 65%). Defines the leverage ceiling used in debt structuring, CMBS underwriting, and DSCR compliance monitoring.',
    `typical_asset_size_max_usd` DECIMAL(18,2) COMMENT 'Maximum typical asset value in USD for investments classified under this market segment (e.g., 500,000,000 for $500M). Defines the upper bound of deal size for mandate compliance and portfolio concentration limits.',
    `typical_asset_size_min_usd` DECIMAL(18,2) COMMENT 'Minimum typical asset value in USD for investments classified under this market segment (e.g., 10,000,000 for $10M). Used in deal sourcing filters, portfolio allocation guidelines, and investment mandate compliance in MRI Software and Argus Enterprise.',
    `value_creation_approach` STRING COMMENT 'Narrative description of the primary value creation approach for this market segment (e.g., Stabilized income with minimal capital expenditure, Lease-up of vacant space with light renovation, Major repositioning, redevelopment, or change of use). Used in investment committee presentations and investor reporting.',
    CONSTRAINT pk_market_segment PRIMARY KEY(`market_segment_id`)
) COMMENT 'Standardized market segment and investment strategy classifications used for portfolio analysis, deal sourcing, and performance benchmarking. Commercial segments: core, core-plus, value-add, opportunistic, and distressed. Residential segments: affordable, workforce, market-rate, and luxury. Each segment defines risk profile descriptors, target IRR and CAP rate ranges, typical hold period benchmarks, leverage parameters, and exit strategy indicators. Referenced by investment, valuation, brokerage, and transaction domains for deal classification, portfolio allocation analysis, and investor reporting against NCREIF and INREV benchmarks.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`zoning_code` (
    `zoning_code_id` BIGINT COMMENT 'Unique surrogate identifier for each zoning code record in the enterprise reference registry. Primary key. [Role: REFERENCE_LOOKUP — _canonical_skip_reason: This entity is a controlled vocabulary / code-list table providing standardized zoning designations; per-role minimum categories do not apply.]',
    `country_id` BIGINT COMMENT 'Foreign key linking to reference.country. Business justification: Zoning codes are municipal/county designations that belong to a specific countrys legal jurisdiction. Normalizing country_code STRING to a FK against the ISO 3166-1 country registry ensures referenti',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: Zoning codes are enacted by specific municipalities or counties that exist as nodes in the geographic hierarchy. Linking zoning_code to geographic_hierarchy enables spatial queries (e.g., all zoning c',
    `affordable_housing_requirement_flag` BOOLEAN COMMENT 'Indicates whether this zoning designation includes an inclusionary zoning requirement mandating a percentage of residential units be designated as affordable housing. True = affordable housing set-aside required; False = no such requirement. Relevant for HUD compliance and residential development planning.',
    `conditional_uses` STRING COMMENT 'Narrative description of land uses that may be permitted under this zoning designation subject to approval of a Conditional Use Permit (CUP) by the governing authority. Relevant for development feasibility and entitlement risk assessment.',
    `density_class` STRING COMMENT 'Density classification associated with the zoning designation, indicating the intensity of permitted land use. Used in development feasibility analysis and portfolio density reporting.. Valid values are `low|medium|high|very_high|not_applicable`',
    `effective_date` DATE COMMENT 'Date on which this zoning designation became legally effective in the governing jurisdiction. Used for historical zoning analysis and regulatory compliance verification.',
    `environmental_overlay_flag` BOOLEAN COMMENT 'Indicates whether this zoning designation includes or is subject to an environmental overlay or restriction (e.g., flood zone, wetlands buffer, brownfield remediation zone, EPA-designated area). True = environmental overlay applies; False = no environmental overlay.',
    `esg_designation` STRING COMMENT 'ESG-related zoning designation or incentive associated with this zoning code, indicating whether the jurisdiction mandates or incentivizes green building standards such as LEED or BREEAM for developments under this designation. Supports ESG portfolio reporting.. Valid values are `leed_required|breeam_required|green_building_incentive|sustainability_overlay|none`',
    `expiry_date` DATE COMMENT 'Date on which this zoning designation is scheduled to expire or be superseded, if applicable (e.g., temporary zoning designations, sunset provisions). Null for permanent designations.',
    `far_max` DECIMAL(18,2) COMMENT 'Maximum Floor Area Ratio (FAR) permitted under this zoning designation, expressed as the ratio of total building floor area to the area of the parcel. A FAR of 2.0 means total floor area may be up to twice the lot area. Critical input for development feasibility analysis in Argus Enterprise and CoStar.',
    `far_min` DECIMAL(18,2) COMMENT 'Minimum Floor Area Ratio (FAR) required under this zoning designation, where applicable. Some jurisdictions mandate minimum development intensity to prevent underutilization of zoned land.',
    `front_setback_ft` DECIMAL(18,2) COMMENT 'Minimum required distance in feet between the front property line and the nearest building face, as mandated by this zoning designation. Used in site planning and architectural design.',
    `gis_layer_reference` STRING COMMENT 'Reference identifier or URL for the municipal Geographic Information System (GIS) layer or dataset from which this zoning designation is sourced. Enables spatial data integration with CoStar Suite and enterprise GIS platforms.',
    `height_limit_ft` DECIMAL(18,2) COMMENT 'Maximum permitted building height in feet as specified by the zoning designation. Used in development feasibility analysis, BIM planning, and construction oversight in Procore.',
    `height_limit_stories` STRING COMMENT 'Maximum permitted number of building stories as specified by the zoning designation, where the jurisdiction expresses height restrictions in stories rather than feet.',
    `jurisdiction_name` STRING COMMENT 'Name of the municipal or county authority that issued and administers this zoning designation (e.g., City of Los Angeles, Cook County, City of New York). Enables multi-jurisdiction portfolio management.',
    `jurisdiction_type` STRING COMMENT 'Type of governing authority that administers this zoning code, distinguishing between city, county, township, or special district jurisdictions.. Valid values are `city|county|township|borough|municipality|special_district`',
    `last_amended_date` DATE COMMENT 'Date of the most recent formal amendment to this zoning designation by the governing jurisdiction. Tracks regulatory change history for compliance and portfolio impact analysis.',
    `lot_coverage_pct` DECIMAL(18,2) COMMENT 'Maximum percentage of the lot area that may be covered by buildings and impervious structures under this zoning designation. Expressed as a percentage (e.g., 60.00 = 60%). Used in site planning and development feasibility.',
    `min_lot_size_sqf` DECIMAL(18,2) COMMENT 'Minimum parcel area in square feet (SQF) required for a lot to be developed under this zoning designation. Critical for subdivision analysis and land acquisition due diligence.',
    `min_lot_width_ft` DECIMAL(18,2) COMMENT 'Minimum required lot frontage width in feet as specified by the zoning designation. Affects parcel subdivision feasibility and site design.',
    `notes` STRING COMMENT 'Free-text operational notes maintained by the enterprise data steward regarding this zoning code record, including data quality observations, pending updates, or cross-reference information not captured in structured fields.',
    `ordinance_reference` STRING COMMENT 'Official ordinance number, resolution number, or legislative reference that established or most recently amended this zoning designation (e.g., Ordinance No. 2023-045). Supports regulatory compliance documentation and audit trails.',
    `overlay_district_flag` BOOLEAN COMMENT 'Indicates whether this zoning code represents a special overlay district that applies supplemental regulations on top of a base zoning designation (e.g., historic preservation overlay, flood plain overlay, transit corridor overlay). True = overlay district; False = base zoning designation.',
    `parking_ratio_min` DECIMAL(18,2) COMMENT 'Minimum required off-street parking spaces per unit of use (e.g., spaces per 1,000 SQF of GLA, or spaces per residential unit) as mandated by this zoning designation. Used in development feasibility and site planning.',
    `parking_ratio_unit` STRING COMMENT 'Unit of measure denominator for the minimum parking ratio (e.g., per_1000_sqf for commercial uses, per_unit for residential uses). Provides context for interpreting the parking_ratio_min value.. Valid values are `per_1000_sqf|per_unit|per_seat|per_bed|per_employee|not_applicable`',
    `permitted_uses` STRING COMMENT 'Narrative or semi-structured description of land uses permitted by right under this zoning designation without requiring a conditional use permit or variance (e.g., Single-family detached dwellings, accessory structures, home occupations). Sourced from municipal zoning ordinance text.',
    `prohibited_uses` STRING COMMENT 'Narrative description of land uses explicitly prohibited under this zoning designation. Critical for acquisition due diligence and regulatory compliance screening.',
    `rear_setback_ft` DECIMAL(18,2) COMMENT 'Minimum required distance in feet between the rear property line and the nearest building face, as mandated by this zoning designation.',
    `rezoning_pending_flag` BOOLEAN COMMENT 'Indicates whether a formal rezoning application or amendment is currently pending with the governing jurisdiction for this zoning designation. True = active rezoning proceeding; False = no pending rezoning. Relevant for portfolio risk monitoring.',
    `side_setback_ft` DECIMAL(18,2) COMMENT 'Minimum required distance in feet between the side property line and the nearest building face, as mandated by this zoning designation.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this zoning code record was sourced or last updated (e.g., costar for CoStar Suite, municipal_gis for direct municipal GIS feed, yardi for Yardi Voyager). Supports data lineage and master data management.. Valid values are `costar|yardi|mri|municipal_gis|manual|other`',
    `state_code` STRING COMMENT 'Two-letter U.S. state abbreviation (ISO 3166-2:US) or equivalent provincial/regional code for the jurisdiction in which this zoning designation applies. Supports geographic filtering and regulatory compliance reporting.. Valid values are `^[A-Z]{2}$`',
    `subcategory` STRING COMMENT 'Secondary classification providing finer granularity within the primary category (e.g., Single-Family Low Density, Neighborhood Commercial, Heavy Industrial, Transit-Oriented Mixed-Use). [ENUM-REF-CANDIDATE: single_family_low_density|single_family_medium_density|multifamily|neighborhood_commercial|general_commercial|regional_commercial|light_industrial|heavy_industrial|mixed_use_residential|mixed_use_commercial|transit_oriented|agricultural_general|agricultural_conservation — promote to reference product]',
    `variance_allowed_flag` BOOLEAN COMMENT 'Indicates whether the governing jurisdiction permits applications for variances from the standard development regulations associated with this zoning designation. True = variances may be applied for; False = no variance process available.',
    `variance_history_notes` STRING COMMENT 'Free-text notes summarizing the history of variances granted or denied for properties under this zoning designation. Supports development feasibility analysis and entitlement risk assessment.',
    `zoning_code_category` STRING COMMENT 'High-level classification grouping the zoning code into a primary land-use category. Drives portfolio segmentation, development feasibility screening, and regulatory compliance reporting. [ENUM-REF-CANDIDATE: residential|commercial|industrial|mixed_use|agricultural|special_overlay|planned_development|open_space — 8 candidates stripped; promote to reference product]',
    `zoning_code_code` STRING COMMENT 'Official alphanumeric zoning designation assigned by the governing municipality or county (e.g., R1, C2, I1, MU, A, PD). This is the externally-recognized code used in regulatory filings, title reports, and GIS databases.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `zoning_code_description` STRING COMMENT 'Extended narrative description of the zoning designation, including its planning intent, applicable land use policies, and any special conditions or notes sourced from the municipal zoning ordinance. Provides context for business users and analysts.',
    `zoning_code_name` STRING COMMENT 'Full descriptive name of the zoning designation as defined by the issuing jurisdiction (e.g., Single-Family Residential, General Commercial, Light Industrial, Mixed-Use Corridor).',
    `zoning_code_status` STRING COMMENT 'Current lifecycle status of the zoning code record within the enterprise reference registry. active indicates the code is currently in force; superseded indicates it has been replaced by a newer designation; pending_amendment indicates a formal rezoning or amendment is in progress.. Valid values are `active|inactive|pending_amendment|superseded|under_review`',
    CONSTRAINT pk_zoning_code PRIMARY KEY(`zoning_code_id`)
) COMMENT 'Authoritative registry of municipal and county zoning designations applicable to portfolio properties — residential (R1–R5), commercial (C1–C3), industrial (I1–I2), mixed-use (MU), agricultural (A), and special overlay districts. Captures FAR limits, height restrictions, permitted uses, conditional use requirements, and variance history. Sourced from municipal GIS databases and maintained for regulatory compliance and development feasibility analysis.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`currency_code` (
    `currency_code_id` BIGINT COMMENT 'Unique surrogate identifier for each currency code record in the enterprise reference registry. Primary key for the currency_code reference product. [Role: REFERENCE_LOOKUP — exempt from per-role minimum-category requirements; this is a controlled vocabulary / ISO code-list table providing standardized currency identifiers for multi-currency financial operations across the real estate portfolio.]',
    `country_id` BIGINT COMMENT 'Foreign key linking to reference.country. Business justification: Currencies are issued by and associated with countries (ISO 4217 maps to ISO 3166-1). Linking currency_code to the country registry enables joining to country-level attributes (VAT applicability, sanc',
    `conversion_factor` DECIMAL(18,2) COMMENT 'Fixed conversion factor applied when this currency was replaced by a successor currency (e.g., 1 EUR = 1.95583 DEM). Applicable only to discontinued currencies with a defined successor. Used for historical financial restatement and legacy portfolio valuation in Argus Enterprise and SAP S/4HANA.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this currency code record was first created in the enterprise reference registry. Supports audit trail requirements under SOX Section 404 and data governance lineage tracking in the Databricks Silver layer.',
    `currency_code_code` STRING COMMENT 'Three-letter alphabetic currency code as defined by ISO 4217 (e.g., USD, EUR, GBP, CAD, AUD, JPY). Used as the business-facing identifier across all financial systems including Yardi Voyager AP/AR, SAP S/4HANA GL, MRI Software, and Argus Enterprise for multi-currency portfolio operations.. Valid values are `^[A-Z]{3}$`',
    `currency_code_name` STRING COMMENT 'Full official name of the currency as defined by ISO 4217 (e.g., United States Dollar, Euro, British Pound Sterling). Displayed in financial reports, Argus Enterprise valuation models, and investor-facing portfolio reporting for clarity.',
    `currency_type` STRING COMMENT 'Classification of the currency by its underlying nature. Fiat currencies are government-issued legal tender (the vast majority of ISO 4217 codes). SDR (Special Drawing Rights) is the IMF composite currency. Precious metal codes (XAU for gold, XAG for silver) and crypto codes may appear in investment portfolios or alternative asset valuations.. Valid values are `fiat|crypto|precious_metal|sdr`',
    `decimal_separator` STRING COMMENT 'Character used as the decimal point separator when displaying monetary amounts in this currency (e.g., period for USD/GBP, comma for EUR in many European countries). Critical for correct parsing and display of financial figures in multi-locale real estate reporting environments.',
    `discontinuation_date` DATE COMMENT 'Date on which this currency code was officially discontinued or superseded per ISO 4217 (e.g., legacy national currencies replaced by EUR). Null for currently active currencies. Retained for historical lease and transaction records in Yardi Voyager and MRI Software that reference the discontinued currency.',
    `display_format` STRING COMMENT 'Locale-specific display format pattern for rendering monetary amounts in this currency (e.g., #,##0.00 for USD, #.##0,00 for EUR in European locales). Controls how currency values are presented in investor reports, NOI statements, and Argus Enterprise output for international portfolio stakeholders.',
    `effective_date` DATE COMMENT 'Date from which this currency code became officially valid and available for use in financial transactions per ISO 4217. Supports historical currency tracking for legacy portfolio transactions, particularly relevant for currencies introduced through monetary union events (e.g., EUR introduction date) or currency redenomination.',
    `exchange_rate_source` STRING COMMENT 'Name or identifier of the authoritative external source used to obtain exchange rates for this currency (e.g., European Central Bank, Federal Reserve, Bloomberg, Reuters/Refinitiv, ICE). Governs which rate feed is consumed by SAP S/4HANA and Yardi Voyager for currency translation in AP/AR and GL consolidation.',
    `exchange_rate_type` STRING COMMENT 'Type of exchange rate applied when translating this currency for financial reporting purposes. Spot rate is used for transaction-date translation; average rate for income statement items; closing rate for balance sheet items per FASB ASC 830 and IAS 21. Budget rate is used for planning in Argus Enterprise DCF models.. Valid values are `spot|average|closing|budget|fixed`',
    `is_active` BOOLEAN COMMENT 'Indicates whether this currency is currently active and available for use in financial transactions across the enterprise. Inactive currencies (e.g., discontinued or superseded ISO codes) are retained for historical reporting but blocked from new transaction entry in Yardi Voyager and SAP S/4HANA.',
    `is_freely_convertible` BOOLEAN COMMENT 'Indicates whether this currency can be freely exchanged for other currencies without government restrictions or capital controls. Non-convertible or restricted currencies require special handling in cross-border real estate investment structures, repatriation planning, and REIT distribution calculations.',
    `is_functional_currency` BOOLEAN COMMENT 'Indicates whether this currency is designated as the functional currency for the enterprise or a specific legal entity under FASB ASC 830 (Foreign Currency Matters) or IASB IAS 21. The functional currency is the primary currency of the economic environment in which the REIT or fund entity operates, used as the base for financial consolidation in SAP S/4HANA.',
    `is_hard_currency` BOOLEAN COMMENT 'Indicates whether this currency is classified as a hard currency — a globally accepted, stable reserve currency (e.g., USD, EUR, GBP, JPY, CHF). Hard currency designation influences lease denomination decisions in international commercial real estate, particularly for NNN leases in emerging markets where rents may be quoted in USD or EUR.',
    `is_reporting_currency` BOOLEAN COMMENT 'Indicates whether this currency is designated as the reporting currency for consolidated financial statements and SEC/regulatory filings. Distinct from functional currency — a REIT may operate in multiple functional currencies but report in a single reporting currency (typically USD) for investor and regulatory purposes.',
    `iso_4217_status` STRING COMMENT 'Official status of the currency code within the ISO 4217 standard. Active codes are currently in circulation; historic codes have been withdrawn or superseded; fund codes represent monetary funds (e.g., XDR for SDR). Drives eligibility rules for new transaction entry across Yardi Voyager, MRI Software, and SAP S/4HANA.. Valid values are `active|historic|fund`',
    `minor_unit_decimal_places` STRING COMMENT 'Number of decimal places used for the minor unit of the currency as specified by ISO 4217 (e.g., 2 for USD/EUR/GBP representing cents, 0 for JPY/KWD which has no minor unit, 3 for KWD). Critical for correct rounding in AP/AR processing in Yardi Voyager, rent schedule calculations, and FASB/IASB-compliant financial reporting.',
    `notes` STRING COMMENT 'Free-text field for additional context, special handling instructions, or regulatory notes associated with this currency (e.g., capital control restrictions, special accounting treatment requirements under IAS 29 for hyperinflationary economies, or notes on currency union membership). Used by treasury and finance teams for operational guidance.',
    `numeric_code` STRING COMMENT 'Three-digit numeric code assigned to the currency under ISO 4217 (e.g., 840 for USD, 978 for EUR). Used in electronic data interchange, CMBS/RMBS reporting, and SAP S/4HANA financial consolidation where numeric codes are required for system interoperability.. Valid values are `^[0-9]{3}$`',
    `pegged_to_currency_code` STRING COMMENT 'ISO 4217 code of the anchor currency to which this currency is officially pegged (e.g., AED pegged to USD, HKD pegged to USD). Relevant for international real estate portfolios in GCC and Asian markets where currency peg stability affects investment return calculations and DSCR analysis in Argus Enterprise.. Valid values are `^[A-Z]{3}$`',
    `region` STRING COMMENT 'Broad geographic region associated with the currency (e.g., North America, Europe, Asia Pacific, Middle East, Latin America). Used for regional portfolio aggregation, cross-border investment analysis, and AUM reporting in Argus Enterprise and MRI Software.',
    `rounding_rule` STRING COMMENT 'Rounding convention applied to monetary amounts in this currency during financial calculations, AP/AR processing, and rent schedule generation. Half-even (bankers rounding) is standard for FASB/IASB-compliant financial reporting. Governs rounding behavior in Yardi Voyager rent calculations, CAM reconciliations, and SAP S/4HANA GL postings.. Valid values are `half_up|half_down|half_even|ceiling|floor`',
    `source_system_code` STRING COMMENT 'Identifier of the operational system of record from which this currency code record was sourced or is mastered (e.g., SAP_S4HANA, YARDI_VOYAGER, MRI_SOFTWARE). Supports data lineage tracking and reconciliation across the enterprise lakehouse Silver layer.',
    `source_system_currency_key` STRING COMMENT 'Native key or identifier used to represent this currency in the originating source system (e.g., SAP currency key USD, Yardi currency code field value). Enables cross-system reconciliation and ETL mapping between the enterprise reference registry and operational systems.',
    `subunit_name` STRING COMMENT 'Name of the minor unit or subunit of the currency (e.g., Cent for USD/EUR, Penny for GBP, Sen for JPY). Used in detailed financial disclosures, lease rent schedules expressed in subunit precision, and CAM reconciliation statements in Yardi Voyager.',
    `successor_currency_code` STRING COMMENT 'ISO 4217 three-letter code of the currency that replaced this currency upon discontinuation (e.g., EUR as successor to DEM, FRF, ITL). Used to support currency migration mapping for historical portfolio restatement and financial consolidation in SAP S/4HANA.. Valid values are `^[A-Z]{3}$`',
    `symbol` STRING COMMENT 'Commonly used typographic symbol representing the currency (e.g., $ for USD, € for EUR, £ for GBP, ¥ for JPY). Used in UI displays, lease rent schedules, NOI statements, and investor reporting dashboards for human-readable financial presentation.',
    `symbol_position` STRING COMMENT 'Indicates whether the currency symbol is displayed before (prefix) or after (suffix) the numeric amount per locale convention (e.g., prefix for USD: $1,000; suffix for SEK: 1 000 kr). Used in report rendering engines for investor communications and tenant-facing financial statements.. Valid values are `prefix|suffix`',
    `thousands_separator` STRING COMMENT 'Character used as the thousands grouping separator when displaying monetary amounts in this currency (e.g., comma for USD/GBP, period for EUR in many European countries, space for CHF). Ensures correct formatting in investor-facing financial reports and lease abstracts.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this currency code record was last modified in the enterprise reference registry. Used for change data capture, incremental ETL processing, and audit compliance under SOX Section 404.',
    `volatility_classification` STRING COMMENT 'Classification of the currencys exchange rate volatility relative to major reserve currencies. Hyperinflationary designation triggers special accounting treatment under FASB ASC 830-10-45 and IAS 29 for real estate entities operating in those economies. Informs FX risk management and hedging strategy for international portfolio investments.. Valid values are `stable|moderate|volatile|hyperinflationary`',
    CONSTRAINT pk_currency_code PRIMARY KEY(`currency_code_id`)
) COMMENT 'ISO 4217 currency code registry supporting multi-currency financial operations across international real estate portfolios. Stores currency code, name, symbol, decimal precision, and active status. Includes exchange rate source reference and functional currency designation for REIT and fund-level financial consolidation under SAP S/4HANA. Supports AP/AR multi-currency processing in Yardi Voyager and financial reporting under FASB/IASB standards.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`uom` (
    `uom_id` BIGINT COMMENT 'Unique surrogate identifier for each unit-of-measure record in the enterprise UOM registry. Primary key. [REFERENCE_LOOKUP role — canonical_skip_reason: This entity is a controlled vocabulary / code-list table; per-role minimum categories do not apply.]',
    `applicable_property_types` STRING COMMENT 'Comma-separated list of property type codes for which this UOM is valid (e.g., office,retail,industrial for SQF; land for acres; parking for stalls). Restricts UOM selection in Yardi Voyager lease setup and MRI Software property configuration to contextually appropriate measures.',
    `area_standard` STRING COMMENT 'For area-dimension UOMs, the industry measurement standard that defines how the area is calculated (e.g., BOMA for US office, IPMS for international, GLA for retail, NLA for net leasable area, GFA for gross floor area). Null for non-area UOMs. Critical for appraisal compliance and cross-border portfolio comparability. [ENUM-REF-CANDIDATE: BOMA|IPMS|GLA|NLA|GFA|RICS|other — 7 candidates stripped; promote to reference product]',
    `conversion_factor` DECIMAL(18,2) COMMENT 'Multiplicative factor to convert one unit of this UOM to one unit of the base_uom_code (e.g., 1 SQF = 0.0929030400 SQM; 1 LF = 0.3048 LM). A value of 1.0 indicates this UOM is itself the base unit. Used in Argus Enterprise and MRI Software for cross-currency and cross-metric portfolio roll-ups.',
    `conversion_formula` STRING COMMENT 'Optional algebraic formula string for non-linear conversions where a simple multiplicative factor is insufficient (e.g., temperature scales). For most real estate UOMs this is null; populated only when the conversion requires an offset or compound expression.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this UOM record was first created in the enterprise reference data registry. Supports audit trail requirements under SOX ITGC controls and data governance lineage tracking.',
    `default_region_code` STRING COMMENT 'ISO 3166-1 alpha-2 or alpha-3 country/region code for which this UOM is the default standard (e.g., US for SQF, DE/GB/AU for SQM). Drives automatic UOM defaulting in Yardi Voyager and MRI Software when creating properties in a given jurisdiction.. Valid values are `^[A-Z]{2,3}$`',
    `dimension_type` STRING COMMENT 'Physical or financial dimension category the UOM belongs to: area (SQF, SQM, GLA, NLA, GFA), linear (LF, LM), volume (CF, CM), weight (LB, KG), rate (PSF/year, PSM/month), count (units, floors), currency (USD, EUR), or other. Drives validation rules in rent calculations and valuation models. [ENUM-REF-CANDIDATE: area|linear|volume|weight|rate|count|currency|other — 8 candidates stripped; promote to reference product]',
    `display_order` STRING COMMENT 'Integer sort order controlling the sequence in which UOMs appear in dropdown lists and selection menus across Yardi Voyager, MRI Software, and Argus Enterprise. Lower values appear first; commonly used UOMs (SQF, SQM) are assigned low values.',
    `effective_date` DATE COMMENT 'Date from which this UOM record is valid and available for use in new transactions, leases, and valuations. Supports temporal validity management in the enterprise reference data registry.',
    `expiry_date` DATE COMMENT 'Date after which this UOM record is no longer valid for use in new transactions. Null indicates no planned expiry. Used to phase out deprecated UOMs while preserving historical data integrity.',
    `is_base_unit` BOOLEAN COMMENT 'Indicates whether this UOM is the designated base unit for its dimension type and measurement system (True = base unit; False = derived unit). Base units have a conversion_factor of exactly 1.0.',
    `is_rate_based` BOOLEAN COMMENT 'Indicates whether this UOM is a rate measure combining a quantity dimension with a time period (e.g., PSF/year, PSM/month, $/SQF/year). Rate-based UOMs require both a numerator UOM and a denominator time period for correct rent and NOI calculations.',
    `is_regulatory_disclosure_required` BOOLEAN COMMENT 'Indicates whether values expressed in this UOM must be disclosed in regulatory filings (True = required). For example, GLA in SQF/SQM is required in SEC REIT filings, HUD disclosures, and LEED/BREEAM certification submissions.',
    `is_rentable_area_measure` BOOLEAN COMMENT 'Indicates whether this UOM is used to express rentable area for lease billing purposes (True = rentable area measure such as SQF or SQM under BOMA/IPMS). Drives rent calculation logic in Yardi Voyager lease administration and FASB ASC 842 / IFRS 16 right-of-use asset computations.',
    `iso_uom_code` STRING COMMENT 'Corresponding ISO 80000 or UN/CEFACT Recommendation 20 unit code for interoperability with SAP S/4HANA procurement, ERP integrations, and international regulatory submissions (e.g., MTK for square meters, FTK for square feet, KGM for kilograms).. Valid values are `^[A-Z0-9]{1,10}$`',
    `measurement_system` STRING COMMENT 'Indicates whether the UOM belongs to the imperial, metric (SI), US customary, or other measurement system. Critical for cross-border portfolio reporting and regulatory area disclosures where jurisdictions mandate specific systems (e.g., metric in EU, imperial in US).. Valid values are `imperial|metric|us_customary|other`',
    `notes` STRING COMMENT 'Free-text field for additional governance notes, known exceptions, or migration guidance associated with this UOM record (e.g., Use SQM for all EU properties per portfolio policy effective 2024-01-01). Maintained by the data governance team.',
    `precision_decimal_places` STRING COMMENT 'Number of decimal places to which values expressed in this UOM should be rounded for display and storage (e.g., 2 for SQF area, 4 for conversion factors, 0 for whole-unit counts). Ensures consistent rounding in lease abstracts, valuation reports, and regulatory area disclosures.',
    `rate_denominator_uom_code` STRING COMMENT 'For rate-based UOMs (is_rate_based = True), the UOM code of the denominator area or volume measure (e.g., for PSF/year the denominator is SQF). Null for non-rate UOMs.. Valid values are `^[A-Z0-9/_-]{1,20}$`',
    `rate_numerator_uom_code` STRING COMMENT 'For rate-based UOMs (is_rate_based = True), the UOM code of the numerator quantity (e.g., for PSF/year the numerator is USD). Null for non-rate UOMs. Enables decomposition of rent rates into currency and area components for PSF/PSM analytics.. Valid values are `^[A-Z0-9/_-]{1,20}$`',
    `rate_time_period` STRING COMMENT 'For rate-based UOMs, the time period denominator of the rate (e.g., annual for PSF/year, monthly for PSM/month). Drives annualization logic in NOI statements, rent schedules, and Argus Enterprise cash flow models. [ENUM-REF-CANDIDATE: annual|monthly|weekly|daily|per_sqf|per_sqm|other — 7 candidates stripped; promote to reference product]',
    `reso_uom_code` STRING COMMENT 'RESO Data Dictionary standardized UOM code for MLS and real estate data exchange interoperability (e.g., SquareFeet, SquareMeters, Acres). Enables consistent data syndication via CoStar Suite and MLS platforms.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this UOM definition was originally sourced or is mastered (e.g., yardi for Yardi Voyager, mri for MRI Software, sap for SAP S/4HANA). Supports data lineage tracking and conflict resolution during ETL reconciliation. [ENUM-REF-CANDIDATE: yardi|mri|argus|sap|costar|procore|other — 7 candidates stripped; promote to reference product]',
    `source_system_uom_code` STRING COMMENT 'The native identifier or code assigned to this UOM in the originating source system (e.g., Yardi Voyager internal UOM key, SAP S/4HANA unit code). Enables bidirectional reconciliation and cross-system mapping during data integration.',
    `successor_uom_code` STRING COMMENT 'UOM code of the replacement unit when this UOM is deprecated or superseded. Enables automated migration of historical records and guides users to the current standard UOM during data entry in Yardi Voyager and MRI Software.. Valid values are `^[A-Z0-9/_-]{1,20}$`',
    `symbol` STRING COMMENT 'Standardized typographic symbol for the unit (e.g., ft², m², lb, kg, $/ft²/yr). Used in printed lease documents, CoStar data exports, and Argus Enterprise cash flow models.. Valid values are `^.{1,15}$`',
    `uom_category` STRING COMMENT 'Business-facing grouping of the UOM within real estate operations (e.g., Leasable Area, Gross Area, Rent Rate, Construction Measure, Valuation Metric, Utility Consumption). Supports filtering in Argus Enterprise and MRI Software reporting. [ENUM-REF-CANDIDATE: leasable_area|gross_area|rent_rate|construction_measure|valuation_metric|utility_consumption|land_area|parking — promote to reference product]',
    `uom_code` STRING COMMENT 'Short, system-facing alphanumeric code uniquely identifying the unit of measure (e.g., SQF, SQM, PSF, LF, CF, LB, KG). Used as the canonical lookup key across Yardi Voyager, MRI Software, Argus Enterprise, and SAP S/4HANA integrations.. Valid values are `^[A-Z0-9/_-]{1,20}$`',
    `uom_description` STRING COMMENT 'Detailed narrative description of the UOM, including its definition, applicable measurement context, and any industry-specific nuances (e.g., distinction between GLA and NLA, BOMA vs IPMS methodology differences). Used in data governance documentation and business glossary.',
    `uom_name` STRING COMMENT 'Full human-readable name of the unit of measure (e.g., Square Feet, Square Meters, Linear Feet, Pounds per Square Foot per Year). Displayed in reports, lease abstracts, and valuation outputs.',
    `uom_status` STRING COMMENT 'Lifecycle status of the UOM record: active (in current use), inactive (no longer used for new records), deprecated (superseded by another UOM, retained for historical data), pending_review (under governance review). Controls availability in Yardi Voyager and MRI Software UOM selection lists.. Valid values are `active|inactive|deprecated|pending_review`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this UOM record. Used to detect stale reference data and trigger downstream cache invalidation in Yardi Voyager, MRI Software, and Argus Enterprise integrations.',
    CONSTRAINT pk_uom PRIMARY KEY(`uom_id`)
) COMMENT 'Enterprise unit-of-measure registry for all measurement dimensions in real estate operations — area (SQF, SQM, GLA, NLA, GFA), linear (LF, LM), volume (CF, CM), weight (LB, KG), and rate-based measures (PSF/year, PSM/month). Defines conversion factors between imperial and metric systems, default UOM by geographic region, and applicable property types per measure. Critical for consistent rent calculations, valuation metrics, cross-border portfolio reporting, and regulatory area disclosures.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`industry_classification` (
    `industry_classification_id` BIGINT COMMENT 'Unique surrogate identifier for each industry classification code record in the enterprise reference repository. Serves as the primary key for this lookup table. [_canonical_skip_reason: REFERENCE_LOOKUP — small enumeration/code-list entity; per-role minimum categories do not apply.]',
    `classification_system` STRING COMMENT 'The industry classification standard or system to which this code belongs. Supported systems include NAICS (North American Industry Classification System), SIC (Standard Industrial Classification), GICS (Global Industry Classification Standard), NACE (European industry classification), ANZSIC (Australian/New Zealand), and ISIC (International Standard Industrial Classification). Determines how the code is interpreted and which authority governs it.. Valid values are `NAICS|SIC|GICS|NACE|ANZSIC|ISIC`',
    `code_version` STRING COMMENT 'The version or revision year of the classification system under which this code is defined (e.g., NAICS 2022, NAICS 2017, SIC 1987). Classification systems are periodically revised; version tracking ensures codes are interpreted against the correct edition for historical comparability and regulatory compliance.',
    `costar_category` STRING COMMENT 'The corresponding tenant industry category as defined in CoStar Suites market analytics taxonomy. CoStar uses its own proprietary tenant categorization that maps to but does not always align 1:1 with NAICS/SIC codes. Populated to enable direct integration with CoStar comparable lease data, market research reports, and tenant mix benchmarking against market peers.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this industry classification code record was first loaded into the enterprise reference repository. Supports data lineage tracking, audit trail requirements under SOX financial controls, and change management for the reference data governance process.',
    `credit_risk_tier` STRING COMMENT 'General credit risk tier associated with tenants in this industry classification, based on historical default rates and sector credit quality benchmarks. Used in lease underwriting, DSCR analysis, and portfolio risk concentration reporting. Supports Argus Enterprise cash flow modeling assumptions and MRI Investment Management risk-adjusted return calculations.. Valid values are `investment_grade|near_investment_grade|speculative|high_risk|unrated`',
    `effective_date` DATE COMMENT 'The date from which this industry classification code is officially valid and available for use, as published by the governing authority. For NAICS, this aligns with the edition release date (e.g., 2017-01-01 for NAICS 2017). Ensures tenant classifications are assigned using codes valid at the time of lease execution.',
    `esg_risk_category` STRING COMMENT 'The ESG risk category associated with tenants or occupiers in this industry classification, reflecting environmental impact, social responsibility, and governance risk exposure. Used in ESG portfolio reporting, LEED/BREEAM tenant engagement programs, and green lease structuring. Supports SEC ESG disclosure requirements for publicly traded REITs and institutional investor reporting.. Valid values are `low|medium|high|very_high|not_assessed`',
    `expiry_date` DATE COMMENT 'The date on which this industry classification code ceases to be officially valid, typically coinciding with the release of a revised edition of the classification system. Null for codes that remain active in the current edition. Used to enforce code validity checks during tenant onboarding and lease amendment processing.',
    `gics_equivalent_code` STRING COMMENT 'The corresponding GICS 8-digit sub-industry code for records originating from NAICS or SIC systems. Used for investment portfolio analysis in Argus Enterprise and MRI Investment Management, where institutional investors and REITs classify tenant and occupier exposure using GICS for equity market benchmarking and ESG reporting. Null when classification_system is already GICS.. Valid values are `^[0-9]{8}$`',
    `hazmat_risk_flag` BOOLEAN COMMENT 'Indicates whether tenants in this industry classification typically handle, store, or generate hazardous materials, requiring environmental due diligence, Phase I/II environmental site assessments, and specialized lease provisions. Relevant for industrial and laboratory occupiers. Supports EPA environmental compliance, OSHA building safety requirements, and property acquisition due diligence.',
    `hierarchy_level` STRING COMMENT 'The hierarchical level of this code within its classification system. For NAICS: sector (2-digit), subsector (3-digit), industry group (4-digit), industry (5-digit), national industry (6-digit). For SIC: division, major group (2-digit), group (3-digit), industry (4-digit). For GICS: sector, industry group, industry, sub-industry. Enables roll-up and drill-down analysis for portfolio diversification reporting. [ENUM-REF-CANDIDATE: sector|subsector|industry_group|industry|national_industry|division|major_group|group|class|subclass — promote to reference product]',
    `industry_classification_code` STRING COMMENT 'The official alphanumeric code assigned by the governing classification authority (e.g., NAICS code 531120 for Lessors of Nonresidential Buildings, SIC code 6512, or GICS code 60101010 for Diversified REITs). This is the externally recognized business identifier used in regulatory filings, lease underwriting, and portfolio reporting.. Valid values are `^[A-Z0-9]{2,10}$`',
    `industry_classification_description` STRING COMMENT 'Full narrative description of the industry classification code as defined by the governing authority. Explains the scope of economic activities covered, typical establishments included, and any cross-references or exclusions. Supports lease underwriting decisions and tenant mix analysis by providing context beyond the short title.',
    `industry_classification_status` STRING COMMENT 'Current lifecycle status of this industry classification code record. Active codes are available for assignment to tenants and occupiers. Deprecated codes have been retired by the governing authority but retained for historical record integrity. Superseded codes have been replaced by a new code in a revised edition of the classification system.. Valid values are `active|inactive|deprecated|superseded`',
    `is_anchor_eligible` BOOLEAN COMMENT 'Indicates whether tenants in this industry classification are typically eligible to serve as anchor tenants in retail or mixed-use properties. Anchor tenants drive foot traffic and influence co-tenancy clauses in lease agreements. Used in retail leasing strategy, tenant mix planning, and co-tenancy clause risk assessment in Salesforce CRM deal pipeline management.',
    `is_essential_business` BOOLEAN COMMENT 'Indicates whether tenants in this industry classification are typically designated as essential businesses under applicable government emergency orders (e.g., grocery, pharmacy, healthcare, utilities). Relevant for lease force majeure clause analysis, rent abatement risk assessment during declared emergencies, and regulatory compliance reporting to HUD and SEC for publicly traded REITs.',
    `is_real_estate_specific` BOOLEAN COMMENT 'Indicates whether this industry classification code is specifically relevant to real estate operations, investment, or property-related activities (e.g., NAICS 531 Real Estate, GICS sector 60 Real Estate). Used to filter the classification code list for real estate portfolio analytics, REIT regulatory reporting, and property management system integrations.',
    `mri_industry_code` STRING COMMENT 'The corresponding industry code as configured in MRI Softwares lease management and residential management modules. MRI Software uses its own tenant industry classification codes for lease underwriting and portfolio reporting. Enables synchronization between the enterprise reference repository and MRI Software tenant and lease records.',
    `naics_equivalent_code` STRING COMMENT 'The corresponding NAICS 6-digit code for records originating from SIC or GICS systems, enabling cross-system concordance. Populated when classification_system is SIC or GICS to allow unified NAICS-based reporting as required by U.S. federal regulatory filings and CoStar market analytics. Null when classification_system is already NAICS.. Valid values are `^[0-9]{6}$`',
    `notes` STRING COMMENT 'Free-text field for additional context, cross-references, internal usage guidance, or exceptions related to this industry classification code. May include notes on code transitions between NAICS revision cycles, known mapping ambiguities between classification systems, or specific real estate portfolio application guidance for asset managers and leasing teams.',
    `real_estate_use_category` STRING COMMENT 'The primary real estate property use category most commonly associated with tenants or occupiers in this industry classification. Drives retail tenant mix analysis (anchor vs. inline), office sector concentration tracking, and industrial occupier type classification. Used in Yardi Voyager and MRI lease management for automated tenant categorization and CoStar market analytics segmentation. [ENUM-REF-CANDIDATE: retail|office|industrial|multifamily|hospitality|mixed_use|specialty|other — 8 candidates stripped; promote to reference product]',
    `regulatory_reporting_code` STRING COMMENT 'The specific code or identifier used when reporting tenant industry classification to regulatory bodies (e.g., SEC REIT tenant concentration disclosures, HUD reporting, CMBS loan-level data reporting). May differ from the standard NAICS/SIC/GICS code when regulators require a mapped or aggregated code. Supports SOX financial controls compliance for publicly traded REITs.',
    `retail_tenant_type` STRING COMMENT 'For retail-use classifications, designates the tenant positioning category within a retail center (e.g., anchor, major, inline, kiosk, pad/outparcel, food and beverage, entertainment, service). Critical for retail tenant mix analysis, GLA allocation planning, and CAM cost recovery structuring. Null or not_applicable for non-retail classifications. [ENUM-REF-CANDIDATE: anchor|major|inline|kiosk|pad|outparcel|food_and_beverage|entertainment|service|not_applicable — promote to reference product]',
    `sector_code` STRING COMMENT 'The top-level sector code within the classification system (e.g., NAICS sector 53, SIC division H, GICS sector code 60). Provides a concise key for sector-level grouping in portfolio analytics, lease underwriting scorecards, and regulatory concentration reporting.. Valid values are `^[A-Z0-9]{1,6}$`',
    `sector_name` STRING COMMENT 'The top-level sector name under which this classification code falls (e.g., Real Estate and Rental and Leasing for NAICS sector 53, Finance, Insurance, and Real Estate for SIC division H, Real Estate for GICS sector 60). Used for high-level portfolio diversification analysis and tenant sector concentration reporting in CRE portfolios.',
    `sic_equivalent_code` STRING COMMENT 'The corresponding SIC 4-digit code for records originating from NAICS or GICS systems. Maintained for backward compatibility with legacy Yardi Voyager tenant records, MRI Software lease management configurations, and older regulatory filings that reference SIC codes. Null when classification_system is already SIC.. Valid values are `^[0-9]{4}$`',
    `superseded_by_code` STRING COMMENT 'When status is superseded, the code that replaces this classification code in the current or subsequent version of the classification system. Enables automated migration of tenant classifications during NAICS revision cycles and maintains audit trail for historical lease records in Yardi Voyager and MRI Software.. Valid values are `^[A-Z0-9]{2,10}$`',
    `title` STRING COMMENT 'The official short title or label of the industry classification code as published by the governing authority (e.g., Lessors of Nonresidential Buildings (except Miniwarehouses), Real Estate Dealers (for their own account), Diversified REITs). Used as the primary display label in reports, dashboards, and tenant categorization screens.',
    `typical_lease_type` STRING COMMENT 'The lease structure most commonly associated with tenants in this industry classification (e.g., NNN for retail/industrial, gross for office, percentage rent for food and beverage). Informs lease underwriting assumptions in Argus Enterprise, CAM recovery modeling, and NOI forecasting. NNN = Triple Net Lease. [ENUM-REF-CANDIDATE: NNN|gross|modified_gross|percentage|ground|net|double_net — 7 candidates stripped; promote to reference product]',
    `typical_space_size_max_sqf` STRING COMMENT 'The maximum typical occupied space size in square feet (SQF) for tenants in this industry classification. Used alongside the minimum to define the expected space demand range for lease underwriting, tenant mix planning, and market absorption analysis. SQF = Square Feet.',
    `typical_space_size_min_sqf` STRING COMMENT 'The minimum typical occupied space size in square feet (SQF) for tenants in this industry classification. Used as a benchmark in lease underwriting, space planning, and GLA allocation analysis. Supports PSF rent benchmarking and NLA/GLA ratio analysis in Argus Enterprise cash flow models. SQF = Square Feet.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this industry classification code record was last modified in the enterprise reference repository. Tracks updates such as status changes, description corrections, system code mapping updates, or ESG risk category revisions. Supports data governance audit trails and downstream system synchronization.',
    `yardi_industry_code` STRING COMMENT 'The corresponding industry code as configured in Yardi Voyagers tenant profile module. Yardi Voyager maintains its own internal industry code list for tenant categorization in lease administration and accounts receivable. This field enables bidirectional synchronization between the enterprise reference repository and Yardi Voyager tenant records.',
    CONSTRAINT pk_industry_classification PRIMARY KEY(`industry_classification_id`)
) COMMENT 'Standard industry classification codes for tenant and occupier categorization — NAICS (North American Industry Classification System), SIC (Standard Industrial Classification), and GICS (Global Industry Classification Standard). Used to classify tenant business types for portfolio diversification analysis, lease underwriting, and regulatory reporting. Supports retail tenant mix analysis (anchor vs. inline), office tenant sector concentration, and industrial occupier type tracking.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`amenity_type` (
    `amenity_type_id` BIGINT COMMENT 'Unique surrogate identifier for each amenity type record in the controlled vocabulary. Primary key for the amenity_type reference product. [REFERENCE_LOOKUP role — canonical_skip_reason: This is a controlled vocabulary / code-list entity; per-role minimum categories for MASTER_RESOURCE/PARTY/TRANSACTION do not apply.]',
    `uom_id` BIGINT COMMENT 'Foreign key linking to reference.uom. Business justification: Amenity types have a typical physical size measured in a specific unit of measure (e.g., square feet for a fitness center, number of spaces for a parking garage). Linking to the enterprise UOM registr',
    `amenity_category` STRING COMMENT 'Functional category grouping amenities by their primary purpose for analytics and comparable analysis (e.g., Wellness & Fitness, Parking & Transportation, Technology & Smart Building, Food & Beverage, Conference & Collaboration, Green Space & Recreation, Concierge & Services, Security & Access). [ENUM-REF-CANDIDATE: Wellness & Fitness|Parking & Transportation|Technology & Smart Building|Food & Beverage|Conference & Collaboration|Green Space & Recreation|Concierge & Services|Security & Access — promote to reference product]',
    `amenity_class` STRING COMMENT 'High-level classification grouping amenities by their physical scope and applicability: building (shared building-wide features such as lobbies and fitness centers), unit (in-unit features such as in-unit laundry or private terrace), community (campus or complex-wide features such as shared green spaces), outdoor (exterior amenities such as parking structures or dog parks).. Valid values are `building|unit|community|outdoor`',
    `amenity_code` STRING COMMENT 'Short, system-readable alphanumeric code uniquely identifying the amenity type across all operational systems (e.g., FIT_CTR, ROOFTOP_TER, EV_CHRG, CONF_FAC). Used as the stable integration key between Yardi Voyager, CoStar Suite, MRI Software, and the data lakehouse.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `amenity_name` STRING COMMENT 'Human-readable display name for the amenity type as it appears in property listings, marketing materials, tenant portals, and brokerage reports (e.g., Fitness Center, Rooftop Terrace, EV Charging Station, Conference Facility).',
    `amenity_type_description` STRING COMMENT 'Full narrative description of the amenity type, including its physical characteristics, typical configuration, and business purpose. Used in property marketing copy, tenant attraction materials, and brokerage listing enrichment within Salesforce CRM and CoStar Suite.',
    `amenity_type_status` STRING COMMENT 'Lifecycle status of the amenity type record within the controlled vocabulary. active — currently in use across operational systems; inactive — no longer assigned to new properties but retained for historical records; deprecated — superseded by a replacement code; pending_review — submitted for governance approval but not yet ratified.. Valid values are `active|inactive|deprecated|pending_review`',
    `applicable_property_types` STRING COMMENT 'Comma-delimited list of property type codes for which this amenity type is relevant (e.g., OFFICE,RETAIL,MULTIFAMILY). Drives filtering logic in property listing platforms, CoStar Suite comparable searches, and Yardi Voyager property setup workflows. Stored as a delimited string per the no-ARRAY-type constraint.',
    `approval_date` DATE COMMENT 'The date on which this amenity type definition was formally approved by the data governance committee for use in enterprise systems. Supports governance audit trails and reference data lifecycle management.',
    `approved_by` STRING COMMENT 'Name or identifier of the data governance authority or individual who approved this amenity type for inclusion in the controlled vocabulary. Supports reference data governance audit trails and SOX compliance documentation.',
    `costar_amenity_code` STRING COMMENT 'The amenity identifier code as used in CoStar Suite for property analytics, comparable sales and lease data, and market research. Enables direct mapping between the enterprise reference vocabulary and CoStar data feeds for comparable analysis (CMA) and Broker Price Opinion (BPO) workflows.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this amenity type record was first created in the enterprise reference data repository. Supports audit trail requirements under SOX financial controls and GDPR data lineage obligations.',
    `display_sort_order` STRING COMMENT 'Integer value controlling the display sequence of amenity types in property listing portals, tenant-facing marketing materials, and brokerage platforms. Lower values appear first. Managed by the reference data governance team.',
    `effective_date` DATE COMMENT 'The date from which this amenity type code became active and available for use in operational systems and property records. Supports temporal validity tracking for the controlled vocabulary and audit compliance.',
    `expiry_date` DATE COMMENT 'The date on which this amenity type code is no longer valid for assignment to new property records. Null indicates the code remains indefinitely active. Used in reference data lifecycle management and downstream system synchronization.',
    `icon_identifier` STRING COMMENT 'Reference key or filename for the standardized icon representing this amenity type in tenant portals, property marketing websites, and mobile applications. Enables consistent visual branding across Salesforce CRM tenant portals and Building Engines service request interfaces.',
    `indoor_outdoor_indicator` STRING COMMENT 'Specifies whether this amenity type is physically located indoors, outdoors, or spans both environments. Used in property marketing, facility operations planning in Building Engines, and LEED site assessment scoring.. Valid values are `indoor|outdoor|both`',
    `is_ada_compliant` BOOLEAN COMMENT 'Indicates whether this amenity type, by definition, must meet Americans with Disabilities Act (ADA) accessibility standards. Used in compliance reporting, building inspection checklists in Building Engines, and regulatory filings with HUD.',
    `is_billable` BOOLEAN COMMENT 'Indicates whether this amenity type is typically subject to a separate charge to tenants (e.g., reserved parking, private storage units, premium concierge services) as opposed to being included in base rent. Drives billing configuration in Yardi Voyager AR and lease charge setup in MRI Software.',
    `is_breeam_qualifying` BOOLEAN COMMENT 'Indicates whether the presence of this amenity type can contribute credits toward a BREEAM (Building Research Establishment Environmental Assessment Method) certification assessment. Relevant for international portfolio assets and cross-border investment reporting.',
    `is_cam_recoverable` BOOLEAN COMMENT 'Indicates whether the operating and maintenance costs associated with this amenity type are recoverable from tenants as part of Common Area Maintenance (CAM) charges under NNN or modified gross lease structures. Used in CAM reconciliation workflows in Yardi Voyager and MRI Software.',
    `is_esg_relevant` BOOLEAN COMMENT 'Indicates whether this amenity type contributes to Environmental, Social, and Governance (ESG) reporting metrics (e.g., EV charging stations, green roofs, bike storage, energy-efficient HVAC systems). Used in ESG portfolio reporting and investor disclosure packages for publicly traded REITs under SEC requirements.',
    `is_leed_qualifying` BOOLEAN COMMENT 'Indicates whether the presence of this amenity type can contribute points toward a LEED (Leadership in Energy and Environmental Design) certification score. Used in development project planning within Procore and asset valuation models in Argus Enterprise.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this amenity type record was most recently modified in the enterprise reference data repository. Used for change data capture (CDC) in the Databricks lakehouse silver layer pipeline and reference data synchronization across operational systems.',
    `maintenance_intensity` STRING COMMENT 'Categorical indicator of the relative operational and maintenance burden associated with this amenity type: low (e.g., bike racks, signage), medium (e.g., fitness equipment, conference rooms), high (e.g., pools, rooftop terraces, EV charging infrastructure). Used in OPEX budgeting, preventive maintenance scheduling in Building Engines, and CAPEX planning.. Valid values are `low|medium|high`',
    `market_segment_applicability` STRING COMMENT 'Comma-delimited list of market segments for which this amenity type is commonly relevant (e.g., CLASS_A,CLASS_B, LUXURY_RESIDENTIAL, INDUSTRIAL). Supports comparable market analysis (CMA) filtering in CoStar Suite and brokerage listing enrichment in Salesforce CRM. [ENUM-REF-CANDIDATE: CLASS_A|CLASS_B|CLASS_C|LUXURY_RESIDENTIAL|AFFORDABLE_HOUSING|INDUSTRIAL|MIXED_USE — promote to reference product]',
    `mri_amenity_code` STRING COMMENT 'The amenity identifier as configured in MRI Software residential and commercial property management modules. Supports data lineage and reconciliation between MRI Software and the enterprise reference data layer.',
    `notes` STRING COMMENT 'Free-text field for additional context, governance decisions, or implementation guidance related to this amenity type. Used by the reference data stewardship team to document edge cases, mapping decisions, and cross-system alignment notes.',
    `regulatory_notes` STRING COMMENT 'Free-text field capturing relevant regulatory, zoning, or compliance considerations associated with this amenity type (e.g., ADA accessibility requirements, EPA environmental standards for EV charging, OSHA safety requirements for fitness equipment). Supports compliance reporting and development due diligence.',
    `requires_permit` BOOLEAN COMMENT 'Indicates whether installation or operation of this amenity type typically requires a municipal building permit, zoning variance, or regulatory approval (e.g., rooftop structures, pools, EV charging infrastructure, food service facilities). Used in development project planning in Procore and regulatory compliance tracking.',
    `reso_amenity_code` STRING COMMENT 'The standardized amenity code as defined by the Real Estate Standards Organization (RESO) Data Dictionary, used for MLS syndication and cross-platform data exchange. Enables interoperability with MLS systems and CoStar Suite data feeds.',
    `smart_building_feature` BOOLEAN COMMENT 'Indicates whether this amenity type is classified as a smart building or PropTech-enabled feature (e.g., automated access control, IoT-connected HVAC, smart parking systems, digital concierge kiosks). Relevant for Building Information Modeling (BIM) integration and ESG technology reporting.',
    `source_system` STRING COMMENT 'Identifies the originating system or authority from which this amenity type definition was sourced: RESO (Real Estate Standards Organization), COSTAR (CoStar Suite), YARDI (Yardi Voyager), MRI (MRI Software), NAR_MLS (National Association of Realtors MLS), MANUAL (manually defined by the data governance team).. Valid values are `RESO|COSTAR|YARDI|MRI|MANUAL|NAR_MLS`',
    `tenant_attraction_score` STRING COMMENT 'Standardized integer score (1–10) representing the relative importance of this amenity type in attracting and retaining tenants, based on market research benchmarks from CoStar Suite and ULI tenant surveys. Used in brokerage deal pipeline analysis in Salesforce CRM and lease renewal probability modeling.',
    `typical_capex_tier` STRING COMMENT 'Indicative tier representing the typical capital expenditure (CAPEX) required to install or construct this amenity type: low (under $50K), medium ($50K–$500K), high ($500K–$2M), very_high (over $2M). Used in development feasibility analysis in Procore and investment underwriting in Argus Enterprise.. Valid values are `low|medium|high|very_high`',
    `valuation_impact_flag` STRING COMMENT 'Indicates the general directional impact this amenity type has on property valuation and CAP rate analysis: positive — typically increases asset value and NOI; neutral — no material valuation impact; negative — may reduce value (e.g., high-maintenance amenities with low tenant uptake); variable — impact depends on market segment. Used in Argus Enterprise DCF models and Appraisal Institute valuation reports.. Valid values are `positive|neutral|negative|variable`',
    `version_number` STRING COMMENT 'Monotonically increasing integer tracking the version of this amenity type definition within the controlled vocabulary. Incremented each time the record is updated through the reference data governance process. Supports audit trails and change management.',
    `yardi_amenity_code` STRING COMMENT 'The amenity code as configured in Yardi Voyager property management and lease administration modules. Used for system-of-record alignment when synchronizing amenity data between the lakehouse silver layer and Yardi Voyager operational data.',
    CONSTRAINT pk_amenity_type PRIMARY KEY(`amenity_type_id`)
) COMMENT 'Controlled vocabulary for property and building amenities used in property marketing, tenant attraction, and asset valuation — fitness centers, rooftop terraces, parking structures, EV charging stations, conference facilities, concierge services, green spaces, and smart building features. Categorized by amenity class (building, unit-level, community), applicable property types, and ESG/LEED relevance flags. Used by property, lease, and brokerage domains for listing enrichment and comparable analysis.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`building_class` (
    `building_class_id` BIGINT COMMENT 'Unique surrogate identifier for each building class record in the enterprise reference repository. Primary key. [REFERENCE_LOOKUP role — canonical_skip_reason: This is a controlled vocabulary / code-list entity providing standardized building quality classifications; per-role minimum categories do not apply.]',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: Building class benchmarks (typical_psf_rent_min, typical_psf_rent_max) are denominated in a specific currency. Linking to the ISO 4217 currency registry ensures referential integrity for financial ben',
    `sustainability_rating_id` BIGINT COMMENT 'Foreign key linking to reference.sustainability_rating. Business justification: Building class definitions specify minimum sustainability certification requirements (e.g., Class A buildings may require LEED Gold or higher). Linking to the sustainability_rating registry normalizes',
    `amenity_requirement_level` STRING COMMENT 'Minimum level of building amenities required for this class designation. Full-service includes concierge, fitness center, conference facilities, and food service; minimal reflects basic building services only. Supports property management benchmarking in Building Engines and Yardi Voyager.. Valid values are `full_service|enhanced|standard|minimal`',
    `asset_segment` STRING COMMENT 'Broad real estate asset segment to which this building class applies. Distinguishes commercial (office, retail), residential (multifamily, single-family), industrial (warehouse, flex), and mixed-use classifications, as building class criteria differ materially by segment.. Valid values are `commercial|residential|industrial|mixed_use`',
    `boma_class_designation` STRING COMMENT 'Official Building Owners and Managers Association (BOMA) building class designation (A, B, C, or D) mapped to this enterprise class. Ensures alignment with the industry-standard BOMA classification framework used in lease administration, property management, and benchmarking.. Valid values are `A|B|C|D`',
    `building_class_status` STRING COMMENT 'Current lifecycle status of this building class record in the enterprise reference data repository. Active records are available for property classification; deprecated records are retained for historical reference only. Managed through the reference data governance process.. Valid values are `active|inactive|deprecated|draft`',
    `class_code` STRING COMMENT 'Short alphanumeric code uniquely identifying the building class (e.g., A, B, C, TROPHY, LUX, MID, AFF, INST). Used as the externally-known business identifier across operational systems including Yardi Voyager, MRI Software, CoStar, and Argus Enterprise for property classification lookups.. Valid values are `^[A-Z]{1,5}$`',
    `class_description` STRING COMMENT 'Detailed narrative description of the building class, including qualitative criteria such as construction quality, finish standards, location requirements, amenity expectations, and typical tenant profile. Supports underwriting, valuation, and investment advisory workflows.',
    `class_name` STRING COMMENT 'Full descriptive name of the building class (e.g., Class A, Class B, Class C, Trophy, Luxury, Mid-Market, Affordable, Institutional Grade). Human-readable label used in reports, dashboards, and tenant-facing materials.',
    `classification_tier` STRING COMMENT 'Numeric ordinal rank of the building class within its asset segment hierarchy (e.g., 1 = highest/Trophy/Class A, 2 = Class B/Mid-Market, 3 = Class C/Affordable). Enables ranked sorting and comparative analytics across the classification spectrum in Argus Enterprise and portfolio reporting.',
    `construction_quality_grade` STRING COMMENT 'Qualitative grade of construction quality required for this building class, reflecting structural integrity, materials specification, and build standards. Premium denotes trophy/Class A+ finishes; economy denotes Class C or below. Informs property valuation and appraisal workflows in Argus Enterprise.. Valid values are `premium|high|standard|economy`',
    `costar_class_code` STRING COMMENT 'CoStar Suite building class code used for market research, comparable sales, and lease data alignment. Enables direct cross-referencing between the enterprise classification system and CoStars industry-standard building quality ratings for benchmarking and market analytics.. Valid values are `^[A-Z]{1,3}$`',
    `effective_date` DATE COMMENT 'Date from which this building class definition becomes effective and applicable for property classification across enterprise systems. Supports temporal versioning of classification standards as market definitions evolve.',
    `energy_star_min_score` STRING COMMENT 'Minimum EPA ENERGY STAR score (1–100 scale) required for buildings to qualify for this class designation. A score of 75 or above qualifies for ENERGY STAR certification. Null if no ENERGY STAR threshold is mandated. Supports ESG and environmental compliance reporting.',
    `expiry_date` DATE COMMENT 'Date on which this building class definition expires and is superseded by a revised version. Null indicates the definition is currently active with no planned expiry. Enables historical classification lookups and audit trails for regulatory compliance.',
    `external_reference_code` STRING COMMENT 'External identifier or code for this building class as defined by the source standards body or system (e.g., CoStar property class code, BOMA designation code). Enables cross-system reconciliation and market data integration for benchmarking and analytics.',
    `finish_quality_grade` STRING COMMENT 'Grade of interior finish quality expected for buildings in this class, covering flooring, ceiling heights, lobby finishes, restroom quality, and common area standards. Directly influences Tenant Improvement (TI) allowance benchmarks and lease negotiation parameters.. Valid values are `luxury|high_end|mid_grade|basic`',
    `hvac_system_requirement` STRING COMMENT 'Minimum Heating, Ventilation, and Air Conditioning (HVAC) system type required for buildings in this class. Central VAV (Variable Air Volume) systems are typically required for Class A office; split systems may be acceptable for Class C. Informs property management and capital expenditure (CAPEX) planning.. Valid values are `central_vav|central_fan_coil|split_system|none`',
    `investment_grade_flag` BOOLEAN COMMENT 'Indicates whether properties in this building class are considered institutional or investment-grade assets suitable for REIT portfolios, pension fund investment, and institutional capital allocation. True for Trophy and Class A designations; typically False for Class C and below.',
    `leed_certification_level` STRING COMMENT 'Minimum Leadership in Energy and Environmental Design (LEED) certification level associated with or required for this building class (Certified, Silver, Gold, Platinum). Null if LEED certification is not a classification criterion. Supports ESG compliance and green building reporting.. Valid values are `certified|silver|gold|platinum`',
    `location_grade` STRING COMMENT 'Required location quality grade for buildings in this class, reflecting proximity to Central Business District (CBD), transportation infrastructure, and market desirability. Prime CBD locations are typically required for Trophy and Class A designations. Used in market segmentation and portfolio analytics.. Valid values are `prime_cbd|secondary_cbd|suburban|tertiary`',
    `max_building_age_years` STRING COMMENT 'Maximum age of a building in years (measured from year of construction or last major renovation) that qualifies for this class. Null indicates no upper age limit. Used alongside min_building_age_years to define the age band for classification eligibility.',
    `max_cap_rate_pct` DECIMAL(18,2) COMMENT 'Maximum typical Capitalization Rate (CAP Rate) expressed as a decimal percentage (e.g., 0.0800 = 8.00%) associated with properties in this building class. Used alongside min_cap_rate_pct to define the CAP rate band for investment analysis and portfolio benchmarking.',
    `min_building_age_years` STRING COMMENT 'Minimum age of a building in years (measured from year of construction or last major renovation) that qualifies for this class. Used as a threshold criterion in automated property classification workflows within Yardi Voyager and MRI Software.',
    `min_cap_rate_pct` DECIMAL(18,2) COMMENT 'Minimum typical Capitalization Rate (CAP Rate) expressed as a decimal percentage (e.g., 0.0400 = 4.00%) associated with properties in this building class. Provides investment benchmarking guidance for asset managers and investment advisors using Argus Enterprise and MRI Software.',
    `min_floor_count` STRING COMMENT 'Minimum number of above-grade floors a building must have to qualify for this class designation. Applicable primarily to office and mixed-use classifications where building height is a quality indicator (e.g., Trophy office typically requires high-rise status).',
    `min_gla_sqf` DECIMAL(18,2) COMMENT 'Minimum Gross Leasable Area (GLA) in Square Feet (SQF) required for a property to qualify for this building class. Null if no minimum size threshold applies. Used in automated property classification and portfolio segmentation analytics.',
    `notes` STRING COMMENT 'Free-text field for additional commentary, classification nuances, regional variations, or governance notes related to this building class definition. Intended for reference data stewards and data governance teams managing the enterprise classification taxonomy.',
    `parking_ratio_min` DECIMAL(18,2) COMMENT 'Minimum parking ratio (spaces per 1,000 square feet of GLA) required for buildings in this class. A key amenity criterion for commercial building classification, particularly for suburban office and retail properties. Expressed as spaces per 1,000 SQF.',
    `property_type_scope` STRING COMMENT 'Specific property type(s) within the asset segment to which this class definition applies (e.g., Office, Retail, Multifamily, Industrial, Hotel, Self-Storage, Senior Housing). Aligns with CoStar and RESO property type taxonomies. [ENUM-REF-CANDIDATE: office|retail|multifamily|industrial|hotel|self_storage|senior_housing|mixed_use|land|other — promote to reference product]',
    `reit_eligible_flag` BOOLEAN COMMENT 'Indicates whether properties classified under this building class are typically eligible for inclusion in a Real Estate Investment Trust (REIT) portfolio based on quality, income-producing characteristics, and institutional standards. Supports investment advisory and portfolio management workflows.',
    `sort_order` STRING COMMENT 'Display sort order for this building class in user interfaces, dropdown lists, and reports. Enables consistent presentation of building class options across Yardi Voyager, MRI Software, and enterprise reporting platforms independent of the classification tier.',
    `source_system_code` STRING COMMENT 'Code identifying the authoritative source system or standards body from which this building class definition originates (e.g., COSTAR for CoStar Suite definitions, BOMA for BOMA International standards, INTERNAL for enterprise-defined classes). Supports data lineage and reference data governance.. Valid values are `COSTAR|BOMA|NAIOP|INTERNAL|YARDI|MRI`',
    `sustainability_certification_required` BOOLEAN COMMENT 'Indicates whether a recognized sustainability certification (e.g., LEED, BREEAM, ENERGY STAR) is required or expected for buildings to qualify for this class designation. Reflects ESG compliance requirements increasingly embedded in institutional-grade CRE classification.',
    `technology_infrastructure_grade` STRING COMMENT 'Required level of technology infrastructure for buildings in this class, including fiber connectivity, building automation systems (BAS), smart building capabilities, and telecommunications readiness. Increasingly critical for Class A and Trophy designations in CRE markets.. Valid values are `smart_building|wired_certified|standard|basic`',
    `typical_lease_structure` STRING COMMENT 'Typical lease structure associated with this building class (e.g., Full Service Gross, Modified Gross, NNN — Triple Net Lease). Provides context for lease administration in Yardi Voyager and MRI Software, and informs CAM (Common Area Maintenance) charge modeling.',
    `typical_psf_rent_max` DECIMAL(18,2) COMMENT 'Maximum typical asking rent expressed in Per Square Foot (PSF) per annum for properties in this building class, in the base currency. Used alongside typical_psf_rent_min to define the rent band for this class in market analytics and investment underwriting.',
    `typical_psf_rent_min` DECIMAL(18,2) COMMENT 'Minimum typical asking rent expressed in Per Square Foot (PSF) per annum for properties in this building class, in the base currency. Provides market benchmarking context for lease negotiations, rent schedule modeling, and comparative market analysis (CMA) in CoStar and Argus Enterprise.',
    `typical_tenant_profile` STRING COMMENT 'Narrative description of the typical tenant profile associated with this building class (e.g., Fortune 500 corporations, financial institutions, law firms for Class A; small-to-medium businesses, local retailers for Class B/C). Supports tenant relationship management and leasing strategy in Salesforce CRM.',
    `typical_vacancy_rate_pct` DECIMAL(18,2) COMMENT 'Typical market vacancy rate expressed as a decimal percentage (e.g., 0.0500 = 5.00%) for properties in this building class. Used as a benchmark input in Effective Gross Income (EGI) and Net Operating Income (NOI) modeling within Argus Enterprise cash flow projections.',
    CONSTRAINT pk_building_class PRIMARY KEY(`building_class_id`)
) COMMENT 'Standardized building quality classification system for commercial and residential assets — Class A, B, C for office and industrial; luxury, mid-market, affordable for residential; trophy, institutional-grade for investment-grade CRE. Defines classification criteria including age thresholds, construction quality standards, location grade, amenity requirements, and typical CAP rate ranges per class. Aligned with BOMA, NAIOP, and CoStar building class definitions.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`construction_type` (
    `construction_type_id` BIGINT COMMENT 'Unique surrogate identifier for each construction type record in the enterprise reference repository. Role: REFERENCE_LOOKUP — exempt from per-role minimum-category requirements. _canonical_skip_reason: This entity is a controlled vocabulary / code-list table providing standardized construction method classifications; it carries no independent transaction, party, or agreement lifecycle.',
    `acoustic_performance_rating` STRING COMMENT 'Qualitative acoustic performance rating (low, moderate, high, very_high) for this construction type based on typical sound transmission characteristics. Relevant for multifamily, hospitality, and office property types; informs tenant improvement specifications and lease negotiations.. Valid values are `low|moderate|high|very_high`',
    `applicable_property_types` STRING COMMENT 'Comma-delimited list of property type codes for which this construction type is commonly used or permitted (e.g., OFFICE,RETAIL,INDUSTRIAL,MULTIFAMILY,HOTEL). Enables cross-domain filtering in CoStar Suite market research, Argus Enterprise portfolio analysis, and development feasibility screening.',
    `bim_support` BOOLEAN COMMENT 'Indicates whether this construction type is fully supported by BIM workflows in Procore and related development management systems (True = BIM-supported; False = not BIM-supported). Supports digital construction management and as-built documentation practices.',
    `breeam_compatibility` STRING COMMENT 'Indicates whether this construction type is compatible with BREEAM certification pathways (not_applicable, compatible, preferred). Supports international ESG investment screening and sustainable development planning for cross-border real estate portfolios.. Valid values are `not_applicable|compatible|preferred`',
    `construction_category` STRING COMMENT 'Broad grouping of construction types for portfolio-level analytics and reporting (light_frame, heavy_frame, concrete, masonry, modular, mixed, specialty). Used in CoStar Suite market segmentation, Argus Enterprise portfolio dashboards, and investment committee reporting. [ENUM-REF-CANDIDATE: light_frame|heavy_frame|concrete|masonry|modular|mixed|specialty — 7 candidates stripped; promote to reference product]',
    `construction_method` STRING COMMENT 'Method by which the building is assembled (site_built, prefabricated, modular, panelized, hybrid). Impacts construction schedule, CAPEX phasing, and Procore project management workflows for development projects.. Valid values are `site_built|prefabricated|modular|panelized|hybrid`',
    `construction_type_code` STRING COMMENT 'Short, system-readable alphanumeric code uniquely identifying the construction type (e.g., WOOD_FRAME, STL_FRAME, CIP_CONC, PRECAST, TILT_UP, MASONRY, MODULAR, MIXED). Used as the stable business key for cross-system integration with Yardi Voyager, Procore, and CoStar Suite.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `construction_type_description` STRING COMMENT 'Detailed narrative describing the structural system, primary materials, assembly method, and distinguishing characteristics of this construction type. Used by appraisers, underwriters, and development teams for technical documentation and cost estimation.',
    `construction_type_name` STRING COMMENT 'Full human-readable name of the construction type as used in property records, valuation reports, and development documentation (e.g., Wood Frame, Structural Steel Frame, Cast-In-Place Concrete, Precast Concrete, Tilt-Up Concrete, Masonry, Modular, Mixed Construction).',
    `construction_type_status` STRING COMMENT 'Current lifecycle status of this construction type reference record (active = in use across enterprise systems; inactive = no longer assigned to new properties; deprecated = superseded by a newer classification). Controls availability in downstream system dropdowns and data entry forms.. Valid values are `active|inactive|deprecated`',
    `cost_benchmark_year` STRING COMMENT 'Calendar year for which the PSF cost benchmarks (typical_cost_psf_low and typical_cost_psf_high) are valid. Enables cost escalation adjustments in Argus Enterprise DCF models and development CAPEX forecasts.',
    `costar_construction_type_code` STRING COMMENT 'Construction type code as used in CoStar Suite property database. Enables market comparables analysis and benchmarking by construction type in CoStar Analytics and supports comparable sales/lease data integration.',
    `depreciation_method` STRING COMMENT 'Standard depreciation method applied to fixed assets of this construction type for financial reporting purposes. Aligns with FASB ASC 360 and IFRS IAS 16 requirements and drives depreciation calculations in Yardi Voyager Fixed Assets and SAP S/4HANA.. Valid values are `straight_line|declining_balance|sum_of_years|units_of_production`',
    `effective_date` DATE COMMENT 'Date from which this construction type classification is valid and available for use in enterprise systems. Supports temporal data governance and ensures that historical property records reference the correct classification version.',
    `energy_efficiency_profile` STRING COMMENT 'Qualitative energy efficiency profile (low, moderate, high, very_high) for this construction type based on typical thermal performance, insulation characteristics, and building envelope properties. Supports ESG reporting, LEED/BREEAM certification tracking, and green building investment analysis.. Valid values are `low|moderate|high|very_high`',
    `expiry_date` DATE COMMENT 'Date after which this construction type classification is no longer valid for new assignments. Null indicates no planned expiry. Supports reference data lifecycle management and downstream system validation rules.',
    `exterior_wall_system` STRING COMMENT 'Description of the typical exterior wall assembly for this construction type (e.g., Curtain Wall, Brick Veneer, Tilt-Up Concrete Panel, Metal Panel, EIFS). Informs building condition assessments, maintenance cost benchmarking, and insurance replacement cost estimates.',
    `fire_resistance_rating_hours` DECIMAL(18,2) COMMENT 'Minimum fire resistance rating in hours for the primary structural assembly as required by the IBC for this construction type (e.g., 0, 1.0, 2.0, 3.0). Used by insurance underwriters to determine property insurance premiums and by development teams for code compliance verification.',
    `floor_load_capacity_psf` DECIMAL(18,2) COMMENT 'Typical live load capacity of floor systems in pounds per square foot (PSF) for this construction type. Critical for industrial, warehouse, and data center property underwriting, tenant improvement design, and building condition assessments.',
    `foundation_type` STRING COMMENT 'Typical foundation system associated with this construction type (slab_on_grade, crawl_space, basement, pile, mat, caisson, other). Used in property condition assessments, maintenance planning in Building Engines, and environmental due diligence during acquisitions. [ENUM-REF-CANDIDATE: slab_on_grade|crawl_space|basement|pile|mat|caisson|other — 7 candidates stripped; promote to reference product]',
    `hvac_compatibility` STRING COMMENT 'Typical HVAC system types compatible with this construction type. Informs tenant improvement (TI) planning, building operations management in Building Engines, and energy efficiency assessments for ESG reporting. [ENUM-REF-CANDIDATE: central_air|split_system|vrf|chilled_water|ptac|mixed|other — 7 candidates stripped; promote to reference product]',
    `ibc_construction_type` STRING COMMENT 'Official IBC construction type designation (Type I-A through Type V-B) reflecting fire-resistance requirements for structural elements. Critical for building permit compliance, insurance underwriting, and occupancy classification. Aligns with Procore project documentation and CoStar property data. [ENUM-REF-CANDIDATE: Type_I-A|Type_I-B|Type_II-A|Type_II-B|Type_III-A|Type_III-B|Type_IV|Type_V-A|Type_V-B — promote to reference product]',
    `insurance_class_code` STRING COMMENT 'Insurer-assigned class code for this construction type used in property insurance policy underwriting and premium calculation. Aligns with ISO Commercial Lines Manual classifications and supports portfolio-level insurance cost benchmarking.. Valid values are `^[A-Z0-9]{1,10}$`',
    `is_combustible` BOOLEAN COMMENT 'Indicates whether this construction type uses combustible materials in its primary structural assembly (True = combustible; False = non-combustible). Directly impacts property insurance classification, fire suppression system requirements, and building code compliance.',
    `iso_construction_class` STRING COMMENT 'ISO construction class code (1–6) used by property insurance underwriters to classify buildings by construction material and fire resistance. Class 1 = Frame; Class 2 = Joisted Masonry; Class 3 = Non-Combustible; Class 4 = Masonry Non-Combustible; Class 5 = Modified Fire Resistive; Class 6 = Fire Resistive. Essential for insurance premium calculation and portfolio risk reporting.. Valid values are `1|2|3|4|5|6`',
    `leed_compatibility` STRING COMMENT 'Indicates whether this construction type is compatible with LEED certification pathways (not_applicable, compatible, preferred). Preferred indicates the construction type is commonly used in LEED-certified projects. Supports ESG investment screening and green development planning.. Valid values are `not_applicable|compatible|preferred`',
    `max_building_height_ft` DECIMAL(18,2) COMMENT 'Maximum allowable building height in feet for this construction type as defined by IBC occupancy and construction type tables. Used in development feasibility analysis, zoning compliance review, and FAR calculations during property acquisition and development planning.',
    `max_stories` STRING COMMENT 'Maximum number of above-grade stories permitted for this construction type under IBC regulations. Supports development feasibility studies, density analysis, and investment underwriting in Argus Enterprise.',
    `primary_material` STRING COMMENT 'Dominant structural material used in this construction type (e.g., wood, steel, concrete, masonry, composite). Drives insurance premium calculations, maintenance cost benchmarks, and CAPEX reserve estimates in Argus Enterprise and Yardi Voyager. [ENUM-REF-CANDIDATE: wood|steel|concrete|masonry|composite|aluminum|other — 7 candidates stripped; promote to reference product]',
    `procore_construction_type_code` STRING COMMENT 'Construction type code as defined in Procore Construction Management system. Enables direct mapping between this enterprise reference record and Procore project specifications, RFIs, and submittal logs for development and renovation projects.. Valid values are `^[A-Z0-9_]{1,30}$`',
    `replacement_cost_multiplier` DECIMAL(18,2) COMMENT 'Relative cost multiplier applied to base construction cost benchmarks to estimate replacement cost for this construction type (e.g., 1.0000 = baseline; 1.2500 = 25% premium over baseline). Used in insurance replacement cost appraisals and Argus Enterprise valuation models.',
    `roof_system` STRING COMMENT 'Typical roof structural system and covering type associated with this construction type (e.g., Built-Up Roofing on Steel Deck, Asphalt Shingle on Wood Truss, TPO Membrane on Concrete). Used in preventive maintenance scheduling in Building Engines and CAPEX reserve planning.',
    `seismic_performance_category` STRING COMMENT 'ASCE 7 seismic design category (A through F) typically associated with this construction type, indicating relative seismic performance and risk. Used in property risk assessment, insurance underwriting, and ESG reporting for portfolio management.. Valid values are `A|B|C|D|E|F`',
    `sort_order` STRING COMMENT 'Integer value controlling the display sequence of construction type options in UI dropdowns, reports, and data entry forms across Yardi Voyager, Procore, and other enterprise systems. Lower values appear first.',
    `structural_system` STRING COMMENT 'Primary lateral and gravity load-resisting structural system associated with this construction type. Informs seismic risk assessment, insurance underwriting, and structural engineering review during property acquisition and development. [ENUM-REF-CANDIDATE: bearing_wall|moment_frame|braced_frame|shear_wall|dual_system|flat_slab|space_frame|other — promote to reference product]',
    `thermal_mass_rating` STRING COMMENT 'Qualitative thermal mass rating (low, moderate, high) indicating the heat storage capacity of this construction type. Impacts energy consumption modeling, LEED/BREEAM certification scoring, and OPEX forecasting for building operations.. Valid values are `low|moderate|high`',
    `typical_construction_duration_months` STRING COMMENT 'Typical construction duration in months for a standard building of this construction type. Used in development project scheduling in Procore, investment return timing analysis in Argus Enterprise, and construction loan draw schedule planning.',
    `typical_cost_psf_high` DECIMAL(18,2) COMMENT 'Upper bound of the typical hard construction cost range in USD per square foot (PSF) for this construction type. Paired with typical_cost_psf_low to define the cost range bracket used in development pro forma modeling and insurance replacement cost estimation.',
    `typical_cost_psf_low` DECIMAL(18,2) COMMENT 'Lower bound of the typical hard construction cost range in USD per square foot (PSF) for this construction type. Used in development feasibility analysis, CAPEX budgeting, and replacement cost valuation in Argus Enterprise and Yardi Voyager.',
    `typical_span_ft` DECIMAL(18,2) COMMENT 'Typical clear span capability in feet for the structural system of this construction type. Informs GLA/NLA planning, column-free floor plate design, and tenant improvement (TI) feasibility assessments for commercial leasing.',
    `typical_useful_life_years` STRING COMMENT 'Expected economic useful life in years for buildings of this construction type. Used for depreciation schedules under FASB ASC 360 and IFRS 16, fixed asset management in Yardi Voyager, and replacement reserve modeling in investment underwriting.',
    `wind_resistance_rating` STRING COMMENT 'Qualitative wind resistance performance rating (basic, enhanced, superior) for this construction type based on IBC and ASCE 7 wind load provisions. Supports property insurance underwriting and catastrophe risk modeling for portfolio management.. Valid values are `basic|enhanced|superior`',
    CONSTRAINT pk_construction_type PRIMARY KEY(`construction_type_id`)
) COMMENT 'Reference classification for building construction methods and structural systems — wood frame, steel frame, concrete (cast-in-place, precast, tilt-up), masonry, modular, and mixed construction. Includes fire resistance rating (Type I–V per IBC), structural system description, typical span capabilities, and applicable property type compatibility. Used by development, maintenance, and valuation domains for construction cost estimation, insurance underwriting, and building condition assessment.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`tenure_type` (
    `tenure_type_id` BIGINT COMMENT 'Unique surrogate identifier for each tenure type record in the enterprise reference repository. Primary key. [Role: REFERENCE_LOOKUP — _canonical_skip_reason: This is a controlled vocabulary / code-list entity; per-role minimum categories do not apply.]',
    `regulatory_framework_id` BIGINT COMMENT 'Foreign key linking to reference.regulatory_framework. Business justification: Tenure types (freehold, leasehold, condominium) are governed by specific regulatory frameworks that define ownership rights, transfer rules, and financing eligibility (e.g., leasehold governed by ASC ',
    `alta_policy_type` STRING COMMENT 'Specifies the standard American Land Title Association (ALTA) title insurance policy type applicable to this tenure structure. Drives title underwriting requirements in transaction and brokerage domains.. Valid values are `owner|lender|leasehold_owner|leasehold_lender|not_applicable`',
    `cmbs_eligible` BOOLEAN COMMENT 'Indicates whether loans secured by properties held under this tenure type are eligible for inclusion in Commercial Mortgage-Backed Securities (CMBS) pools. Leasehold and air rights structures often face CMBS eligibility restrictions.',
    `cre_applicable` BOOLEAN COMMENT 'Indicates whether this tenure type is applicable to Commercial Real Estate (CRE) transactions and portfolio holdings. Used to filter valid tenure types in investment advisory, brokerage, and REIT portfolio management contexts.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this tenure type reference record was first created in the enterprise data platform. Supports audit trail and data governance requirements.',
    `effective_date` DATE COMMENT 'Date from which this tenure type code is valid and available for use in operational and analytical systems. Supports temporal validity management of the reference data repository.',
    `esg_reporting_flag` BOOLEAN COMMENT 'Indicates whether properties held under this tenure type are subject to ESG reporting obligations (e.g., LEED certification tracking, BREEAM assessments, EPA environmental compliance). Supports sustainability reporting for REIT and institutional portfolios.',
    `expiry_date` DATE COMMENT 'Date after which this tenure type code is no longer valid for use in new transactions. Null indicates no planned expiry. Used in conjunction with effective_date to manage reference data lifecycle.',
    `external_reference_code` STRING COMMENT 'Corresponding tenure type code used in an external data provider or industry standard taxonomy (e.g., CoStar Suite property type code, RESO data dictionary tenure field value, MLS tenure classification code). Enables cross-system mapping and market data integration.',
    `fasb_asc842_classification` STRING COMMENT 'Specifies the lease accounting classification applicable to this tenure type under FASB ASC 842. Leasehold interests may be classified as finance or operating leases; freehold is classified as owned asset. Drives accounting treatment in the finance domain.. Valid values are `finance_lease|operating_lease|owned_asset|not_applicable`',
    `fractional_ownership` BOOLEAN COMMENT 'Indicates whether this tenure type inherently involves fractional or shared ownership of a property interest (True for timeshare, co-op share structures; False for sole freehold or standard leasehold). Relevant for investment portfolio and AUM calculations.',
    `ground_lease_applicable` BOOLEAN COMMENT 'Indicates whether this tenure type is associated with or derived from a ground lease arrangement (True for leasehold, air rights; False for freehold, condominium). Links to the lease.ground_lease product for detailed ground lease terms.',
    `hoa_applicable` BOOLEAN COMMENT 'Indicates whether properties held under this tenure type are typically subject to Homeowners Association (HOA) governance, fees, and covenants. Applicable to condominium and certain freehold planned community structures.',
    `ifrs16_classification` STRING COMMENT 'Specifies the lease accounting classification applicable to this tenure type under IFRS 16. Leasehold interests are typically recognized as right-of-use assets; freehold as owned assets. Supports international portfolio reporting and financial consolidation in SAP S/4HANA.. Valid values are `right_of_use_asset|owned_asset|short_term_lease|not_applicable`',
    `is_financeable` BOOLEAN COMMENT 'Indicates whether properties held under this tenure type are generally eligible for conventional mortgage financing (True) or face significant financing restrictions (False), as is common with co-ops, timeshares, and certain leasehold structures. Informs LTV limit applicability.',
    `is_transferable` BOOLEAN COMMENT 'Indicates whether the tenure type permits unrestricted transfer of ownership interest (True) or imposes transferability constraints such as board approval (co-op), lease assignment restrictions, or statutory limitations (life estate). Critical for deal structuring and title underwriting.',
    `ltv_limit_pct` DECIMAL(18,2) COMMENT 'Maximum Loan-to-Value (LTV) ratio percentage typically permitted by lenders for properties held under this tenure type (e.g., 80.00 for freehold, 70.00 for leasehold, null for non-financeable types). Used in finance domain deal structuring and debt instrument underwriting.',
    `notes` STRING COMMENT 'Free-text field for additional governance notes, legal caveats, jurisdiction-specific considerations, or data steward annotations related to this tenure type. Not used for operational processing; intended for data governance and reference data management purposes.',
    `ownership_category` STRING COMMENT 'Broad legal ownership category grouping tenure types for portfolio analysis and regulatory reporting. freehold = absolute ownership (fee simple); leasehold = time-limited ownership under a ground lease; shared_ownership = condominium or co-op structures; limited_interest = easement, air rights, life estate; other = non-standard structures.. Valid values are `freehold|leasehold|shared_ownership|limited_interest|other`',
    `ownership_duration_type` STRING COMMENT 'Classifies the temporal nature of ownership rights conferred by this tenure type. perpetual = freehold/fee simple with no expiry; fixed_term = leasehold with defined expiry; life_of_holder = life estate; conditional = easement or air rights subject to conditions; not_applicable = timeshare or other fractional structures.. Valid values are `perpetual|fixed_term|life_of_holder|conditional|not_applicable`',
    `pmi_applicable` BOOLEAN COMMENT 'Indicates whether Private Mortgage Insurance (PMI) requirements apply to financing arrangements for properties held under this tenure type. Relevant for residential freehold and condominium structures where LTV exceeds 80%.',
    `property_use_class` STRING COMMENT 'Indicates the primary property use classification(s) for which this tenure type is applicable. For example, co-op is predominantly residential; air rights may apply to commercial or mixed-use; freehold applies to all. Used to filter valid tenure types in property and transaction domain workflows.. Valid values are `residential|commercial|mixed_use|industrial|land|all`',
    `registration_required` BOOLEAN COMMENT 'Indicates whether formal title or deed registration with a government land registry is required for this tenure type. Typically True for freehold and long leasehold; may vary for easements and air rights depending on jurisdiction.',
    `reit_eligible` BOOLEAN COMMENT 'Indicates whether properties held under this tenure type qualify for inclusion in a Real Estate Investment Trust (REIT) portfolio under SEC and IRS REIT qualification rules. Certain limited-interest tenures (e.g., timeshare, some easements) may not qualify.',
    `reso_field_name` STRING COMMENT 'The standardized field name or lookup value from the Real Estate Standards Organization (RESO) Data Dictionary that corresponds to this tenure type. Ensures MLS interoperability and industry-standard data exchange compliance.',
    `short_name` STRING COMMENT 'Abbreviated display label for use in space-constrained UI elements, report column headers, and dashboard widgets (e.g., Fee Simple, Leasehold, Condo, Co-op).. Valid values are `^.{1,20}$`',
    `snda_required` BOOLEAN COMMENT 'Indicates whether a Subordination Non-Disturbance and Attornment (SNDA) agreement is typically required for financing or leasing transactions under this tenure type. Relevant for leasehold and ground lease structures.',
    `sort_order` STRING COMMENT 'Numeric sequence controlling the display order of tenure types in dropdown lists, reports, and UI selection components across integrated systems (Yardi Voyager, MRI Software, Salesforce CRM). Lower values appear first.',
    `source_system_code` STRING COMMENT 'Identifier of the operational system of record from which this tenure type was originally sourced or is mastered (e.g., YARDI, MRI, ARGUS, COSTAR). Supports data lineage tracking and system-of-record governance in the Silver Layer.',
    `tenure_type_code` STRING COMMENT 'Short, system-facing alphanumeric code uniquely identifying the tenure type (e.g., FREEHOLD, LEASEHOLD, CONDO, COOP, TIMESHARE, LIFE_ESTATE, EASEMENT, AIR_RIGHTS). Used as the stable integration key across Yardi Voyager, MRI Software, Argus Enterprise, and SAP S/4HANA.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `tenure_type_description` STRING COMMENT 'Full narrative description of the tenure type, including legal ownership characteristics, transferability constraints, and typical use cases. Supports business user education and data governance documentation.',
    `tenure_type_name` STRING COMMENT 'Human-readable, business-facing label for the tenure type (e.g., Freehold (Fee Simple), Leasehold, Condominium, Cooperative (Co-op), Timeshare, Life Estate, Easement, Air Rights). Displayed in transaction, owner, and finance domain UIs and reports.',
    `tenure_type_status` STRING COMMENT 'Lifecycle status of the tenure type reference record. active = currently in use across operational systems; inactive = temporarily disabled; deprecated = superseded by another code and no longer available for new records but retained for historical data integrity.. Valid values are `active|inactive|deprecated`',
    `title_insurance_required` BOOLEAN COMMENT 'Indicates whether title insurance is required or strongly recommended for transactions involving this tenure type, per American Land Title Association (ALTA) standards. Typically True for freehold and leasehold; may vary for air rights and easements.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this tenure type reference record. Used for change tracking, cache invalidation, and downstream system synchronization.',
    `valuation_method_preference` STRING COMMENT 'Indicates the preferred or standard property valuation methodology for properties held under this tenure type, as recognized by the Appraisal Institute and IVSC. Leasehold interests typically require Discounted Cash Flow (DCF) analysis; freehold may use sales comparison or income approach.. Valid values are `income_approach|sales_comparison|cost_approach|dcf|not_specified`',
    CONSTRAINT pk_tenure_type PRIMARY KEY(`tenure_type_id`)
) COMMENT 'Classification of property ownership and tenure structures — freehold (fee simple), leasehold, condominium, cooperative (co-op), timeshare, life estate, easement, and air rights. Defines legal ownership characteristics, transferability constraints, financing eligibility (LTV limits, PMI applicability), and title insurance requirements per ALTA standards. Referenced by transaction, owner, and finance domains for deal structuring, title underwriting, and portfolio ownership analysis.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`document_type` (
    `document_type_id` BIGINT COMMENT 'Unique surrogate identifier for each document type record in the enterprise document type registry. Primary key. [REFERENCE_LOOKUP role — canonical_skip_reason: This is a reference/lookup code table classifying document types; per-role minimum categories do not apply.]',
    `regulatory_framework_id` BIGINT COMMENT 'Foreign key linking to reference.regulatory_framework. Business justification: Document types are governed by specific regulatory frameworks (e.g., lease agreements governed by ASC 842, environmental reports governed by CERCLA, SEC filings governed by SEC regulations). Linking t',
    `allowed_lifecycle_states` STRING COMMENT 'Comma-delimited list of all valid lifecycle states a document of this type may occupy (e.g., draft,under_review,executed,expired,superseded,voided). Defines the complete state machine for document lifecycle management and drives UI validation in DocuSign CLM and Yardi Voyager.',
    `confidentiality_level` STRING COMMENT 'Default data classification and confidentiality level for documents of this type: public (freely shareable), internal (internal use only), confidential (sensitive business data, limited distribution), restricted (highly sensitive, need-to-know access only). Drives DMS access control policies and GDPR data handling procedures.. Valid values are `public|internal|confidential|restricted`',
    `contains_pii` BOOLEAN COMMENT 'Indicates whether documents of this type typically contain personally identifiable information (PII) subject to GDPR or other privacy regulations (True). Applies to tenant applications, background check reports, guarantor financial statements, and employment records. Drives GDPR data subject request handling.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this document type record was first created in the enterprise reference data registry. Supports audit trail, data lineage, and SOX internal control documentation.',
    `default_lifecycle_state` STRING COMMENT 'The initial lifecycle state assigned to a new document instance of this type upon creation: draft (under preparation), executed (fully signed), expired (past term end), superseded (replaced by amendment or new version), voided (cancelled before execution). Defines the starting node in the document lifecycle state machine.. Valid values are `draft|executed|expired|superseded|voided`',
    `document_type_category` STRING COMMENT 'High-level category grouping the document type by its primary business function: legal (contracts, agreements), financial (loan docs, tax returns, CMBS prospectuses), operational (work orders, COOs, HOA docs), compliance (regulatory filings, SOX controls), environmental (Phase I/II reports, EPA filings), insurance (certificates, policies), title (ALTA commitments, deeds), construction (Procore submittals, RFIs, BIM deliverables). [ENUM-REF-CANDIDATE: legal|financial|operational|compliance|environmental|insurance|title|construction — 8 candidates stripped; promote to reference product]',
    `document_type_status` STRING COMMENT 'Lifecycle status of the document type record in the registry. active = currently in use across operations; inactive = no longer issued but retained for historical records; deprecated = superseded by a newer type; draft = under review and not yet published for operational use.. Valid values are `active|inactive|deprecated|draft`',
    `domain` STRING COMMENT 'The primary enterprise data domain this document type belongs to, aligning with the enterprise data domain taxonomy (Lease, Transaction, Valuation, Development, Investment, Maintenance, Brokerage, Finance, Compliance, Tenant, Property). Drives domain-specific workflow routing and access control. [ENUM-REF-CANDIDATE: lease|transaction|valuation|development|investment|maintenance|brokerage|finance|compliance|tenant|property — 11 candidates stripped; promote to reference product]',
    `effective_date` DATE COMMENT 'The date from which this document type definition became or becomes effective for operational use. Supports versioning and temporal validity of the reference data registry, ensuring historical document records reference the correct type definition at the time of document creation.',
    `esg_relevant` BOOLEAN COMMENT 'Indicates whether this document type is relevant to Environmental, Social, and Governance (ESG) reporting obligations (True). Applies to LEED certification documents, BREEAM assessments, Phase I/II environmental reports, EPA compliance filings, and ESG disclosure reports for publicly traded REITs.',
    `expiry_date` DATE COMMENT 'The date on which this document type definition ceases to be valid for new document creation. Null indicates no planned expiry. Used in conjunction with effective_date to support bi-temporal reference data management and regulatory change management.',
    `external_standard_code` STRING COMMENT 'Industry-standard or regulatory code identifying this document type in an external classification system (e.g., RESO document type code, ALTA form number, HUD form number, ASTM standard reference for Phase I/II environmental reports, AIA contract document number). Enables cross-system interoperability and regulatory reporting.',
    `filing_obligation` STRING COMMENT 'Specifies the external filing or recording obligation for documents of this type: none (internal only), county_recording (deeds, mortgages), sec_filing (REIT prospectuses, 10-K/10-Q exhibits), hud_filing (HUD-required forms), state_filing (state regulatory submissions), municipal_filing (local permits, COOs). Drives compliance workflow routing. [ENUM-REF-CANDIDATE: none|internal_only|county_recording|sec_filing|hud_filing|state_filing|municipal_filing — 7 candidates stripped; promote to reference product]',
    `is_legal_instrument` BOOLEAN COMMENT 'Indicates whether this document type constitutes a legally binding instrument (True) or is an informational/operational document (False). Legal instruments include lease agreements, PSAs, SNDAs, LOIs, loan documents, and deeds. Drives mandatory signatory and notarization requirements.',
    `is_recordable` BOOLEAN COMMENT 'Indicates whether this document type must be recorded with a county recorder, land registry, or other governmental authority (True). Applies to deeds, mortgages, ALTA title commitments, easements, and certain lease memoranda. Drives title and closing workflow steps.',
    `is_regulated` BOOLEAN COMMENT 'Indicates whether this document type is subject to specific regulatory requirements (True), such as SEC disclosure requirements for REIT prospectuses, HUD forms, EPA environmental reports, or OSHA safety certifications. Triggers compliance workflow and mandatory review steps.',
    `is_template_available` BOOLEAN COMMENT 'Indicates whether a standard enterprise-approved template exists for this document type (True). When True, the template_reference_code field identifies the master template in DocuSign CLM or the document management system. Drives template-based document generation workflows.',
    `min_signatory_count` STRING COMMENT 'Minimum number of signatories required for a document of this type to be considered fully executed. Used to validate document completeness in DocuSign CLM and compliance audit workflows.',
    `property_type_applicability` STRING COMMENT 'Comma-delimited list of property types for which this document type is applicable (e.g., commercial,industrial,retail,multifamily,office,land,mixed_use,residential). A null or all value indicates universal applicability. Supports property-type-specific document requirement validation.',
    `required_signatory_roles` STRING COMMENT 'Comma-delimited list of organizational roles required to execute documents of this type (e.g., Landlord,Tenant,Guarantor, Buyer,Seller,Escrow Officer, Borrower,Lender,Notary). Drives DocuSign CLM routing templates and execution workflow configuration.',
    `requires_board_approval` BOOLEAN COMMENT 'Indicates whether documents of this type require board or investment committee approval before execution (True). Typically applies to major acquisition PSAs, large loan documents, REIT prospectuses, and significant lease commitments above defined thresholds. Relevant for SEC-regulated REITs under SOX.',
    `requires_legal_review` BOOLEAN COMMENT 'Indicates whether documents of this type must undergo mandatory legal counsel review before execution (True). Applies to complex instruments such as ground leases, SNDA agreements, CMBS loan documents, and environmental indemnity agreements. Drives approval workflow routing.',
    `requires_notarization` BOOLEAN COMMENT 'Indicates whether documents of this type require notarization before they are considered legally valid and enforceable. Applies to deeds, certain mortgage documents, and affidavits. Drives closing checklist and DocuSign CLM workflow configuration.',
    `requires_wet_signature` BOOLEAN COMMENT 'Indicates whether this document type requires original wet (ink) signatures rather than electronic signatures via DocuSign CLM. Certain jurisdictions and document types (e.g., deeds, wills, some mortgage instruments) mandate wet signatures for legal validity.',
    `retention_basis` STRING COMMENT 'The event from which the retention period clock starts: from_execution (date document was signed), from_expiration (date agreement expired), from_termination (date relationship ended), from_creation (date document was created), permanent (never purge). Critical for SOX and SEC compliance scheduling.. Valid values are `from_execution|from_expiration|from_termination|from_creation|permanent`',
    `retention_period_years` STRING COMMENT 'Mandatory document retention period in years as required by applicable regulations (SEC Rule 17a-4 for REIT records, SOX Section 802 for financial records, state real estate record-keeping laws, IRS requirements for tax documents). Drives automated archival and purge scheduling in the document management system.',
    `sort_order` STRING COMMENT 'Numeric value controlling the display sequence of document types in UI dropdowns, document checklists, and reports. Lower values appear first. Enables business-defined ordering independent of alphabetical or ID-based sorting.',
    `source_system` STRING COMMENT 'The operational system of record that primarily originates or manages documents of this type: Yardi Voyager (lease and AR documents), MRI Software (investment and residential documents), Procore (construction submittals and RFIs), DocuSign CLM (executed contracts), SAP S/4HANA (financial and procurement documents), Building Engines (work orders and maintenance records), or manual for paper-based origination. [ENUM-REF-CANDIDATE: yardi|mri|argus|salesforce|costar|sap|procore|building_engines|docusign|adp|manual — 11 candidates stripped; promote to reference product]',
    `sox_control_applicable` BOOLEAN COMMENT 'Indicates whether this document type falls within the scope of SOX Section 302/404 internal controls over financial reporting (True). Applies to financial statements, material contracts, loan agreements, and lease documents that affect reported financial position under FASB ASC 842 or IFRS 16.',
    `subcategory` STRING COMMENT 'Secondary classification within the category providing finer-grained grouping (e.g., within legal: lease_document, sale_document, financing_document, dispute_resolution; within financial: appraisal_report, loan_document, tax_document). Supports hierarchical document taxonomy navigation.',
    `template_reference_code` STRING COMMENT 'The identifier of the master document template in DocuSign CLM or the enterprise document management system associated with this document type. Populated only when is_template_available is True. Used to auto-populate document generation workflows.',
    `transaction_type_applicability` STRING COMMENT 'Comma-delimited list of transaction types for which this document type is applicable (e.g., acquisition,disposition,leasing,refinancing,development,property_management). Supports transaction-specific document checklist generation and deal pipeline management in Salesforce CRM.',
    `type_code` STRING COMMENT 'Short, system-unique alphanumeric code identifying the document type (e.g., LEASE_AGR, LOI, SNDA, PSA, ALTA_TITLE, PHASE1_ENV, COO, APPRAISAL, CMBS_PROSP). Used as the stable external key for cross-system integration with Yardi Voyager, MRI Software, DocuSign CLM, and Procore.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `type_description` STRING COMMENT 'Detailed narrative description of the document type, its legal or operational purpose, and the business context in which it is used. Supports onboarding, compliance training, and audit documentation.',
    `type_name` STRING COMMENT 'Full human-readable name of the document type as used in business operations (e.g., Lease Agreement, Letter of Intent (LOI), Subordination Non-Disturbance and Attornment Agreement (SNDA), Purchase and Sale Agreement (PSA), ALTA Title Commitment). Displayed in document management UIs and reports.',
    `typical_validity_days` STRING COMMENT 'Standard number of days a document of this type remains valid from its execution or issuance date before it expires or requires renewal (e.g., ALTA title commitments typically valid 180 days, insurance certificates 365 days, LOIs 30-90 days). Used to auto-calculate expiration dates and trigger renewal alerts.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this document type record was most recently modified in the enterprise reference data registry. Supports change tracking, audit trail, and incremental data pipeline processing in the Databricks Lakehouse Silver Layer.',
    `workflow_template_code` STRING COMMENT 'Reference code for the standard approval and routing workflow template associated with this document type in DocuSign CLM or the enterprise document management system. Maps to pre-configured routing rules, approval chains, and SLA timelines for document execution.. Valid values are `^[A-Z0-9_]{2,30}$`',
    CONSTRAINT pk_document_type PRIMARY KEY(`document_type_id`)
) COMMENT 'Enterprise document type registry classifying all real estate legal, operational, and financial documents — lease agreements, LOIs, SNDAs, estoppel certificates, PSAs, ALTA title commitments, Phase I/II environmental reports, certificates of occupancy, appraisal reports, loan documents, CMBS prospectuses, HOA governing documents, insurance certificates, and tax returns. Defines required signatories, regulatory retention periods (per SEC, SOX, state record-keeping laws), workflow routing rules, filing obligations, and document lifecycle states (draft, executed, expired, superseded). Serves as the authoritative lookup for document management, compliance, and audit trail across all operational domains.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`space_use_type` (
    `space_use_type_id` BIGINT COMMENT 'Unique surrogate identifier for each space use type classification record. Primary key for the controlled vocabulary of leasable space use categories. [Role: REFERENCE_LOOKUP — _canonical_skip_reason: This is a small enumeration/code-list table providing controlled vocabulary for space use classifications; per-role minimum categories are exempt.]',
    `uom_id` BIGINT COMMENT 'Foreign key linking to reference.uom. Business justification: Space use types define area measurement standards (e.g., rentable square feet, gross leasable area) that must reference the enterprise UOM registry for consistency. Linking ensures that area benchmark',
    `industry_classification_id` BIGINT COMMENT 'Foreign key linking to reference.industry_classification. Business justification: Space use types are associated with specific industry classifications that define the type of tenant occupying the space (e.g., retail space → NAICS 44-45 Retail Trade, office space → NAICS 52 Finance',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: Tenant improvement allowance benchmarks (ti_allowance_benchmark_psf) are denominated in a specific currency. Linking to the ISO 4217 currency registry ensures referential integrity for financial bench',
    `ada_compliance_required` BOOLEAN COMMENT 'Indicates whether Americans with Disabilities Act (ADA) accessibility compliance requirements are mandated for spaces of this use type. Drives compliance checklist generation in Building Engines and regulatory reporting for HUD and local authorities.',
    `applicable_lease_structures` STRING COMMENT 'Pipe-delimited list of lease structures typically associated with this space use type (e.g., NNN|gross|modified_gross|percentage_rent|ground_lease). Guides lease structuring in Yardi Voyager and DocuSign CLM and informs brokerage deal configuration. [ENUM-REF-CANDIDATE: NNN|gross|modified_gross|percentage_rent|ground_lease|net|double_net — promote to reference product]',
    `base_rent_benchmark_psf` DECIMAL(18,2) COMMENT 'Market benchmark base rent rate expressed in currency Per Square Foot (PSF) per annum for this space use type. Sourced from CoStar Suite comparable lease data and used in Argus Enterprise cash flow modeling and brokerage CMA preparation.',
    `breakpoint_type` STRING COMMENT 'Specifies the breakpoint type used in percentage rent calculations for this space use type — natural breakpoint (base rent divided by percentage rate), artificial breakpoint (negotiated fixed threshold), or not applicable. Relevant for retail and F&B use types in Yardi Voyager percentage rent schedules.. Valid values are `natural|artificial|not_applicable`',
    `cam_inclusion_rule` STRING COMMENT 'Defines whether Common Area Maintenance (CAM) charges are included, excluded, partially included, or not applicable for spaces of this use type. Drives CAM reconciliation logic in Yardi Voyager and MRI Software lease accounting modules.. Valid values are `included|excluded|partial|not_applicable`',
    `cam_recovery_method` STRING COMMENT 'Specifies the CAM expense recovery methodology applicable to this space use type — pro-rata share, fixed amount, capped recovery, base-year stop, or not applicable. Used in Yardi Voyager CAM estimate and reconciliation schedules.. Valid values are `pro_rata|fixed|capped|base_year|not_applicable`',
    `capex_responsibility` STRING COMMENT 'Defines the default Capital Expenditure (CAPEX) responsibility for structural improvements and major systems for this space use type — landlord, tenant, shared, or not applicable. Supports CAPEX planning in Procore and fixed asset management in Yardi Voyager.. Valid values are `landlord|tenant|shared|not_applicable`',
    `co_tenancy_applicable` BOOLEAN COMMENT 'Indicates whether co-tenancy clauses (allowing rent reduction or termination rights if anchor tenants vacate) are typically applicable for this space use type. Primarily relevant for retail and food-and-beverage use types in shopping center lease structures.',
    `effective_date` DATE COMMENT 'Date from which this space use type classification became or becomes effective in the enterprise controlled vocabulary. Supports temporal validity tracking for data governance and audit purposes.',
    `exclusive_use_applicable` BOOLEAN COMMENT 'Indicates whether exclusive use clauses (restricting the landlord from leasing adjacent space to competing tenants) are typically applicable for this space use type. Relevant for retail, food-and-beverage, and medical use types in lease negotiation and Salesforce CRM deal pipeline management.',
    `expiry_date` DATE COMMENT 'Date on which this space use type classification ceases to be valid in the enterprise controlled vocabulary. Null indicates no planned expiry. Supports deprecation management and controlled vocabulary lifecycle governance.',
    `external_code_costar` STRING COMMENT 'Corresponding space use type code as used in CoStar Suite for comparable lease and property analytics. Enables direct mapping between enterprise reference data and CoStar market data for benchmarking and CMA preparation.',
    `external_code_reso` STRING COMMENT 'Corresponding space use type code as defined by the Real Estate Standards Organization (RESO) data dictionary standard. Enables interoperability with MLS systems, CoStar Suite, and other RESO-compliant platforms for data exchange and market benchmarking.',
    `fire_egress_class` STRING COMMENT 'International Building Code (IBC) occupancy classification for fire egress and life safety purposes associated with this space use type (e.g., assembly, business, mercantile, storage). Drives building compliance checks and preventive maintenance scheduling in Building Engines. [ENUM-REF-CANDIDATE: assembly|business|mercantile|industrial|storage|residential|hazardous|not_applicable — 8 candidates stripped; promote to reference product]',
    `fit_out_category` STRING COMMENT 'Standard fit-out delivery condition associated with this space use type — warm shell, cold shell, turnkey, as-is, or not applicable. Informs TI allowance benchmarking, construction scope in Procore, and lease negotiation defaults in Salesforce CRM.. Valid values are `warm_shell|cold_shell|turnkey|as_is|not_applicable`',
    `food_service_permitted` BOOLEAN COMMENT 'Indicates whether food preparation and service activities are permitted for spaces of this use type. Relevant for distinguishing restaurant/F&B use from retail or office use types, and for triggering health department compliance requirements and grease trap infrastructure planning.',
    `hvac_responsibility` STRING COMMENT 'Defines who bears responsibility for Heating, Ventilation, and Air Conditioning (HVAC) systems for this space use type — landlord, tenant, shared, or not applicable. Drives lease clause defaults in DocuSign CLM and work order assignment rules in Building Engines.. Valid values are `landlord|tenant|shared|not_applicable`',
    `leed_relevance` STRING COMMENT 'Indicates the degree to which LEED certification criteria and ESG sustainability metrics are relevant to this space use type — high, medium, low, or not applicable. Supports ESG reporting, green building compliance, and LEED certification tracking per U.S. Green Building Council standards.. Valid values are `high|medium|low|not_applicable`',
    `load_factor_typical` DECIMAL(18,2) COMMENT 'Typical load factor (also known as loss factor or add-on factor) expressed as a decimal ratio for this space use type, representing the difference between rentable and usable area (e.g., 0.15 = 15%). Used in BOMA-compliant area calculations and rent roll reporting in Yardi Voyager.',
    `max_contiguous_area` DECIMAL(18,2) COMMENT 'Maximum contiguous leasable area (in the applicable unit of measure — SQF or SQM) typically available for this space use type within a single building. Used in CoStar Suite availability searches and brokerage space matching for large-block tenant requirements.',
    `measurement_standard` STRING COMMENT 'Defines the area measurement methodology applicable to this space use type — Gross Leasable Area (GLA), Net Leasable Area (NLA), BOMA standard, IPMS standard, gross, or net. Governs how rentable square footage is calculated and reported for rent roll and lease administration purposes.. Valid values are `GLA|NLA|BOMA|IPMS|gross|net`',
    `min_divisible_area` DECIMAL(18,2) COMMENT 'Minimum leasable area (in the applicable unit of measure — SQF or SQM) to which a space of this use type can be subdivided. Governs space planning and demised space configuration in Yardi Voyager and MRI Software space inventory management.',
    `occupancy_density_typical` DECIMAL(18,2) COMMENT 'Typical occupancy density expressed as area per person (SQF or SQM per person) for this space use type. Used in building capacity planning, HVAC sizing, fire safety compliance, and ESG workplace analytics.',
    `opex_responsibility` STRING COMMENT 'Defines the default Operating Expenditure (OPEX) responsibility allocation for this space use type — landlord, tenant, shared, or not applicable. Informs lease structure defaults, CAM billing configuration in Yardi Voyager, and NOI modeling in Argus Enterprise.. Valid values are `landlord|tenant|shared|not_applicable`',
    `outdoor_area_applicable` BOOLEAN COMMENT 'Indicates whether outdoor or exterior leasable area (e.g., patio, terrace, rooftop deck, signage fascia) is applicable and measurable for this space use type. Affects GLA/NLA calculation methodology and lease area definitions in Yardi Voyager.',
    `parking_ratio_per_1000sqf` DECIMAL(18,2) COMMENT 'Standard parking ratio (number of parking stalls per 1,000 square feet of leasable area) associated with this space use type. Used in property development feasibility, zoning compliance, and lease negotiation for office, retail, and medical use types.',
    `percentage_rent_applicable` BOOLEAN COMMENT 'Indicates whether percentage rent (overage rent based on tenant gross sales) is a standard feature of leases for this space use type. Typically true for retail and food-and-beverage use types. Drives percentage rent clause inclusion in Yardi Voyager lease setup.',
    `property_type_applicability` STRING COMMENT 'Pipe-delimited list of property types to which this space use type applies (e.g., office_building|mixed_use|retail_center|medical_office). Constrains valid space use assignments during lease and space inventory setup in Yardi Voyager and MRI Software. [ENUM-REF-CANDIDATE: office_building|retail_center|mixed_use|medical_office|industrial|multifamily|hospitality|specialty — promote to reference product]',
    `rent_escalation_type` STRING COMMENT 'Typical rent escalation mechanism associated with this space use type — fixed step increases, CPI-indexed, percentage-based, flat (no escalation), or not applicable. Informs rent schedule configuration in Yardi Voyager and Argus Enterprise cash flow projections.. Valid values are `fixed_step|cpi_indexed|percentage|flat|not_applicable`',
    `revenue_recognition_method` STRING COMMENT 'Accounting revenue recognition method applicable to lease income for this space use type — straight-line, cash basis, percentage of completion, or not applicable. Governs lease accounting entries in Yardi Voyager GL and SAP S/4HANA financial consolidation per FASB ASC 842 and IFRS 16.. Valid values are `straight_line|cash_basis|percentage_of_completion|not_applicable`',
    `rou_asset_applicable` BOOLEAN COMMENT 'Indicates whether a Right-of-Use (ROU) asset must be recognized on the lessees balance sheet for leases of this space use type under FASB ASC 842 or IFRS 16. Drives lease accounting classification logic in Yardi Voyager and MRI Software lease accounting modules.',
    `sort_order` STRING COMMENT 'Numeric display sort order for presenting space use type options in UI dropdowns, reports, and rent roll templates. Allows business-defined ordering independent of alphabetical or ID sequence.',
    `space_use_type_status` STRING COMMENT 'Current lifecycle status of the space use type record in the controlled vocabulary — active (in use), inactive (no longer applied to new leases), deprecated (replaced by another code), or pending_review (under governance review). Governs availability of the code in downstream lease and property systems.. Valid values are `active|inactive|deprecated|pending_review`',
    `sublease_permitted` BOOLEAN COMMENT 'Indicates whether subleasing is typically permitted for spaces of this use type. Drives default sublease clause inclusion in DocuSign CLM lease templates and sublease approval workflow configuration in Yardi Voyager.',
    `ti_allowance_benchmark_psf` DECIMAL(18,2) COMMENT 'Market benchmark Tenant Improvement (TI) allowance expressed in currency Per Square Foot (PSF) for this space use type. Provides a reference value for lease negotiation, deal underwriting in Argus Enterprise, and TI budget planning in Procore.',
    `typical_lease_term_max_months` STRING COMMENT 'Maximum typical lease term in months for this space use type, reflecting market norms. Used alongside the minimum to define the expected lease term range for deal structuring, WALT analysis, and Argus Enterprise cash flow modeling.',
    `typical_lease_term_min_months` STRING COMMENT 'Minimum typical lease term in months for this space use type, reflecting market norms (e.g., 12 months for storage, 60 months for office, 120 months for anchor retail). Used in Weighted Average Lease Term (WALT) benchmarking and deal underwriting.',
    `use_category` STRING COMMENT 'Broad asset class category grouping the space use type (e.g., commercial, residential, mixed_use, industrial, hospitality, specialty). Aligns with CoStar Suite and Argus Enterprise asset class taxonomies for portfolio-level reporting and investment analysis.. Valid values are `commercial|residential|mixed_use|industrial|hospitality|specialty`',
    `use_type_code` STRING COMMENT 'Short, system-recognized alphanumeric code uniquely identifying the space use type (e.g., OFF, RET, F&B, MED, FIT, STG, PRK, RTF, SGN, CAM). Used as the business key in Yardi Voyager, MRI Software, and CoStar Suite for space inventory classification and rent roll reporting.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `use_type_description` STRING COMMENT 'Detailed narrative description of the space use classification, including typical tenant profile, permitted activities, and distinguishing characteristics from adjacent use types. Supports training, onboarding, and data governance documentation.',
    `use_type_name` STRING COMMENT 'Full human-readable name of the space use classification (e.g., Office, Retail, Restaurant / Food and Beverage, Medical / Dental, Fitness, Storage, Parking, Rooftop, Signage, Common Area). Displayed in lease administration, rent roll, and brokerage reporting.',
    `zoning_use_class` STRING COMMENT 'Standard zoning use classification code or category associated with this space use type (e.g., B1, A1, A3, D1 under UK Use Classes Order; or C-1, C-2, O-1 under US zoning codes). Supports regulatory compliance checks and development feasibility analysis. [ENUM-REF-CANDIDATE: promote to reference product if jurisdiction-specific zoning codes are required]',
    CONSTRAINT pk_space_use_type PRIMARY KEY(`space_use_type_id`)
) COMMENT 'Controlled vocabulary for leasable space use classifications within a building — office, retail, restaurant/food and beverage, medical/dental, fitness, storage, parking, rooftop, signage, and common area. Defines GLA/NLA measurement methodology per use type, applicable lease structures, TI allowance benchmarks, and CAM inclusion/exclusion rules. Used by lease, property, and brokerage domains for space inventory management and rent roll reporting.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`investment_vehicle` (
    `investment_vehicle_id` BIGINT COMMENT 'Primary key for investment_vehicle',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: Investment vehicles denominate minimum investment amounts and financial metrics in a specific currency. Linking to the ISO 4217 currency registry ensures referential integrity for financial data and e',
    `accounting_standard` STRING COMMENT 'Financial accounting standard under which this investment vehicle type is reported: US_GAAP (FASB ASC 946 for investment companies, ASC 842 for lease obligations), IFRS (IFRS 16 for leases, IFRS 10 for consolidation), both (dual-reporting entities), other.. Valid values are `US_GAAP|IFRS|both|other`',
    `carried_interest_pct` DECIMAL(18,2) COMMENT 'Standard carried interest (promote) percentage allocated to the general partner or fund manager above the preferred return threshold, expressed as a decimal (e.g., 0.2000 = 20%). Null for vehicles without a carried interest structure (e.g., REITs, separate accounts).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this investment vehicle reference record was first created in the enterprise data platform. Supports data lineage, audit trail, and reference data governance.',
    `effective_date` DATE COMMENT 'Date from which this investment vehicle reference classification became effective and available for use across enterprise systems. Used for temporal validity tracking and historical reporting.',
    `erisa_eligible` BOOLEAN COMMENT 'Indicates whether this investment vehicle type is eligible to accept capital from ERISA-governed pension and retirement plan assets. Relevant for plan asset rules, fiduciary obligations, and prohibited transaction exemptions under ERISA.',
    `esg_reporting_required` BOOLEAN COMMENT 'Indicates whether this investment vehicle type requires Environmental, Social, and Governance (ESG) reporting to investors or regulators. Relevant for GRESB (Global Real Estate Sustainability Benchmark) participation, SFDR (EU Sustainable Finance Disclosure Regulation) compliance, and institutional investor mandates.',
    `exchange_listed` BOOLEAN COMMENT 'Indicates whether this investment vehicle type is listed and traded on a public securities exchange (e.g., NYSE, NASDAQ for publicly traded REITs). False for non-traded REITs, private equity funds, DSTs, and other non-listed vehicles.',
    `expiry_date` DATE COMMENT 'Date on which this investment vehicle reference classification expires or is no longer valid for use in new transactions or structures. Null for classifications with no defined end date. Supports temporal validity and reference data lifecycle management.',
    `finra_product_type_code` STRING COMMENT 'FINRA product type classification code applicable to this investment vehicle for broker-dealer compliance, suitability analysis, and regulatory reporting (e.g., non-traded REIT, direct participation program, public non-listed REIT). Null for vehicles not distributed through broker-dealers.',
    `fund_structure` STRING COMMENT 'Structural characteristic of the investment vehicle indicating liquidity and redemption profile: open_end (continuous subscriptions/redemptions, e.g., ODCE funds), closed_end (fixed capital raise, finite life), evergreen (perpetual with periodic liquidity windows), finite_life (defined investment period and wind-down), perpetual (no defined end date). Null for non-fund vehicles.. Valid values are `open_end|closed_end|evergreen|finite_life|perpetual`',
    `geographic_focus` STRING COMMENT 'Primary geographic investment mandate or focus for this vehicle type (e.g., US_national, US_gateway_markets, Europe, Asia_Pacific, global, specific_state_or_MSA). Used for geographic diversification analysis and investor mandate alignment.',
    `hud_regulated` BOOLEAN COMMENT 'Indicates whether this investment vehicle type is subject to U.S. Department of Housing and Urban Development (HUD) regulations, applicable to vehicles investing in affordable housing, FHA-insured mortgages, or HUD-assisted multifamily properties.',
    `inrev_vehicle_type_code` STRING COMMENT 'INREV standardized vehicle type code for European non-listed real estate fund classification and reporting. Used for cross-border institutional investor reporting and INREV benchmark comparisons.',
    `investment_strategy` STRING COMMENT 'Risk-return investment strategy classification for the vehicle type: core (stabilized, low-risk, income-focused), core_plus (modest value enhancement), value_add (significant repositioning or lease-up), opportunistic (highest risk/return, development or distressed), debt (mortgage/mezzanine lending), diversified (multi-strategy). Aligns with NCREIF/INREV/ANREV style classifications.. Valid values are `core|core_plus|value_add|opportunistic|debt|diversified`',
    `investment_vehicle_description` STRING COMMENT 'Detailed narrative description of the investment vehicle type, including its structural characteristics, typical use cases, investor base, and distinguishing features. Used in investor education materials, onboarding documentation, and regulatory disclosures.',
    `investment_vehicle_status` STRING COMMENT 'Current lifecycle status of this investment vehicle reference record: active (in use across consuming domains), inactive (no longer in use for new structures), deprecated (superseded by a newer classification), pending_review (under governance review for addition or modification).. Valid values are `active|inactive|deprecated|pending_review`',
    `investor_eligibility` STRING COMMENT 'Minimum investor eligibility classification required to participate in this vehicle type: retail (open to general public), accredited (SEC Reg D Rule 501 — net worth >$1M or income >$200K), qualified_purchaser (Investment Company Act — $5M+ investments), institutional (pension funds, endowments, sovereign wealth), qualified_eligible_person (CFTC Rule 4.7), other.. Valid values are `retail|accredited|qualified_purchaser|institutional|qualified_eligible_person|other`',
    `legal_structure` STRING COMMENT 'Legal organizational form of the investment vehicle (e.g., corporation for REITs, limited partnership for PE funds, LLC, statutory trust for DSTs, tenancy_in_common for TIC structures). Drives tax treatment, liability, and regulatory filing requirements. [ENUM-REF-CANDIDATE: corporation|partnership|llc|trust|statutory_trust|tenancy_in_common|other — 7 candidates stripped; promote to reference product]',
    `leverage_permitted` BOOLEAN COMMENT 'Indicates whether the investment vehicle type is permitted to use debt financing (leverage). True for most equity and value-add vehicles; may be False for certain tax-exempt or regulatory-constrained structures. Relevant for LTV and DSCR compliance monitoring.',
    `liquidity_profile` STRING COMMENT 'Investor liquidity profile indicating the frequency or availability of redemptions/withdrawals: daily (publicly traded REITs), monthly, quarterly (ODCE funds), annual, semi_liquid (periodic liquidity windows), illiquid (closed-end funds with no redemption until wind-down). Critical for investor suitability and portfolio liquidity management.. Valid values are `daily|monthly|quarterly|annual|semi_liquid|illiquid`',
    `management_fee_basis` STRING COMMENT 'Basis on which management fees are calculated for this vehicle type: nav (Net Asset Value), committed_capital (total LP commitments), invested_capital (deployed capital), gross_asset_value (GAV including leverage), other. Used in fee modeling and investor reporting.. Valid values are `nav|committed_capital|invested_capital|gross_asset_value|other`',
    `max_leverage_ratio` DECIMAL(18,2) COMMENT 'Maximum permitted Loan-to-Value (LTV) ratio for this investment vehicle type, expressed as a decimal (e.g., 0.6500 = 65% LTV). Null if leverage is not permitted or no regulatory cap applies. Used in debt structuring, CMBS underwriting, and DSCR compliance.',
    `min_investment_amount` DECIMAL(18,2) COMMENT 'Minimum capital commitment or investment threshold required for participation in this vehicle type, expressed in the vehicles base currency. Used during investor onboarding and eligibility screening. Null for publicly traded vehicles with no minimum.',
    `n1031_exchange_eligible` BOOLEAN COMMENT 'Indicates whether interests in this investment vehicle type qualify for like-kind exchange treatment under IRS Section 1031, allowing deferral of capital gains tax upon disposition. Applicable to DSTs and direct property ownership structures; generally not applicable to REIT shares or partnership interests.',
    `ncreif_vehicle_type_code` STRING COMMENT 'NCREIF standardized vehicle type code used for performance benchmarking and index inclusion (e.g., ODCE for Open-End Diversified Core Equity funds). Enables comparison against NCREIF NPI, NCREIF ODCE, and NCREIF PREA benchmarks.',
    `preferred_return_pct` DECIMAL(18,2) COMMENT 'Standard preferred return (hurdle rate) percentage applicable to this vehicle type, expressed as a decimal (e.g., 0.0800 = 8%). Represents the minimum return threshold that must be achieved before the general partner or manager participates in carried interest. Null for vehicles without a preferred return structure.',
    `property_type_focus` STRING COMMENT 'Primary real estate property type focus or mandate for this investment vehicle type: diversified (multi-sector), office, retail, industrial, multifamily, hospitality, healthcare, mixed_use, other. Used for portfolio construction, sector allocation analytics, and investor mandate matching. [ENUM-REF-CANDIDATE: diversified|office|retail|industrial|multifamily|hospitality|healthcare|mixed_use|other — 9 candidates stripped; promote to reference product]',
    `regulatory_classification` STRING COMMENT 'Primary regulatory classification of the investment vehicle indicating the governing regulatory framework: sec_registered (publicly traded REITs, registered funds), sec_exempt (private placements under Reg D), finra_regulated, state_blue_sky (state-level securities regulation), unregulated (institutional separate accounts), other.. Valid values are `sec_registered|sec_exempt|finra_regulated|state_blue_sky|unregulated|other`',
    `reit_distribution_requirement_pct` DECIMAL(18,2) COMMENT 'Minimum percentage of taxable income that must be distributed to shareholders to maintain REIT tax status. Typically 90% per IRS requirements. Null for non-REIT vehicle types. Used in compliance monitoring and investor reporting.',
    `reporting_standard` STRING COMMENT 'Primary performance and financial reporting standard applicable to this investment vehicle type: NCREIF (National Council of Real Estate Investment Fiduciaries — U.S. institutional), INREV (European non-listed real estate), ANREV (Asia-Pacific non-listed real estate), GIPS (Global Investment Performance Standards), SEC (public company reporting), GAAP (U.S. Generally Accepted Accounting Principles), IFRS (International Financial Reporting Standards), other. [ENUM-REF-CANDIDATE: NCREIF|INREV|ANREV|GIPS|SEC|GAAP|IFRS|other — 8 candidates stripped; promote to reference product]',
    `sec_form_type` STRING COMMENT 'Primary SEC filing form type associated with this investment vehicle type (e.g., S-11 for REIT IPO registration, 10-K for annual report, 10-Q for quarterly report, N-2 for closed-end fund registration, D for Regulation D private placement). Null for non-SEC-registered vehicles.',
    `sec_registration_required` BOOLEAN COMMENT 'Indicates whether this investment vehicle type requires registration with the U.S. Securities and Exchange Commission (SEC). True for publicly traded REITs and registered investment companies; False for private placements and institutional separate accounts.',
    `sox_compliance_required` BOOLEAN COMMENT 'Indicates whether this investment vehicle type is subject to Sarbanes-Oxley Act (SOX) internal control and financial reporting requirements. Applicable to publicly traded REITs and other SEC-reporting entities. Drives audit, internal control, and financial close processes.',
    `tax_treatment` STRING COMMENT 'Federal income tax treatment applicable to this investment vehicle type: pass_through (partnerships, LLCs), reit_distribution (REIT must distribute 90%+ of taxable income), c_corp (corporate taxation), ubti_exempt (Unrelated Business Taxable Income exempt for tax-exempt investors), ubti_subject (generates UBTI for tax-exempt investors), other.. Valid values are `pass_through|reit_distribution|c_corp|ubti_exempt|ubti_subject|other`',
    `typical_hold_period_years` DECIMAL(18,2) COMMENT 'Standard or typical investment hold period in years for this vehicle type (e.g., 7.0 for a closed-end value-add fund, 10.0 for an opportunistic fund, null for open-end perpetual vehicles). Used in IRR modeling, DCF analysis, and investor return projections in Argus Enterprise.',
    `ubti_generating` BOOLEAN COMMENT 'Indicates whether this investment vehicle type generates Unrelated Business Taxable Income (UBTI) for tax-exempt investors such as pension funds, endowments, and IRAs. Critical for institutional investor eligibility screening and tax compliance.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this investment vehicle reference record was last modified in the enterprise data platform. Supports change tracking, data lineage, and reference data governance.',
    `vehicle_category` STRING COMMENT 'Broad category grouping investment vehicle types for portfolio analytics and regulatory classification. Values: REIT (Real Estate Investment Trust), private_equity_fund, joint_venture, separate_account, debt_vehicle (CMBS/RMBS), tax_exchange_vehicle (1031/DST/TIC), other. [ENUM-REF-CANDIDATE: REIT|private_equity_fund|joint_venture|separate_account|debt_vehicle|tax_exchange_vehicle|other — 7 candidates stripped; promote to reference product]',
    `vehicle_code` STRING COMMENT 'Short, system-unique alphanumeric code identifying the investment vehicle type (e.g., REIT_EQUITY, PE_CLOSED, JV, DST, TIC, CMBS). Used as the canonical lookup key across all consuming domains including investment, transaction, owner, and finance.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `vehicle_name` STRING COMMENT 'Full human-readable name of the investment vehicle type (e.g., Equity Real Estate Investment Trust, Closed-End Private Equity Fund, Delaware Statutory Trust). Used in reports, investor documents, and regulatory filings.',
    `vehicle_subtype` STRING COMMENT 'Granular subtype classification within the vehicle category (e.g., equity_reit, mortgage_reit, hybrid_reit, open_end_fund, closed_end_fund, odce_fund, value_add_fund, opportunistic_fund, core_fund, core_plus_fund, cmbs, rmbs, dst, tic, 1031_exchange). [ENUM-REF-CANDIDATE: equity_reit|mortgage_reit|hybrid_reit|open_end_fund|closed_end_fund|odce_fund|value_add_fund|opportunistic_fund|core_fund|core_plus_fund|cmbs|rmbs|dst|tic|1031_exchange — promote to reference product]',
    CONSTRAINT pk_investment_vehicle PRIMARY KEY(`investment_vehicle_id`)
) COMMENT 'Reference classification for real estate investment structures and legal vehicles — REIT (equity, mortgage, hybrid), private equity fund (open-end, closed-end), ODCE fund, value-add/opportunistic fund, joint venture (JV), separate account, CMBS, RMBS, DST (Delaware Statutory Trust), TIC (Tenants in Common), and 1031 exchange vehicle. Defines regulatory classification (SEC, FINRA, state blue sky), applicable tax treatment (pass-through, REIT distribution requirements, UBTI), investor eligibility requirements (accredited, qualified purchaser, institutional), minimum investment thresholds, and reporting standards (NCREIF, INREV, ANREV). Referenced by investment, transaction, owner, and finance domains for fund structuring, investor onboarding, and regulatory reporting.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`sustainability_rating` (
    `sustainability_rating_id` BIGINT COMMENT 'Unique surrogate identifier for each sustainability certification level or rating record in the enterprise reference registry. Role: REFERENCE_LOOKUP — exempt from per-role minimums; this table is a controlled vocabulary of green building certification schemes and their defined rating tiers. _canonical_skip_reason: This is a reference/lookup entity providing standardized code sets for sustainability certifications; no MASTER_RESOURCE or TRANSACTION minimums apply.',
    `country_id` BIGINT COMMENT 'Foreign key linking to reference.country. Business justification: Sustainability certification schemes are issued by certifying bodies domiciled in specific countries (e.g., USGBC in USA for LEED, BRE in UK for BREEAM). Linking to the country registry enables joinin',
    `superseded_by_sustainability_rating_id` BIGINT COMMENT 'Reference to the sustainability_rating_id of the newer record that supersedes this one when a scheme version is updated (e.g., LEED v3 Platinum superseded by LEED v4.1 Platinum). Enables version lineage tracking and migration mapping for existing certified properties in the portfolio.',
    `applicable_building_types` STRING COMMENT 'Comma-separated list of building or asset types to which this certification level applies (e.g., Office, Retail, Industrial or New Construction, Existing Buildings, Interior Design). Aligns with RESO property type taxonomy and CoStar property classifications for ESG eligibility screening.',
    `applicable_project_phase` STRING COMMENT 'Project lifecycle phase for which this certification level is applicable (e.g., NEW_CONSTRUCTION for LEED BD+C, EXISTING_BUILDING for LEED O+M, INTERIOR_FIT_OUT for LEED ID+C). Used in Procore development project ESG planning and Building Engines facility operations tracking.. Valid values are `NEW_CONSTRUCTION|EXISTING_BUILDING|INTERIOR_FIT_OUT|CORE_AND_SHELL|OPERATIONS|ALL`',
    `breeam_assessment_type` STRING COMMENT 'BREEAM-specific assessment type applicable to this record (e.g., NEW_CONSTRUCTION, IN_USE, REFURBISHMENT). Set to NA for non-BREEAM schemes. Supports BREEAM portfolio tracking and compliance reporting for UK and European assets.. Valid values are `NEW_CONSTRUCTION|IN_USE|REFURBISHMENT|COMMUNITIES|INFRASTRUCTURE|NA`',
    `cap_rate_compression_bps` STRING COMMENT 'Indicative benchmark basis points of CAP rate compression (yield reduction) associated with achieving this certification level relative to non-certified comparable assets. Used in Argus Enterprise investment analysis and portfolio valuation models to quantify the sustainability premium on asset value.',
    `carbon_reporting_applicable` BOOLEAN COMMENT 'Indicates whether this certification scheme and level includes or requires carbon emissions measurement and reporting as part of the certification criteria (True). Supports Scope 1, 2, and 3 emissions tracking for TCFD and SEC climate disclosure compliance.',
    `certifying_body_name` STRING COMMENT 'Name of the official organization or authority that administers, audits, and issues the certification (e.g., U.S. Green Building Council (USGBC), Building Research Establishment (BRE), U.S. Environmental Protection Agency (EPA), International WELL Building Institute (IWBI), GRESB B.V.). Required for regulatory compliance filings and ESG audit trails.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this sustainability rating reference record was first created in the enterprise data lakehouse Silver layer. Supports data lineage, audit trail requirements, and SOX-compliant change management for reference data governance.',
    `effective_from` DATE COMMENT 'Date from which this certification level definition became officially valid and available for use in property certifications and ESG reporting. Supports temporal validity management of the reference data registry and ensures correct scheme version application by certification date.',
    `effective_until` DATE COMMENT 'Date after which this certification level definition is no longer valid for new certifications (null for currently active records with no planned expiry). Used in conjunction with effective_from to enforce temporal reference data integrity across the enterprise data lakehouse.',
    `energy_performance_focus` BOOLEAN COMMENT 'Indicates whether energy efficiency and performance is a primary evaluation criterion for this certification scheme and level (True), as opposed to schemes focused primarily on health/wellness, water, or social factors (False). Used for OPEX reduction analysis and CAPEX planning in Argus Enterprise models.',
    `energy_star_eligible_property_types` STRING COMMENT 'Comma-separated list of EPA-defined property use types eligible for ENERGY STAR certification under this rating record (e.g., Office, K-12 School, Hospital, Retail Store). Applicable only to ENERGY STAR scheme records; null for other schemes. Used in Yardi Voyager and MRI Software ESG module property eligibility screening.',
    `esg_framework_alignment` STRING COMMENT 'Comma-separated list of ESG reporting frameworks to which this certification scheme contributes or aligns (e.g., GRI, SASB, TCFD, GRESB, UN SDGs, EU Taxonomy). Critical for investor-grade ESG reporting, REIT sustainability disclosures, and SEC climate risk reporting compliance.',
    `external_reference_url` STRING COMMENT 'Official URL linking to the certifying bodys published documentation, scoring guide, or technical standard for this certification level (e.g., USGBC LEED scorecard page, BRE BREEAM technical standards). Provides direct access to authoritative source documentation for ESG analysts and compliance teams.. Valid values are `^https?://.+`',
    `gresb_score_contribution` BOOLEAN COMMENT 'Indicates whether achieving this certification level contributes to the GRESB Real Estate Assessment score (True) or is not recognized by GRESB (False). Directly impacts REIT investor relations and AUM-weighted ESG benchmarking.',
    `indoor_air_quality_applicable` BOOLEAN COMMENT 'Indicates whether indoor environmental quality or air quality is a primary criterion for this certification scheme and level (True), as is the case for WELL Building Standard and LEED Indoor Environmental Quality credits. Relevant for tenant health and wellness disclosures and OSHA compliance.',
    `is_renewal_required` BOOLEAN COMMENT 'Indicates whether periodic renewal or recertification is required to maintain this certification level (True) or whether it is a one-time permanent certification (False). Drives automated compliance alerts in Building Engines and ESG portfolio monitoring workflows.',
    `leed_category` STRING COMMENT 'LEED-specific rating system category applicable to this record (e.g., BD_AND_C for Building Design and Construction, O_AND_M for Operations and Maintenance, ID_AND_C for Interior Design and Construction). Set to NA for non-LEED schemes. Enables precise LEED sub-system tracking in ESG portfolios. [ENUM-REF-CANDIDATE: BD_AND_C|ID_AND_C|O_AND_M|ND|HOMES|CITIES_AND_COMMUNITIES|NA — 7 candidates stripped; promote to reference product]',
    `max_possible_score` DECIMAL(18,2) COMMENT 'The total maximum achievable score under the schemes scoring framework (e.g., 110 points for LEED v4, 100% for BREEAM, 100 for ENERGY STAR). Used to normalize scores across schemes for cross-portfolio ESG benchmarking and GRESB reporting.',
    `max_score_threshold` DECIMAL(18,2) COMMENT 'Maximum numeric score defining the upper boundary of this certification tier (exclusive upper bound for non-top tiers; null or scheme maximum for the highest tier). Enables precise tier-band mapping in ESG scoring engines and Argus Enterprise valuation models.',
    `min_score_threshold` DECIMAL(18,2) COMMENT 'Minimum numeric score required to achieve this certification level within the schemes scoring framework (e.g., 80 points for LEED Platinum, 85% for BREEAM Outstanding). Used in valuation models, ESG gap analysis, and development project target-setting.',
    `premium_rent_uplift_pct` DECIMAL(18,2) COMMENT 'Indicative benchmark percentage premium on market rent per square foot (PSF) attributable to achieving this certification level, based on industry research and comparable market data. Used in Argus Enterprise DCF models, lease underwriting, and investment advisory valuations to quantify the green premium.',
    `rating_level_code` STRING COMMENT 'Short alphanumeric code representing the specific certification tier or rating level within the scheme (e.g., CERT, SILVER, GOLD, PLATINUM for LEED; PASS, GOOD, VERY_GOOD, EXCELLENT, OUTSTANDING for BREEAM; CERTIFIED for ENERGY STAR). Used as a lookup key in property, development, and compliance domain tables.',
    `rating_level_description` STRING COMMENT 'Narrative description of what the certification tier represents, including the performance expectations, sustainability outcomes, and distinguishing characteristics relative to other tiers within the same scheme. Supports ESG analyst interpretation and investor due diligence.',
    `rating_level_name` STRING COMMENT 'Full descriptive name of the certification tier or rating level (e.g., LEED Platinum, BREEAM Outstanding, ENERGY STAR Certified, WELL Gold). Displayed in ESG portfolio dashboards, investor reporting packs, and tenant-facing marketing collateral.',
    `recognition_scope` STRING COMMENT 'Geographic scope of recognition for this certification scheme and level (e.g., GLOBAL for LEED and BREEAM International, NATIONAL for NABERS Australia, REGIONAL for jurisdiction-specific schemes). Used for cross-border portfolio ESG comparability and investor reporting.. Valid values are `GLOBAL|REGIONAL|NATIONAL|LOCAL`',
    `renewal_cycle_years` STRING COMMENT 'Number of years after which the certification must be renewed or recertified to remain valid (e.g., 3 years for ENERGY STAR, 5 years for BREEAM In-Use). Drives compliance calendar management in Building Engines and ESG reporting schedules for REIT investor disclosures.',
    `scheme_code` STRING COMMENT 'Standardized code identifying the green building or sustainability certification scheme (e.g., LEED, BREEAM, ENERGY STAR, WELL Building Standard, GRESB, Fitwel, NABERS). Used as the primary grouping key for ESG portfolio reporting and investor disclosures. [ENUM-REF-CANDIDATE: LEED|BREEAM|ENERGY_STAR|WELL|GRESB|FITWEL|NABERS|EDGE|DGNB|GREEN_STAR — promote to reference product]',
    `scheme_name` STRING COMMENT 'Full human-readable name of the sustainability or green building certification scheme (e.g., Leadership in Energy and Environmental Design (LEED), Building Research Establishment Environmental Assessment Method (BREEAM), ENERGY STAR). Used in investor reports, ESG disclosures, and tenant marketing materials.',
    `scheme_version` STRING COMMENT 'Version or edition of the certification scheme under which this rating level is defined (e.g., LEED v4.1, BREEAM 2018, WELL v2, ENERGY STAR 2023). Critical for tracking certification vintage and ensuring comparability across portfolio assets assessed under different scheme versions.',
    `score_unit` STRING COMMENT 'Unit of measure used by the certification schemes scoring system (e.g., POINTS for LEED, PERCENTAGE for BREEAM, STARS for NABERS, SCORE for ENERGY STAR 1–100 scale). Ensures correct interpretation of min/max score thresholds across heterogeneous schemes.. Valid values are `POINTS|PERCENTAGE|STARS|SCORE|RATING`',
    `sort_order` STRING COMMENT 'Display sort order for this record within its certification scheme grouping, used to control the presentation sequence in ESG reporting dropdowns, investor dashboards, and property management system lookup lists (e.g., Yardi Voyager, MRI Software ESG modules).',
    `sustainability_rating_status` STRING COMMENT 'Lifecycle status of this sustainability rating reference record (e.g., ACTIVE for currently valid certification levels, DEPRECATED for retired tiers, SUPERSEDED for levels replaced by a newer scheme version, DRAFT for pending publication). Controls which records are available for selection in downstream property and compliance domain lookups.. Valid values are `ACTIVE|DEPRECATED|SUPERSEDED|DRAFT`',
    `third_party_verified` BOOLEAN COMMENT 'Indicates whether this certification level requires independent third-party verification or audit by an accredited assessor (True), as opposed to self-reported or self-assessed ratings (False). Critical for investor-grade ESG credibility and SOX-compliant financial reporting for public REITs.',
    `tier_rank` STRING COMMENT 'Ordinal rank of this certification level within its scheme, where 1 represents the highest/best tier (e.g., LEED Platinum = 1, LEED Gold = 2, LEED Silver = 3, LEED Certified = 4). Enables ranked sorting and tier-progression analytics in ESG portfolio dashboards.',
    `typical_certification_cost_usd` DECIMAL(18,2) COMMENT 'Indicative benchmark cost in US dollars to achieve this certification level, including registration, assessment, and certification fees (excluding tenant improvement or capital expenditure costs). Used in CAPEX budgeting within Argus Enterprise and SAP S/4HANA project systems for development feasibility analysis.',
    `typical_certification_duration_days` STRING COMMENT 'Indicative number of calendar days from application submission to certification award for this scheme and level. Used in Procore construction project scheduling and development timeline planning to account for ESG certification lead times.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this sustainability rating reference record. Used for incremental data pipeline processing, change data capture in Databricks Lakehouse, and reference data version control in ESG reporting workflows.',
    `water_efficiency_applicable` BOOLEAN COMMENT 'Indicates whether water efficiency and conservation is a scored or required criterion within this certification scheme and level (True). Relevant for ESG portfolio reporting under GRI 303 (Water and Effluents) and LEED Water Efficiency credits.',
    `well_concept` STRING COMMENT 'Primary WELL Building Standard concept category associated with this certification level (e.g., AIR, WATER, LIGHT, MIND). Set to NA for non-WELL schemes. Supports tenant wellness program reporting and WELL portfolio tracking for health-focused investors. [ENUM-REF-CANDIDATE: AIR|WATER|NOURISHMENT|LIGHT|MOVEMENT|THERMAL_COMFORT|SOUND|MATERIALS|MIND|COMMUNITY|INNOVATION|NA — promote to reference product]',
    CONSTRAINT pk_sustainability_rating PRIMARY KEY(`sustainability_rating_id`)
) COMMENT 'Registry of green building and sustainability certification schemes — LEED (Certified through Platinum), BREEAM (Pass through Outstanding), ENERGY STAR, WELL Building Standard, GRESB, Fitwel, and NABERS. Stores certification level definitions, scoring thresholds, applicable building types, certifying body, renewal cycle requirements, and ESG reporting framework alignment (GRI, SASB, TCFD). Referenced by property, development, and compliance domains for ESG portfolio tracking and investor reporting.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`country` (
    `country_id` BIGINT COMMENT 'Unique surrogate identifier for the country record. Serves as the primary key and top-level node in the geographic hierarchy referenced across all real estate domains. [REFERENCE_LOOKUP role — canonical_skip_reason: This entity is a controlled vocabulary / code-list table providing ISO country codes and geographic metadata; per-role minimum categories do not apply.]',
    `alpha2_code` STRING COMMENT 'Two-letter ISO 3166-1 country code (e.g., US, GB, DE). Used as the primary short-form identifier in lease agreements, tenant records, property addresses, and regulatory filings across Yardi Voyager and SAP S/4HANA.. Valid values are `^[A-Z]{2}$`',
    `alpha3_code` STRING COMMENT 'Three-letter ISO 3166-1 country code (e.g., USA, GBR, DEU). Used in financial consolidation reporting in SAP S/4HANA, CMBS/RMBS documentation, and cross-border investment portfolio reporting in Argus Enterprise.. Valid values are `^[A-Z]{3}$`',
    `aml_risk_rating` STRING COMMENT 'FATF-aligned AML risk classification for the country. Used in KYC/AML due diligence for real estate transactions, tenant onboarding, and cross-border investment approvals. High-risk countries require enhanced due diligence per SOX and SEC compliance requirements.. Valid values are `low|medium|high|very_high`',
    `area_measurement_body` STRING COMMENT 'Name of the primary standards body governing property area measurement methodology in the country (e.g., BOMA, IPMS, RICS). Ensures consistent GLA/NLA calculations for PSF rent benchmarking and CAM reconciliation.',
    `breeam_recognized` BOOLEAN COMMENT 'Indicates whether BREEAM certification is officially recognized or incentivized in the country. Relevant for ESG compliance, green building asset classification, and sustainability reporting for European and international portfolios.',
    `capital_city` STRING COMMENT 'Name of the countrys capital city. Used as a geographic reference point for market research, CoStar comparable data alignment, and investment market classification.',
    `capital_gains_tax_applicable` BOOLEAN COMMENT 'Indicates whether capital gains tax applies to real estate dispositions in the country. Affects IRR and NPV modeling in Argus Enterprise, investment advisory recommendations, and property acquisition/disposition strategy.',
    `country_name` STRING COMMENT 'Official short-form country name in English as defined by ISO 3166-1 (e.g., United States, United Kingdom, Germany). Used as the display label in property records, lease agreements, tenant profiles, and portfolio reports.',
    `country_status` STRING COMMENT 'Operational status of the country record within the enterprise reference data registry. active indicates the country is in use across operational systems; inactive indicates no current portfolio exposure; deprecated indicates the country code has been superseded (e.g., post-dissolution or renaming per ISO 3166-1 updates).. Valid values are `active|inactive|deprecated`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this country record was first created in the enterprise reference data registry. Supports data lineage, audit trail requirements, and SOX financial controls for reference data governance.',
    `default_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code representing the primary legal tender of the country (e.g., USD, GBP, EUR). Used as the default currency for property valuations, lease rent schedules, NOI calculations, and CAP rate analysis in Yardi Voyager, MRI Software, and Argus Enterprise.. Valid values are `^[A-Z]{3}$`',
    `dialing_code` STRING COMMENT 'International telephone dialing prefix for the country (e.g., +1 for USA, +44 for UK). Used for formatting tenant and owner contact phone numbers in Salesforce CRM and Yardi Voyager tenant records.. Valid values are `^+[0-9]{1,4}$`',
    `effective_from` DATE COMMENT 'Date from which this country record is valid and active within the enterprise reference data registry. Supports temporal data management and ISO 3166-1 change tracking (e.g., country reclassifications, new sovereign states).',
    `effective_until` DATE COMMENT 'Date after which this country record is no longer valid. Null indicates an open-ended active record. Used to manage deprecated or superseded country codes following ISO 3166-1 updates (e.g., dissolution of a country or code reassignment).',
    `esg_reporting_framework` STRING COMMENT 'Primary ESG reporting framework mandated or commonly adopted for real estate assets in the country (e.g., GRI, TCFD, SFDR, local regulation). Drives sustainability data collection, LEED/BREEAM certification tracking, and ESG disclosure requirements for REITs and institutional investors.',
    `fatf_member` BOOLEAN COMMENT 'Indicates whether the country is a member of the Financial Action Task Force (FATF). Relevant for AML/KYC compliance in cross-border real estate investment transactions, REIT capital flows, and CMBS/RMBS structuring.',
    `foreign_ownership_allowed` BOOLEAN COMMENT 'Indicates whether foreign nationals and entities are permitted to own real property in the country. Critical for investment advisory, portfolio acquisition strategy, and REIT eligibility assessments in Argus Enterprise and MRI Software.',
    `foreign_ownership_restriction_notes` STRING COMMENT 'Narrative description of any restrictions, conditions, or limitations on foreign ownership of real property in the country (e.g., maximum ownership percentage, restricted zones, required local partner). Supports investment advisory and compliance review.',
    `gdpr_applicable` BOOLEAN COMMENT 'Indicates whether the General Data Protection Regulation (GDPR) applies to real estate operations conducted in or with residents of this country. Drives data handling policies for tenant PII in Salesforce CRM, Yardi Voyager, and DocuSign CLM.',
    `ifrs_adopted` BOOLEAN COMMENT 'Indicates whether the country has adopted International Financial Reporting Standards (IFRS) for financial reporting. Determines applicable accounting treatment for investment property (IAS 40), lease liabilities (IFRS 16), and financial instrument disclosures in SAP S/4HANA.',
    `land_registration_system` STRING COMMENT 'Type of land title registration system in use in the country. Affects title insurance requirements, ALTA policy applicability, due diligence procedures for property acquisition, and LTV calculations for debt instruments.. Valid values are `torrens|deed_recording|cadastral|mixed|none`',
    `lease_accounting_standard` STRING COMMENT 'The applicable lease accounting standard for real estate leases in the country. Drives right-of-use asset recognition, lease liability classification, and financial statement presentation in Yardi Voyager lease accounting and SAP S/4HANA financial consolidation.. Valid values are `ASC_842|IFRS_16|local_GAAP|mixed`',
    `leed_recognized` BOOLEAN COMMENT 'Indicates whether LEED certification is officially recognized or incentivized by the countrys regulatory or governmental bodies. Supports ESG reporting, green building compliance tracking, and sustainability-linked financing decisions.',
    `measurement_standard` STRING COMMENT 'Predominant unit-of-measure standard used for property area measurement in the country. Determines whether GLA, NLA, and GRI calculations are expressed in SQF (square feet) or SQM (square meters) in Yardi Voyager, CoStar Suite, and lease administration systems.. Valid values are `imperial|metric|mixed`',
    `multiple_time_zones` BOOLEAN COMMENT 'Indicates whether the country spans multiple time zones. Relevant for scheduling lease payment processing, maintenance dispatch, and financial period close operations across geographically dispersed property portfolios.',
    `numeric_code` STRING COMMENT 'Three-digit ISO 3166-1 numeric country code (e.g., 840 for USA, 826 for GBR). Used in UN trade statistics, ALTA title insurance documentation, and cross-system integration where alpha codes may conflict.. Valid values are `^[0-9]{3}$`',
    `official_name` STRING COMMENT 'Full official name of the country as recognized by the United Nations (e.g., United States of America, United Kingdom of Great Britain and Northern Ireland). Used in legal contracts, SNDA agreements, and regulatory filings requiring formal jurisdiction identification.',
    `portfolio_exposure` BOOLEAN COMMENT 'Indicates whether the enterprise currently holds active real estate assets, leases, or investments in this country. Used to filter active jurisdictions in portfolio reporting, AUM dashboards, and regulatory compliance monitoring.',
    `primary_valuation_standard` STRING COMMENT 'The predominant property valuation standard applied in the country. Determines the methodology used for appraisals, CAP rate benchmarking, DCF modeling, and NAV/GAV calculations in Argus Enterprise and investment advisory services.. Valid values are `IVSC|RICS|USPAP|local_standard|mixed`',
    `property_law_system` STRING COMMENT 'Legal system governing property rights and real estate transactions in the country. Determines applicable title transfer procedures, SNDA enforceability, ground lease structures, and tenure type classifications used in lease administration and investment advisory.. Valid values are `common_law|civil_law|mixed|customary_law|religious_law`',
    `region` STRING COMMENT 'Broad geographic region or continent grouping for the country (e.g., North America, Europe, Asia-Pacific, Middle East, Africa, Latin America). Used for portfolio segmentation, AUM reporting, and investment strategy classification in Argus Enterprise and MRI Software. [ENUM-REF-CANDIDATE: North America|Europe|Asia-Pacific|Middle East|Africa|Latin America|Oceania|South Asia — promote to reference product]',
    `reit_framework_exists` BOOLEAN COMMENT 'Indicates whether the country has an established legal and regulatory framework for Real Estate Investment Trusts (REITs) or equivalent listed property vehicles. Used in investment portfolio structuring and AUM classification in Argus Enterprise.',
    `sanctions_status` STRING COMMENT 'Current OFAC/UN sanctions status for the country. Determines whether real estate transactions, lease agreements, and investment activities are permissible. sanctioned or embargoed countries are blocked from all transaction processing in Yardi Voyager and SAP S/4HANA.. Valid values are `clear|monitored|sanctioned|embargoed`',
    `sort_order` STRING COMMENT 'Numeric display sequence for ordering country records in dropdown lists, reports, and reference data selectors across Yardi Voyager, Salesforce CRM, and other operational systems. Lower values appear first.',
    `sovereignty_type` STRING COMMENT 'Classification of the country or territorys political sovereignty status. Determines applicable legal frameworks, title insurance requirements (ALTA), and regulatory reporting obligations for cross-border real estate transactions.. Valid values are `sovereign_state|territory|dependency|disputed|special_administrative_region`',
    `standard_vat_rate_pct` DECIMAL(18,2) COMMENT 'Standard VAT or GST rate applicable to real estate transactions in the country, expressed as a percentage (e.g., 20.00 for 20%). Used in lease rent schedule calculations, AP invoice processing, and tax provision modeling in SAP S/4HANA.',
    `sub_region` STRING COMMENT 'UN M.49 sub-regional grouping for the country (e.g., Northern Europe, South-Eastern Asia, Northern America). Supports granular portfolio analytics and cross-border investment reporting in Argus Enterprise.',
    `tax_treaty_with_us` BOOLEAN COMMENT 'Indicates whether the country has an active bilateral tax treaty with the United States. Affects withholding tax rates on rental income, capital gains treatment for cross-border property dispositions, and REIT distribution taxation for international investors.',
    `time_zone_primary` STRING COMMENT 'IANA time zone identifier for the countrys primary or capital time zone (e.g., America/New_York, Europe/London). Used for scheduling lease payment due dates, maintenance work orders in Building Engines, and financial period close timestamps in SAP S/4HANA.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this country record in the enterprise reference data registry. Used for change data capture, reference data synchronization across Yardi Voyager, SAP S/4HANA, and MRI Software, and audit trail compliance.',
    `vat_applicable` BOOLEAN COMMENT 'Indicates whether Value Added Tax (VAT) or equivalent goods and services tax applies to real estate transactions and rental income in the country. Affects lease rent invoicing, CAM charge calculations, and AP/AR processing in Yardi Voyager and SAP S/4HANA.',
    `withholding_tax_rate_pct` DECIMAL(18,2) COMMENT 'Standard withholding tax rate applied to rental income and property-related payments remitted to foreign investors in the country, expressed as a percentage. Used in cross-border investment advisory, REIT distribution modeling, and DSCR calculations.',
    CONSTRAINT pk_country PRIMARY KEY(`country_id`)
) COMMENT 'ISO 3166-1 country registry supporting international real estate portfolio operations. Stores country code (alpha-2, alpha-3, numeric), country name, region/continent grouping, default currency, applicable regulatory frameworks (GDPR, local property law), and tax treaty status. Serves as the top-level node in the geographic hierarchy and is referenced by all domains requiring country-level jurisdiction identification.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`regulatory_framework` (
    `regulatory_framework_id` BIGINT COMMENT 'Unique surrogate identifier for each regulatory or compliance framework record in the enterprise registry. Primary key. [_canonical_skip_reason: REFERENCE_LOOKUP/MASTER_RESOURCE — this entity is a reference registry of regulatory frameworks; per-role minimums for MASTER_RESOURCE apply and are satisfied below.]',
    `country_id` BIGINT COMMENT 'Foreign key linking to reference.country. Business justification: Regulatory frameworks are jurisdiction-specific and governed by a countrys legal system. Linking to the country registry enables joining to country-level attributes (property law system, REIT framewo',
    `geographic_hierarchy_id` BIGINT COMMENT 'Foreign key linking to reference.geographic_hierarchy. Business justification: State and municipal regulatory frameworks apply to specific geographic jurisdictions represented in the enterprise geographic hierarchy. Linking enables spatial queries (e.g., all regulations applicab',
    `currency_code_id` BIGINT COMMENT 'Foreign key linking to reference.currency_code. Business justification: Regulatory frameworks specify maximum penalty amounts denominated in a specific currency (max_penalty_amount with penalty_currency_code). Linking to the ISO 4217 currency registry ensures referential ',
    `applicable_business_processes` STRING COMMENT 'Comma-separated list of core business processes governed by this framework (e.g., Lease Administration, Financial Reporting, Property Acquisition). Maps the framework to operational workflows for compliance impact assessment and process-level control assignment.',
    `applicable_data_domains` STRING COMMENT 'Comma-separated list of enterprise data domains impacted by this framework (e.g., Lease, Finance, Tenant, Property, Compliance). Used to route compliance requirements to domain data stewards and enforce data governance controls.',
    `asset_class_applicability` STRING COMMENT 'Comma-separated list of real estate asset classes to which this framework applies (e.g., commercial, residential, industrial, retail, multifamily, mixed_use). Enables property-type-level compliance filtering and applicability determination in portfolio management.',
    `citation_reference` STRING COMMENT 'Formal legal or standards citation for the framework (e.g., FASB ASC 842, IFRS 16, 15 U.S.C. § 1681 (FCRA), 29 CFR Part 1910, EU Regulation 2016/679). Used in legal documents, audit reports, and compliance filings.',
    `compliance_owner` STRING COMMENT 'Name or title of the internal role, department, or individual responsible for managing compliance with this framework (e.g., Chief Compliance Officer, Legal — Lease Accounting, Environmental Health & Safety Manager). Drives accountability assignment in compliance workflows.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this regulatory framework record was first created in the enterprise registry. Supports audit trail, data lineage, and compliance record-keeping requirements under SOX and GDPR.',
    `effective_date` DATE COMMENT 'Date on which the regulatory framework became or becomes legally effective and enforceable. Used to determine applicability windows for properties, leases, and transactions. Aligns with ASC 842 and IFRS 16 adoption date tracking.',
    `external_reference_url` STRING COMMENT 'URL linking to the official regulatory text, standards document, or governing body publication for this framework (e.g., FASB codification link, EUR-Lex GDPR URL, OSHA CFR link). Provides direct access to authoritative source material for compliance officers.',
    `framework_category` STRING COMMENT 'High-level category classifying the nature of the regulatory framework. Drives compliance domain routing, reporting groupings, and risk classification. [ENUM-REF-CANDIDATE: lease_accounting|financial_reporting|fair_housing|environmental|workplace_safety|data_privacy|accessibility|building_code|local_ordinance|tax|other — promote to reference product]',
    `framework_code` STRING COMMENT 'Short, unique alphanumeric code identifying the regulatory framework (e.g., ASC842, IFRS16, SOX, GDPR, ADA, OSHA-29CFR1910, CERCLA, IBC). Used as the business key for cross-system referencing and compliance tagging across all operational and analytical domains.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `framework_name` STRING COMMENT 'Full official name of the regulatory or compliance framework (e.g., ASC 842 — Leases, IFRS 16 — Leases, Sarbanes-Oxley Act, General Data Protection Regulation). Serves as the primary human-readable label in compliance dashboards and reports.',
    `framework_type` STRING COMMENT 'Classification of the framework by its issuing authority level — federal statute, state regulation, local ordinance, international standard, or industry self-regulatory standard. Determines jurisdictional applicability and enforcement hierarchy.. Valid values are `federal|state|local|international|industry_standard`',
    `internal_policy_reference` STRING COMMENT 'Reference code or document identifier for the enterprises internal policy, procedure, or control document that implements this regulatory framework (e.g., POL-LEASE-001, POL-PRIVACY-GDPR-002). Links the external regulation to internal governance documentation.',
    `is_esg_relevant` BOOLEAN COMMENT 'Indicates whether this framework has direct relevance to Environmental, Social, and Governance (ESG) reporting or sustainability performance (True/False). Flags frameworks such as LEED, BREEAM, EPA environmental regulations, and fair housing laws for ESG portfolio reporting.',
    `is_financial_reporting` BOOLEAN COMMENT 'Indicates whether this framework governs financial statement preparation, disclosure, or audit requirements (True/False). Flags frameworks such as ASC 842, IFRS 16, SOX, and SEC Regulation S-X that directly impact GL, lease accounting, and financial close processes in Yardi Voyager, MRI Software, and SAP S/4HANA.',
    `is_mandatory` BOOLEAN COMMENT 'Indicates whether compliance with this framework is legally mandatory (True) or voluntary/best-practice (False) for the enterprise. Mandatory frameworks (e.g., SOX, GDPR, OSHA) require formal compliance programs; voluntary frameworks (e.g., LEED, BREEAM, ESG) are adopted by choice.',
    `is_reit_applicable` BOOLEAN COMMENT 'Indicates whether this framework has specific applicability or implications for Real Estate Investment Trusts (REITs), including SEC reporting requirements, FFO/AFFO disclosure standards, and REIT qualification rules (True/False).',
    `issuing_body` STRING COMMENT 'Name of the regulatory authority, standards body, or government agency that issued or administers the framework (e.g., FASB, IASB, SEC, HUD, EPA, OSHA, GDPR — EU Commission, USGBC, ISO). Used for compliance ownership assignment and regulatory liaison tracking.',
    `jurisdiction_scope` STRING COMMENT 'Geographic or organizational scope of the frameworks applicability (e.g., USA — Federal, EU — All Member States, California, New York City). Supports multi-jurisdiction compliance mapping and property-level applicability determination.',
    `last_amended_date` DATE COMMENT 'Date of the most recent amendment, revision, or update to the framework. Used to track regulatory change management and trigger re-assessment of impacted business processes and contracts.',
    `lease_classification_impact` STRING COMMENT 'Indicates whether this framework affects operating lease classification, finance lease classification, both, or is not applicable to lease accounting. Directly relevant for ASC 842 and IFRS 16 compliance in lease administration systems (Yardi Voyager, MRI Software).. Valid values are `operating|finance|both|not_applicable`',
    `max_penalty_amount` DECIMAL(18,2) COMMENT 'Maximum monetary penalty per violation or per reporting period as defined by the framework, expressed in the frameworks base currency. Used for financial risk modeling, insurance coverage assessment, and compliance investment prioritization.',
    `next_review_date` DATE COMMENT 'Date of the next scheduled internal compliance review or regulatory re-assessment for this framework. Automatically calculated from last review date plus review frequency, but may be manually overridden for ad-hoc reviews triggered by regulatory amendments.',
    `penalty_structure` STRING COMMENT 'Narrative description of the penalty regime for non-compliance, including fine ranges, criminal liability, license revocation, or other sanctions (e.g., Up to €20M or 4% of global annual turnover — GDPR, Civil penalties up to $25,000/day — EPA CERCLA). Informs risk quantification and compliance investment decisions.',
    `regulatory_framework_description` STRING COMMENT 'Detailed narrative description of the regulatory frameworks purpose, scope, and key requirements. Provides compliance officers and business users with a plain-language summary of what the framework mandates and its impact on real estate operations.',
    `regulatory_framework_status` STRING COMMENT 'Current lifecycle status of the regulatory framework record. active — currently in force; superseded — replaced by a newer version; repealed — formally withdrawn; pending — enacted but not yet effective; draft — proposed but not yet enacted; sunset — expired per sunset clause.. Valid values are `active|superseded|repealed|pending|draft|sunset`',
    `related_framework_codes` STRING COMMENT 'Comma-separated list of framework codes that are cross-referenced or interdependent with this framework (e.g., ASC 842 cross-references ASC 840, IFRS 16 cross-references IAS 17, GDPR cross-references ePrivacy Directive). Supports compliance impact analysis across related regulatory requirements.',
    `reporting_cadence` STRING COMMENT 'Frequency at which compliance reports or disclosures must be submitted to the governing body or internal stakeholders under this framework (e.g., quarterly for SEC 10-Q, annual for SOX, event_driven for GDPR breach notification).. Valid values are `annual|semi_annual|quarterly|monthly|on_demand|event_driven`',
    `reporting_deadline_days` STRING COMMENT 'Number of calendar days after the reporting period end (or triggering event) by which the required compliance report or disclosure must be filed. For example, GDPR breach notification requires 72 hours (3 days); SEC 10-K requires 60–90 days.',
    `review_frequency_months` STRING COMMENT 'Number of months between scheduled internal compliance reviews for this framework. Drives the compliance calendar and review workflow scheduling (e.g., 12 months for annual SOX review, 6 months for semi-annual OSHA safety audits).',
    `risk_tier` STRING COMMENT 'Enterprise risk classification for non-compliance with this framework, based on penalty severity, reputational impact, and operational disruption potential. critical — existential risk (e.g., SOX, GDPR); high — significant financial/legal exposure; medium — moderate operational impact; low — minor administrative risk.. Valid values are `critical|high|medium|low`',
    `short_name` STRING COMMENT 'Commonly used abbreviation or acronym for the framework (e.g., ASC 842, IFRS 16, SOX, GDPR, CCPA, ADA, OSHA). Used in UI labels, report headers, and compliance matrices where space is limited.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this framework record was sourced or is primarily managed (e.g., SAP_S4HANA, YARDI, DOCUSIGN_CLM, MANUAL). Supports data lineage tracking and master data management.',
    `state_province_code` STRING COMMENT 'Two-to-six character code for the state or province where the framework applies, when jurisdiction is sub-national (e.g., CA for California, NY for New York). Null for federal or international frameworks.. Valid values are `^[A-Z]{2,6}$`',
    `sunset_date` DATE COMMENT 'Date on which the regulatory framework expires, is scheduled for repeal, or requires renewal. Null for frameworks with no defined expiry. Triggers compliance review workflows when approaching.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this regulatory framework record. Used for change tracking, incremental data pipeline processing, and compliance audit trails.',
    `version_number` STRING COMMENT 'Version or revision identifier for the framework (e.g., 2016, Rev. 3, Amendment 2023-01). Supports version-controlled compliance tracking and audit trail for regulatory changes over time.',
    CONSTRAINT pk_regulatory_framework PRIMARY KEY(`regulatory_framework_id`)
) COMMENT 'Registry of regulatory and compliance frameworks governing real estate operations across all jurisdictions. Covers lease accounting (ASC 842, IFRS 16), financial reporting (SOX, SEC Regulation S-X), fair housing (HUD Fair Housing Act), environmental (EPA CERCLA, state brownfield programs), workplace safety (OSHA 29 CFR 1910), data privacy (GDPR, CCPA), accessibility (ADA), building codes (IBC, NFPA), and local ordinances (rent control, inclusionary zoning). Each framework record defines jurisdiction scope, effective date, sunset/renewal date, applicable business processes, required reporting cadence, penalty structure, responsible compliance owner, and cross-references to related frameworks. Serves as the authoritative framework registry for the compliance domain and all domains requiring regulatory context.';

CREATE OR REPLACE TABLE `real_estate_ecm`.`reference`.`program_property_type_coverage` (
    `program_property_type_coverage_id` BIGINT COMMENT 'Unique surrogate identifier for this program property type coverage requirement record. Primary key.',
    `insurance_program_id` BIGINT COMMENT 'Foreign key linking to the enterprise insurance program within which this property type coverage requirement is defined.',
    `property_type_id` BIGINT COMMENT 'Foreign key linking to the property classification taxonomy node for which coverage requirements are being defined within this insurance program.',
    `coverage_requirement` STRING COMMENT 'Indicates whether coverage for this property type is required, optional, excluded, or conditional within this insurance program. Drives underwriting decisions and policy issuance workflows.',
    `created_date` TIMESTAMP COMMENT 'Timestamp when this coverage requirement record was created in the system. Audit trail for program structuring process.',
    `deductible_override` DECIMAL(18,2) COMMENT 'Property-type-specific deductible amount that overrides the program-level deductible for properties of this type. Null if program-level deductible applies. Used for high-risk property types requiring higher retention.',
    `effective_date` DATE COMMENT 'Date on which this property type coverage requirement becomes effective within the insurance program. May differ from program inception date if property types are added mid-term.',
    `exclusion_list` STRING COMMENT 'Pipe-delimited list of specific coverage exclusions or perils excluded for this property type within this program. Examples: flood, earthquake, terrorism, mold, asbestos. Drives policy wording and disclosure requirements.',
    `expiration_date` DATE COMMENT 'Date on which this property type coverage requirement expires or is removed from the insurance program. Null if active through program expiration.',
    `last_modified_by` STRING COMMENT 'User ID or system identifier of the person or process that last modified this coverage requirement record. Audit trail.',
    `last_modified_date` TIMESTAMP COMMENT 'Timestamp when this coverage requirement record was last modified. Tracks changes during program renewal or mid-term adjustments.',
    `mandatory_endorsements` STRING COMMENT 'Pipe-delimited list of mandatory policy endorsement codes that must be attached when insuring properties of this type under this program. Examples: WC000313 (Protective Safeguards), CP1018 (Ordinance or Law), IL0021 (Additional Insured).',
    `min_coverage_limit` DECIMAL(18,2) COMMENT 'Minimum coverage limit amount required for properties of this type within this insurance program, expressed in dollars. Enforced during policy binding and renewal.',
    `rate_tier` STRING COMMENT 'Underwriting rate tier classification assigned to this property type within this program. Drives premium calculation and carrier selection. Examples: tier_1 (lowest risk), tier_5 (highest risk), preferred, standard, substandard.',
    `underwriter_notes` STRING COMMENT 'Free-text notes from the underwriter or risk manager documenting special considerations, carrier requirements, or risk mitigation measures specific to this property type within this program.',
    `created_by` STRING COMMENT 'User ID or system identifier of the person or process that created this coverage requirement record. Audit trail.',
    CONSTRAINT pk_program_property_type_coverage PRIMARY KEY(`program_property_type_coverage_id`)
) COMMENT 'This association product represents the underwriting coverage configuration between property_type and insurance_program. It captures the specific coverage requirements, limits, endorsements, and exclusions that apply when a particular property type is included in an insurance program. Each record links one property_type to one insurance_program with underwriting parameters that exist only in the context of this relationship. This is an operational underwriting design artifact created during program structuring and renewal processes.. Existence Justification: Insurance programs in real estate cover portfolios containing multiple property types (office, retail, industrial, multifamily, land), and each property type appears across multiple insurance programs over different policy years and portfolio segments. The underwriting process requires risk managers to define specific coverage requirements, minimum limits, mandatory endorsements, exclusions, and rate tiers for each property type within each program. This is an operational underwriting design activity performed during program structuring and renewal.';

